/* ============================================================
   Module 3, The Grown-Ups' Table  ("After Bedtime")
   A parent-facing, fine-dining meal planner. Pick a kitchen
   (Italian, Japanese, and more), follow a craving, and get
   tonight's three ideas, each with the chef's thinking, the
   method, the ingredients and a ready shopping list.

   Recipes were developed and adversarially cross-checked by a
   culinary panel (one author + one stern editor per cuisine) for
   authenticity, sound quantities and correct method.

   Plugs into the same platform core as Animals and Meals:
   { id, title, renderHome }. Its whole look is the dark
   "After Bedtime" theme, scoped behind body.gm-active so it
   never touches Chloe's light rose world.
   ============================================================ */
(function(){
  "use strict";
  var P = window.ChloePlatform, el = P.el;

  /* ---------------- recipe database (built + verified offline) ---------------- */
  var GM = {"cuisines":[{"key":"mediterranean","short":"Mediterranean","name":"Mediterranean & Middle Eastern","cats":["Mezze","Grills & Mains","Bowls & Salads"],"hue":"#5cc0ad"},{"key":"italian","short":"Italian","name":"Italian","cats":["Pizza","Pasta","Risotto","Secondi"],"hue":"#d06a4e"},{"key":"japanese","short":"Japanese","name":"Japanese","cats":["Sushi & Rice bowls","Ramen & Noodles","Yakimono (grilled)","Small plates"],"hue":"#9bb0c9"},{"key":"american","short":"American","name":"American","cats":["Burgers","BBQ & Grill","Comfort classics"],"hue":"#d9a45a"},{"key":"mexican","short":"Mexican","name":"Mexican","cats":["Tacos","Bowls & Enchiladas","Sides & Salsas"],"hue":"#df7d3f"},{"key":"indian","short":"Indian","name":"Indian","cats":["Curries","Tandoori & Grills","Rice & Breads"],"hue":"#e0ab44"},{"key":"thai","short":"Thai","name":"Thai & Southeast Asian","cats":["Curries & Stir-fry","Noodles","Salads & Small plates"],"hue":"#88bd76"},{"key":"french","short":"French","name":"French","cats":["Bistro mains","Brasserie classics","Desserts"],"hue":"#c79ad0"}],"types":["Pizza","Pasta","Burgers","Curry","Noodles & Ramen","Tacos","Grills & BBQ","Rice & Bowls","Mains","Starters","Salads","Desserts"],"dishes":[{"id":"me-hummus-tahini","name":"Hummus bi Tahini","category":"Mezze","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Silky, lemony hummus from a tin, ready in the time it takes to toast pita. A spoon of bicarb in a quick simmer slips the chickpea skins so the blend turns creamy instead of grainy. No overnight soak, no fuss.","ingredients":["2 x 400 g tins chickpeas, drained","1/2 tsp bicarbonate of soda","150 g tahini, well stirred","60 ml fresh lemon juice (about 2 lemons)","1 small garlic clove","1 tsp fine salt","60 ml ice-cold water, plus more as needed","2 tbsp extra virgin olive oil, to finish","1 tsp paprika or Aleppo pepper, to finish"],"steps":["Tip the chickpeas into a pan with the bicarb and water to cover, bring to a brisk simmer for 8 to 10 minutes until soft and the skins float, then drain.","Blend the warm chickpeas, tahini, lemon juice, garlic and salt for a full 2 minutes, scraping down once.","With the motor running, trickle in the ice water until the hummus turns pale and loose. Taste and adjust salt and lemon.","Spread on a plate, swirl a well in the middle, pool in the olive oil and dust with paprika. Serve with warm pita."],"pairing":"Warm pita and a glass of mint tea","tags":["Vegetarian","Vegan","Make-ahead","Gluten-free option","Quick","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":290,"protein":10,"carbs":24,"fat":18,"allergens":["Sesame"],"role":"appetizer","cuisineKey":"mediterranean","type":"Starters"},{"id":"me-baba-ganoush","name":"Baba Ganoush","category":"Mezze","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Smoky charred aubergine whipped with tahini and lemon into a loose, savoury dip. Burning the skins over a flame or under the grill gives that bitter smoke that is the whole point.","ingredients":["3 large aubergines (about 1.2 kg total)","60 g tahini, well stirred","2 tbsp fresh lemon juice","1 small garlic clove, crushed","3/4 tsp fine salt","2 tbsp extra virgin olive oil, plus more to finish","1 tbsp chopped flat-leaf parsley"],"steps":["Char the whole aubergines over a gas flame or under a hot grill, turning often, for 15 to 20 minutes until the skin is blackened and the flesh collapses.","Cool in a colander, then peel off all the skin and let the flesh drain 10 minutes.","Mash the flesh with a fork to keep some texture, then stir in the tahini, lemon juice, garlic, salt and olive oil. Taste and adjust.","Spread on a plate, drizzle with more oil and scatter parsley. Serve with flatbread."],"pairing":"A crisp dry white or sparkling water with lemon","tags":["Vegetarian","Vegan","Make-ahead","Gluten-free option","Light"],"vegetarian":true,"spicy":false,"calories":175,"protein":4,"carbs":12,"fat":13,"allergens":["Sesame"],"role":"appetizer","cuisineKey":"mediterranean","type":"Starters"},{"id":"me-falafel","name":"Crispy Falafel","category":"Mezze","course":"Starter","meal":"both","tier":"signature","inspiration":"Tawlet (Kamal Mouzawak, Beirut)","minutes":35,"serves":4,"level":"Weekend","idea":"Shatteringly crisp, green-centred falafel made the proper way from soaked raw chickpeas, never tinned. The ground-not-blended texture and a herb-packed crumb are what separate the real thing from a dense pub fritter. Soak the night before and the active work is quick.","ingredients":["250 g dried chickpeas, soaked overnight (do not cook)","1 small onion, roughly chopped","4 garlic cloves","30 g flat-leaf parsley","20 g fresh coriander","1.5 tsp ground cumin","1 tsp ground coriander","1 tsp fine salt","1/2 tsp bicarbonate of soda","1 litre neutral oil, for frying"],"steps":["Drain the soaked chickpeas well and pat dry; they stay raw, never cooked.","Pulse the chickpeas, onion, garlic and herbs to a coarse, couscous-like crumb that just holds when pressed. Do not blend to a paste.","Mix in the cumin, ground coriander and salt. Chill 30 minutes, then stir through the bicarb just before frying.","Shape into walnut-sized balls with wet hands.","Fry at 175C in batches for 3 to 4 minutes until deep golden with a green, steamy centre. Drain on paper.","Serve hot with tahini sauce and pickles."],"pairing":"Tahini-lemon sauce, pickled turnips and a cold lager","tags":["Vegetarian","Vegan","Make-ahead","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":330,"protein":12,"carbs":30,"fat":18,"allergens":[],"role":"appetizer","cuisineKey":"mediterranean","type":"Starters"},{"id":"me-whipped-feta","name":"Whipped Feta with Honey","category":"Mezze","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":10,"serves":4,"level":"Weeknight","idea":"Feta and yoghurt blitzed into a cloud, finished with a drizzle of honey and a crack of black pepper. Five minutes in a food processor and you have a mezze that tastes like much more effort than it took.","ingredients":["200 g feta","100 g Greek yoghurt","1 tbsp extra virgin olive oil, plus more to finish","1 tsp lemon juice","1 tbsp runny honey","1/2 tsp black pepper","1 tsp toasted sesame seeds or chilli flakes, to finish"],"steps":["Blitz the feta, yoghurt, olive oil and lemon juice in a food processor for 2 minutes until smooth and fluffy.","Spread thickly onto a plate with the back of a spoon.","Drizzle with honey and a little more olive oil, then crack over the black pepper.","Scatter sesame seeds or chilli flakes and serve with warm pita or crudites."],"pairing":"Warm pita, sliced cucumber and a chilled rosé","tags":["Vegetarian","Quick","Gluten-free option","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":220,"protein":10,"carbs":7,"fat":17,"allergens":["Milk","Sesame"],"role":"appetizer","cuisineKey":"mediterranean","type":"Starters"},{"id":"me-muhammara","name":"Muhammara (Roasted Pepper & Walnut Dip)","category":"Mezze","course":"Starter","meal":"both","tier":"signature","inspiration":"Orfali Bros (Mohamad Orfali, Dubai)","minutes":20,"serves":6,"level":"Weekend","idea":"A jewel-red Aleppan dip of roasted red peppers and toasted walnuts, sharpened with pomegranate molasses and warmed by cumin. A Syrian classic that Ottolenghi has championed in print; the balance of sweet, smoky and sour against the slight grit of hand-pounded walnuts is its whole identity.","ingredients":["3 large red peppers (or 250 g jarred roasted peppers, drained)","120 g walnuts, toasted","40 g fine dried breadcrumbs","2 tbsp pomegranate molasses, plus extra to finish","1 tbsp tomato paste","1 garlic clove","1 tsp ground cumin","1/2 tsp Aleppo pepper or chilli flakes","2 tbsp extra virgin olive oil","1 tbsp lemon juice","3/4 tsp salt","1 tbsp pomegranate seeds and chopped parsley, to finish"],"steps":["If using fresh peppers, char them whole under a hot grill, turning, for 12 to 15 minutes until blackened, then steam in a covered bowl 10 minutes, peel and deseed.","Toast the walnuts in a dry pan until fragrant, then set a few aside for the top.","Pulse the peppers, walnuts, breadcrumbs, pomegranate molasses, tomato paste, garlic, cumin, Aleppo pepper, olive oil, lemon juice and salt to a coarse, spoonable paste; keep some texture.","Taste and balance the sweet-sour with more molasses or lemon.","Spread on a plate, drizzle with molasses and oil, and scatter the reserved walnuts, pomegranate seeds and parsley."],"pairing":"Warm flatbread, grilled halloumi and a glass of Lebanese red","tags":["Vegetarian","Vegan","Make-ahead","Spicy","Crowd-pleaser"],"vegetarian":true,"spicy":true,"calories":230,"protein":4,"carbs":13,"fat":18,"allergens":["Gluten","Tree nuts"],"role":"appetizer","cuisineKey":"mediterranean","type":"Starters"},{"id":"me-chicken-shawarma","name":"Chicken Shawarma","category":"Grills & Mains","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"All the spit-roast flavour of street shawarma from a home oven: thigh meat in warm spices and yoghurt, roasted hot then crisped under the grill. A quick weeknight version once the marinade is on.","ingredients":["800 g boneless skinless chicken thighs","3 tbsp Greek yoghurt","3 tbsp olive oil","2 tbsp fresh lemon juice","4 garlic cloves, crushed","2 tsp ground cumin","2 tsp ground coriander","1 tsp smoked paprika","1/2 tsp ground cinnamon","1 tsp salt","1/2 tsp black pepper"],"steps":["Whisk the yoghurt, oil, lemon, garlic, spices, salt and pepper into a marinade and coat the thighs. Rest at least 30 minutes, ideally overnight.","Heat the oven to 220C. Stack the thighs snugly in a small dish and roast 30 to 35 minutes to an internal 75C.","Flash under a hot grill for 3 to 5 minutes until the edges char.","Rest 5 minutes, slice thinly, then pile into warm flatbread with garlic sauce, pickles and tomato, or serve over rice."],"pairing":"Garlic toum, pickled cucumber and a chilled Côtes du Rhône","tags":["Make-ahead","Gluten-free option","Crowd-pleaser","Batch-cook"],"vegetarian":false,"spicy":false,"calories":350,"protein":40,"carbs":4,"fat":19,"allergens":["Milk"],"role":"main","cuisineKey":"mediterranean","type":"Grills & BBQ"},{"id":"me-lamb-kofta","name":"Lamb Kofta Kebab","category":"Grills & Mains","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Juicy spiced minced lamb skewers, kneaded with grated onion and parsley so they stay tender. Fattier lamb and a firm knead give the springy bite of a proper kofta.","ingredients":["600 g minced lamb (around 20% fat)","1 small onion, coarsely grated and squeezed dry","20 g flat-leaf parsley, finely chopped","2 garlic cloves, crushed","1.5 tsp ground cumin","1 tsp ground coriander","1 tsp sweet paprika","1/2 tsp ground cinnamon","1 tsp salt","1/2 tsp black pepper","1 tbsp olive oil, for grilling"],"steps":["Combine the lamb, grated onion, parsley, garlic, spices, salt and pepper in a bowl.","Knead firmly for 3 to 4 minutes until sticky and cohesive, then chill 15 minutes.","With wet hands, mould around metal skewers into long sausage shapes, pressing firmly.","Grill on a hot griddle or barbecue, brushed with oil, for 8 to 10 minutes, turning, until charred and just cooked.","Rest briefly and serve with flatbread, sumac onions and yoghurt."],"pairing":"Sumac onions, garlicky yoghurt and a robust Syrah","tags":["Quick","Gluten-free option","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":380,"protein":26,"carbs":3,"fat":30,"allergens":[],"role":"main","cuisineKey":"mediterranean","type":"Grills & BBQ"},{"id":"me-shakshuka","name":"Shakshuka","category":"Grills & Mains","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Eggs poached in a spiced tomato and pepper sauce, all in one pan. Cumin, caraway and a pinch of chilli build a deep brunch sauce; the aim is just-set whites over a still-runny yolk.","ingredients":["3 tbsp olive oil","1 onion, finely sliced","2 red peppers, sliced","4 garlic cloves, sliced","1.5 tsp ground cumin","1 tsp sweet paprika","1/2 tsp caraway seeds","1/2 tsp chilli flakes","2 x 400 g tins chopped tomatoes","1 tsp sugar","1 tsp salt","6 large eggs","60 g feta, crumbled","2 tbsp chopped coriander"],"steps":["Soften the onion and peppers in the oil over medium heat for 10 minutes in a wide pan.","Add the garlic, cumin, paprika, caraway and chilli and fry 1 minute until fragrant.","Pour in the tomatoes with sugar and salt and simmer 12 to 15 minutes until thick and jammy.","Make six wells, crack in the eggs, cover and cook gently 6 to 8 minutes until the whites just set.","Scatter feta and coriander and serve from the pan with crusty bread."],"pairing":"Crusty sourdough and a glass of fresh orange juice","tags":["Vegetarian","One-pan","Spicy","Comfort","Gluten-free option"],"vegetarian":true,"spicy":true,"calories":280,"protein":14,"carbs":17,"fat":18,"allergens":["Egg","Milk"],"role":"main","cuisineKey":"mediterranean","type":"Grills & BBQ"},{"id":"me-sheet-pan-harissa-chicken","name":"Sheet-Pan Harissa Chicken & Chickpeas","category":"Grills & Mains","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"One tray, almost no washing up: chicken thighs and chickpeas roasted in harissa and lemon until the edges crisp and the chickpeas turn nutty. A weeknight rescue dish that still tastes North African.","ingredients":["8 bone-in skin-on chicken thighs (about 1 kg)","1 x 400 g tin chickpeas, drained","2 tbsp rose harissa (or regular harissa)","3 tbsp olive oil","1 lemon (half juiced, half sliced)","1 tsp ground cumin","1 red onion, cut into wedges","1 tsp salt","2 tbsp chopped coriander, to finish","100 g Greek yoghurt, to serve"],"steps":["Heat the oven to 220C. Toss the chickpeas, onion wedges and lemon slices in a large roasting tray with 1 tbsp oil and a pinch of salt.","Mix the harissa, remaining oil, lemon juice, cumin and salt, then rub all over the chicken thighs.","Nestle the thighs skin-up among the chickpeas and roast 30 to 35 minutes until the skin is crisp and the juices run clear.","Scatter with coriander and serve with the yoghurt and warm flatbread."],"pairing":"Flatbread, cooling yoghurt and a chilled Grenache rosé","tags":["One-pan","Spicy","Gluten-free option","Batch-cook","Comfort"],"vegetarian":false,"spicy":true,"calories":560,"protein":42,"carbs":16,"fat":36,"allergens":["Milk"],"role":"main","cuisineKey":"mediterranean","type":"Grills & BBQ"},{"id":"me-musakhan","name":"Musakhan (Sumac Chicken & Caramelised Onion)","category":"Grills & Mains","course":"Main","meal":"dinner","tier":"signature","inspiration":"EM SHERIF (Mireille Hayek, Beirut)","minutes":70,"serves":4,"level":"Project","idea":"Palestine's national dish: roast chicken over flatbread soaked in olive oil, sumac and a mountain of slow-cooked onions, scattered with toasted pine nuts. Sami Tamimi calls it the taste of home in Falastin; the tart hit of sumac against sweet onions and crisp-skinned chicken is unforgettable.","ingredients":["8 bone-in skin-on chicken thighs (about 1 kg)","5 large onions, thinly sliced (about 1 kg)","90 ml extra virgin olive oil, plus more for the bread","4 tbsp sumac, plus extra to finish","1 tsp ground allspice","1 tsp ground cumin","1/2 tsp ground cinnamon","1.5 tsp salt","4 large flatbreads or taboon bread","60 g pine nuts, toasted","20 g flat-leaf parsley, chopped","1 lemon, in wedges"],"steps":["Heat the oven to 200C. Rub the chicken with 2 tbsp oil, 1 tbsp sumac, half the allspice, cumin, cinnamon and 1 tsp salt. Roast in a tray 35 to 40 minutes until cooked through and the skin is golden.","Meanwhile, cook the onions slowly in the remaining oil over medium-low heat for 25 to 30 minutes until soft, sweet and pale gold, stirring often.","Stir 3 tbsp sumac, the rest of the spices and 1/2 tsp salt through the onions and cook 2 minutes more.","Brush the flatbreads with oil, lay them on a tray and spread the onions over. Sit the roasted chicken on top and spoon over the pan juices.","Return to the oven for 8 to 10 minutes until the bread crisps at the edges.","Scatter with toasted pine nuts, parsley and more sumac. Serve with lemon wedges."],"pairing":"Cucumber-yoghurt salad and a glass of Lebanese Cinsault","tags":["Make-ahead","Comfort","Crowd-pleaser","Date night"],"vegetarian":false,"spicy":false,"calories":680,"protein":38,"carbs":42,"fat":40,"allergens":["Gluten","Tree nuts"],"role":"main","cuisineKey":"mediterranean","type":"Grills & BBQ"},{"id":"me-tabbouleh","name":"Tabbouleh","category":"Bowls & Salads","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"The Levantine herb salad as it should be: overwhelmingly parsley and mint, with bulgur as a supporting whisper, not a bed. Hand-chopping keeps the herbs lively and green.","ingredients":["40 g fine bulgur wheat","150 g flat-leaf parsley, very finely chopped","30 g fresh mint, finely chopped","4 spring onions, finely sliced","3 ripe tomatoes, finely diced","60 ml fresh lemon juice","60 ml extra virgin olive oil","3/4 tsp salt","1/4 tsp ground allspice"],"steps":["Rinse the bulgur and soak in cold water 15 minutes until just tender, then drain and squeeze dry.","Soak the diced tomatoes briefly in their own juice, then drain off the excess.","Chop the parsley and mint by hand into fine ribbons; skip the food processor, which turns them to paste.","Combine the bulgur, herbs, spring onions and tomatoes.","Whisk the lemon, oil, salt and allspice and toss through just before serving."],"pairing":"Serve alongside grills, or with romaine leaves as scoops","tags":["Vegetarian","Vegan","Light","Quick","Make-ahead","Lunchbox"],"vegetarian":true,"spicy":false,"calories":210,"protein":3,"carbs":14,"fat":15,"allergens":["Gluten"],"role":"salad","cuisineKey":"mediterranean","type":"Salads"},{"id":"me-fattoush","name":"Fattoush","category":"Bowls & Salads","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A crunchy Levantine bread salad of crisp toasted pita, cucumber and tomato in a tangy sumac dressing. Toasting the pita and dressing late keeps every shard shatteringly crisp.","ingredients":["2 pita breads, torn","3 tbsp olive oil, for the pita","3 baby cucumbers, sliced","4 ripe tomatoes, cut into wedges","1 baby gem lettuce, chopped","4 radishes, thinly sliced","4 spring onions, sliced","20 g flat-leaf parsley, chopped","10 g fresh mint, chopped","2 tbsp fresh lemon juice","60 ml extra virgin olive oil","1 tbsp sumac, plus extra to finish","1 small garlic clove, crushed","1/2 tsp salt"],"steps":["Toss the torn pita with the 3 tbsp oil and bake at 200C for 8 to 10 minutes until deep golden, then cool.","Combine the cucumbers, tomatoes, lettuce, radishes, spring onions and herbs in a large bowl.","Whisk the lemon, oil, sumac, garlic and salt into a sharp dressing.","Add the crisp pita, pour over the dressing, toss, dust with more sumac and serve at once."],"pairing":"A natural partner to grilled meats; pair with a chilled dry rosé","tags":["Vegetarian","Vegan","Light","Quick","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":280,"protein":4,"carbs":21,"fat":20,"allergens":["Gluten"],"role":"salad","cuisineKey":"mediterranean","type":"Salads"},{"id":"me-greek-salad","name":"Horiatiki (Greek Village Salad)","category":"Bowls & Salads","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"The honest Greek village salad: chunky tomato, cucumber and pepper with a whole slab of feta on top, no lettuce in sight. Great olive oil and dried oregano are all it needs.","ingredients":["500 g ripe tomatoes, cut into wedges","1 cucumber, peeled in stripes and sliced thick","1 green pepper, sliced into rings","1 small red onion, thinly sliced","100 g Kalamata olives","200 g block feta (do not crumble)","60 ml extra virgin olive oil","1 tbsp red wine vinegar","1.5 tsp dried Greek oregano","1/2 tsp salt"],"steps":["Pile the tomato, cucumber, pepper rings and red onion into a wide shallow bowl.","Scatter over the olives and season with the salt.","Lay the whole slab of feta on top rather than crumbling it.","Drizzle generously with oil and the vinegar, dust heavily with oregano and serve at once with bread."],"pairing":"Crusty bread for the juices and a chilled glass of Assyrtiko","tags":["Vegetarian","Gluten-free option","Light","Quick","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":340,"protein":10,"carbs":11,"fat":29,"allergens":["Milk","Sulphites"],"role":"salad","cuisineKey":"mediterranean","type":"Salads"},{"id":"me-halloumi-grain-bowl","name":"Halloumi & Freekeh Bowl with Lemon-Herb Dressing","category":"Bowls & Salads","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A filling lunch bowl of nutty grains, crisp pan-fried halloumi and a bright herb dressing. Uses a pouch of pre-cooked grains so it comes together fast, and it travels well for a lunchbox the next day.","ingredients":["2 x 250 g pouches cooked freekeh or bulgur (or 300 g cooked from dry)","2 x 225 g blocks halloumi, sliced","1 tbsp olive oil, for frying","200 g cherry tomatoes, halved","1 cucumber, diced","60 g rocket","20 g mint, chopped","20 g parsley, chopped","60 ml extra virgin olive oil","2 tbsp lemon juice","1 tsp honey","1/2 tsp salt","2 tbsp pomegranate seeds, to finish"],"steps":["Warm the grains through and tip into a big bowl with the tomatoes, cucumber, rocket and herbs.","Fry the halloumi in the olive oil over medium-high heat 2 minutes a side until golden and crisp.","Whisk the extra virgin oil, lemon, honey and salt into a dressing and toss most of it through the grains.","Top with the hot halloumi, drizzle the rest of the dressing and scatter pomegranate seeds."],"pairing":"A chilled Assyrtiko or sparkling water with lemon","tags":["Vegetarian","Quick","Lunchbox","Make-ahead","Light"],"vegetarian":true,"spicy":false,"calories":620,"protein":28,"carbs":35,"fat":41,"allergens":["Gluten","Milk"],"role":"salad","cuisineKey":"mediterranean","type":"Salads"},{"id":"me-ottolenghi-roast-aubergine","name":"Roasted Aubergine with Saffron Yoghurt & Pomegranate","category":"Bowls & Salads","course":"Starter","meal":"both","tier":"signature","inspiration":"Ottolenghi (Yotam Ottolenghi, London)","minutes":50,"serves":4,"level":"Weekend","idea":"The dish from the cover of Ottolenghi's Plenty: aubergine halves roasted until collapsing, draped in saffron-stained yoghurt and showered with pomegranate seeds and za'atar. A study in contrast, soft and silky against jewel-bright tart seeds, that defined a generation of vegetable cooking.","ingredients":["4 medium aubergines, halved lengthways","90 ml olive oil","1 tsp salt","1/2 tsp black pepper","1 large pinch saffron threads","3 tbsp hot water","250 g Greek yoghurt","1 small garlic clove, crushed","2 tbsp lemon juice","1 tbsp extra virgin olive oil","seeds of 1 pomegranate (about 120 g)","2 tsp za'atar","10 g mint leaves, torn"],"steps":["Heat the oven to 220C. Score the cut faces of the aubergines in a criss-cross, brush generously with the olive oil and season with salt and pepper.","Roast cut-side up for 35 to 40 minutes until deeply golden and completely soft. Cool to warm.","Steep the saffron in the hot water for 5 minutes, then whisk into the yoghurt with the garlic, lemon juice, extra virgin oil and a pinch of salt to a pourable cream.","Arrange the aubergines on a platter and spoon the saffron yoghurt generously over the cut faces.","Shower with pomegranate seeds, dust with za'atar and scatter the mint. Serve warm or at room temperature."],"pairing":"Warm flatbread and a glass of dry Provençal rosé","tags":["Vegetarian","Gluten-free option","Make-ahead","Light","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":340,"protein":7,"carbs":20,"fat":27,"allergens":["Milk","Sesame"],"role":"salad","cuisineKey":"mediterranean","type":"Salads"},{"id":"me-shish-taouk","name":"Shish Taouk (Lebanese Garlic Chicken Skewers)","cuisineKey":"mediterranean","category":"Grills & Mains","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":40,"serves":4,"level":"Weeknight","idea":"Yoghurt-and-garlic marinated chicken skewers, charred and served with toum and warm flatbread for a light, satisfying lunch or dinner main.","ingredients":["800 g boneless skinless chicken thighs, cut into 3 cm pieces","4 tbsp Greek yoghurt","3 tbsp olive oil","3 tbsp lemon juice","5 garlic cloves, crushed","1 tbsp tomato paste","1 tsp sweet paprika","1 tsp dried oregano","1/2 tsp ground allspice","1 tsp salt","1/2 tsp black pepper","4 flatbreads, to serve"],"steps":["Whisk yoghurt, olive oil, lemon juice, garlic, tomato paste, paprika, oregano, allspice, salt and pepper in a bowl.","Add the chicken and toss to coat. Cover and marinate at least 30 minutes, ideally 2 hours.","Thread the chicken onto skewers, leaving a little space between pieces.","Grill over high heat or under a hot grill for 10 to 12 minutes, turning, until charred and cooked through.","Rest 3 minutes, then serve on warm flatbread with toum and pickles."],"pairing":"Toum garlic sauce and warm flatbread","tags":["chicken","grilled","skewers","high-protein"],"vegetarian":false,"spicy":false,"calories":420,"protein":44,"carbs":22,"fat":17,"allergens":["Gluten","Milk"],"type":"Grills & BBQ"},{"id":"me-samke-harra","name":"Samke Harra (Spiced Tahini Baked Fish)","cuisineKey":"mediterranean","category":"Grills & Mains","role":"main","course":"Main","meal":"both","tier":"signature","inspiration":"EM SHERIF (Mireille Hayek, Beirut)","minutes":55,"serves":4,"level":"Weekend","idea":"A Tripoli classic of whole white fish baked under a fiery coriander, chilli and walnut tahini sauce, finished with toasted pine nuts in the refined Em Sherif style.","ingredients":["4 sea bass or sea bream fillets (about 600 g)","3 tbsp olive oil","1 tsp salt","1/2 tsp black pepper","150 g tahini, well stirred","90 ml lemon juice","120 ml water","6 garlic cloves, crushed","30 g fresh coriander, chopped","1 red chilli, finely chopped","1 tsp ground cumin","1/2 tsp Aleppo pepper","40 g pine nuts, toasted","20 g walnuts, chopped"],"steps":["Heat oven to 200 C. Pat the fish dry, rub with olive oil, salt and pepper and set in a baking dish.","Whisk tahini with lemon juice and water until smooth and pourable, loosening with more water if needed.","Soften the garlic, coriander, chilli, cumin and Aleppo pepper in a little oil for 2 minutes, then stir into the tahini.","Spoon the sauce over the fish to coat generously.","Bake 18 to 22 minutes until the fish flakes and the sauce is bubbling and just golden.","Scatter with toasted pine nuts and walnuts and serve with rice or flatbread."],"pairing":"Vermicelli rice and a squeeze of lemon","tags":["fish","baked","tahini","levantine"],"vegetarian":false,"spicy":true,"calories":510,"protein":40,"carbs":14,"fat":34,"allergens":["Fish","Sesame","Tree nuts"],"type":"Grills & BBQ"},{"id":"me-makloubeh","name":"Makloubeh (Upside-Down Spiced Chicken & Rice)","cuisineKey":"mediterranean","category":"Grills & Mains","role":"main","course":"Main","meal":"dinner","tier":"signature","inspiration":"Tawlet (Kamal Mouzawak, Beirut)","minutes":80,"serves":6,"level":"Project","idea":"The celebrated upside-down Levantine rice pot, layered with fried aubergine, spiced chicken and saffron rice, dramatically flipped at the table and showered with toasted nuts.","ingredients":["8 bone-in skin-on chicken thighs (about 1 kg)","2 large aubergines, sliced into rounds","1 large cauliflower, cut into florets","400 g basmati rice, rinsed and soaked 20 minutes","2 tsp ground allspice","1 tsp ground cinnamon","1 tsp ground cumin","1/2 tsp ground turmeric","1 large pinch saffron","2 tsp salt","90 ml olive oil","1 litre chicken stock","60 g pine nuts, toasted","60 g flaked almonds, toasted","20 g parsley, chopped"],"steps":["Simmer the chicken in the stock with half the spices and 1 tsp salt for 25 minutes, then reserve chicken and stock.","Fry or roast the aubergine and cauliflower in olive oil until deeply golden; drain.","In a heavy pot, layer the chicken skin-side down, then aubergine and cauliflower, then the drained spiced rice.","Pour over the reserved stock to just cover the rice, season, cover and cook gently 30 to 35 minutes until rice is tender.","Rest 10 minutes off the heat, place a large platter over the pot and confidently flip.","Scatter with pine nuts, almonds and parsley and serve with cucumber yoghurt."],"pairing":"Cucumber and mint yoghurt","tags":["chicken","rice","one-pot","celebration"],"vegetarian":false,"spicy":false,"calories":680,"protein":38,"carbs":62,"fat":32,"allergens":["Tree nuts"],"type":"Grills & BBQ"},{"id":"me-freekeh-roast-veg","name":"Smoky Freekeh with Roasted Vegetables & Tahini","cuisineKey":"mediterranean","category":"Grills & Mains","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Nutty smoked freekeh tossed with roasted squash, courgette and chickpeas under a lemon tahini drizzle, a hearty vegetarian main that holds up for lunch the next day.","ingredients":["300 g freekeh, rinsed","700 ml vegetable stock","500 g butternut squash, diced","2 courgettes, sliced","1 x 400 g tin chickpeas, drained","4 tbsp olive oil","1 tsp ground cumin","1 tsp sweet paprika","1 tsp salt","90 g tahini, well stirred","2 tbsp lemon juice","60 ml water","20 g parsley, chopped","2 tbsp pomegranate seeds"],"steps":["Heat oven to 210 C. Toss squash, courgette and chickpeas with 3 tbsp oil, cumin, paprika and salt; roast 25 to 30 minutes until caramelised.","Meanwhile simmer freekeh in the stock for 20 to 25 minutes until tender, then drain any excess and fluff.","Whisk tahini with lemon juice and water to a pourable sauce.","Fold the roasted vegetables through the warm freekeh with the remaining oil.","Plate, drizzle generously with tahini and scatter parsley and pomegranate seeds."],"pairing":"A dollop of garlic yoghurt","tags":["grains","meal-prep","tahini"],"vegetarian":true,"spicy":false,"calories":540,"protein":18,"carbs":68,"fat":24,"allergens":["Gluten","Sesame"],"type":"Grills & BBQ"},{"id":"me-kibbeh-trio","name":"Baked Kibbeh with Pine Nuts","cuisineKey":"mediterranean","category":"Mezze","role":"appetizer","course":"Starter","meal":"both","tier":"signature","inspiration":"EM SHERIF (Mireille Hayek, Beirut)","minutes":70,"serves":6,"level":"Project","idea":"A burnished tray of bulgur and lamb kibbeh layered around a spiced pine-nut filling, cut into the classic diamonds, an Em Sherif table essential.","ingredients":["300 g fine bulgur wheat","500 g lean minced lamb","1 onion, grated","1.5 tsp ground allspice","1 tsp ground cinnamon","1 tsp salt","1/2 tsp black pepper","300 g minced lamb, for filling","1 onion, finely chopped, for filling","60 g pine nuts, toasted","1 tbsp pomegranate molasses","60 ml olive oil"],"steps":["Soak the bulgur in cold water 15 minutes, then squeeze dry.","Blend the bulgur, 500 g lamb, grated onion, allspice, cinnamon, salt and pepper to a smooth paste, adding a little iced water.","For the filling, fry the chopped onion and remaining lamb until browned, stir in pine nuts and pomegranate molasses, season and cool.","Press half the kibbeh paste into an oiled tray, spread the filling, then top with the remaining paste, smoothing the surface.","Score into diamonds, brush with olive oil and bake at 200 C for 30 to 35 minutes until deep golden.","Rest briefly and serve warm with yoghurt."],"pairing":"Cool labneh or garlic yoghurt","tags":["lamb","kibbeh","mezze","baked"],"vegetarian":false,"spicy":false,"calories":380,"protein":22,"carbs":26,"fat":21,"allergens":["Gluten","Tree nuts"],"type":"Starters"},{"id":"me-sambousek-cheese","name":"Sambousek (Cheese & Herb Pastries)","cuisineKey":"mediterranean","category":"Mezze","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":6,"level":"Weekend","idea":"Crisp little half-moon pastries filled with melting akkawi and halloumi and fresh mint, a beloved Levantine mezze for sharing.","ingredients":["12 sheets shortcrust or sambousek pastry rounds","200 g akkawi or mozzarella, grated","100 g halloumi, grated","20 g mint, chopped","20 g parsley, chopped","1 spring onion, finely sliced","1/2 tsp black pepper","1 egg, beaten, for sealing","1 litre neutral oil, for frying"],"steps":["Mix the cheeses, mint, parsley, spring onion and pepper into a filling.","Place a spoonful on each pastry round, brush the edge with egg and fold into a half-moon, crimping firmly.","Heat the oil to 175 C.","Fry the sambousek in batches for 2 to 3 minutes until golden and crisp.","Drain on paper and serve hot with a lemon wedge."],"pairing":"Lemon wedges and a tomato dip","tags":["pastry","cheese","fried","mezze"],"vegetarian":true,"spicy":false,"calories":300,"protein":11,"carbs":24,"fat":18,"allergens":["Gluten","Milk","Egg"],"type":"Starters"},{"id":"me-warak-enab","name":"Warak Enab (Stuffed Vine Leaves)","cuisineKey":"mediterranean","category":"Mezze","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":75,"serves":6,"level":"Project","idea":"Vine leaves rolled tight around lemony herbed rice and slow-simmered until silky, the cold mezze that anchors every Levantine spread.","ingredients":["250 g vine leaves in brine, rinsed","200 g short-grain rice, rinsed","3 ripe tomatoes, finely diced","1 onion, finely chopped","30 g parsley, chopped","20 g mint, chopped","90 ml extra virgin olive oil","90 ml lemon juice","1 tsp ground allspice","1 tsp salt","1/2 tsp black pepper","400 ml water"],"steps":["Mix the rice, tomatoes, onion, herbs, half the olive oil, half the lemon juice, allspice, salt and pepper.","Lay a vine leaf vein-side up, place a little filling near the stem, fold the sides and roll tightly.","Line a pot with a few leaves, then pack the rolls in snug layers.","Pour over the water, remaining oil and lemon juice, weigh down with a plate and simmer gently 45 minutes until the rice is tender.","Cool in the pot, then serve at room temperature with lemon."],"pairing":"Thick labneh and lemon","tags":["vine-leaves","mezze","make-ahead"],"vegetarian":true,"spicy":false,"calories":240,"protein":4,"carbs":34,"fat":11,"allergens":[],"type":"Starters"},{"id":"me-batata-harra","name":"Batata Harra (Spicy Coriander Potatoes)","cuisineKey":"mediterranean","category":"Mezze","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Crisp cubes of potato tossed in garlic, coriander, chilli and lemon, a punchy hot mezze that disappears fast.","ingredients":["800 g potatoes, cut into 2 cm cubes","4 tbsp olive oil","6 garlic cloves, crushed","30 g fresh coriander, chopped","1 red chilli, finely chopped","1/2 tsp Aleppo pepper","1 tsp salt","2 tbsp lemon juice"],"steps":["Heat oven to 220 C. Toss the potatoes with 3 tbsp oil and salt and roast 25 minutes until crisp and golden.","In a pan, warm the remaining oil and gently fry the garlic, chilli and Aleppo pepper for 1 minute.","Add the roasted potatoes and most of the coriander and toss to coat.","Finish with lemon juice and the remaining coriander and serve hot."],"pairing":"Garlic toum or labneh","tags":["potatoes","mezze"],"vegetarian":true,"spicy":true,"calories":260,"protein":4,"carbs":36,"fat":12,"allergens":[],"type":"Starters"},{"id":"me-salatet-rocca","name":"Salatet Rocca (Rocket, Tomato & Sumac Salad)","cuisineKey":"mediterranean","category":"Bowls & Salads","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Peppery rocket with sweet tomatoes, thin red onion and walnuts in a sumac and pomegranate dressing, the bright Levantine answer to a green salad.","ingredients":["100 g rocket","250 g cherry tomatoes, halved","1 small red onion, thinly sliced","60 g walnuts, toasted","2 tbsp extra virgin olive oil","1 tbsp pomegranate molasses","1 tbsp lemon juice","1 tsp sumac","1/2 tsp salt","2 tbsp pomegranate seeds"],"steps":["Whisk the olive oil, pomegranate molasses, lemon juice, sumac and salt into a dressing.","Combine the rocket, tomatoes and red onion in a bowl.","Toss with the dressing just before serving.","Scatter with walnuts and pomegranate seeds."],"pairing":"Grilled halloumi or any kebab","tags":["salad","sumac","quick"],"vegetarian":true,"spicy":false,"calories":210,"protein":4,"carbs":12,"fat":17,"allergens":["Tree nuts"],"type":"Salads"},{"id":"me-jajik-cucumber","name":"Khyar bi Laban (Cucumber Mint Yoghurt Salad)","cuisineKey":"mediterranean","category":"Bowls & Salads","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":10,"serves":4,"level":"Weeknight","idea":"Cool strained yoghurt with crisp cucumber, garlic and dried mint, the calming foil to every grill and spice on the table.","ingredients":["400 g Greek yoghurt","2 baby cucumbers, finely diced","1 small garlic clove, crushed","2 tsp dried mint","1 tbsp extra virgin olive oil","1/2 tsp salt","1 tbsp fresh mint, chopped"],"steps":["Stir the yoghurt with the garlic, dried mint and salt until smooth.","Fold in the diced cucumber.","Spoon into a bowl and drizzle with olive oil.","Finish with fresh mint and serve chilled."],"pairing":"Any kebab, kibbeh or rice dish","tags":["yoghurt","cooling","quick"],"vegetarian":true,"spicy":false,"calories":120,"protein":7,"carbs":7,"fat":7,"allergens":["Milk"],"type":"Salads"},{"id":"me-loubieh-salad","name":"Loubieh b'Zeit (Braised Green Beans in Olive Oil)","cuisineKey":"mediterranean","category":"Bowls & Salads","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":40,"serves":4,"level":"Weeknight","idea":"Green beans slow-braised with tomato, onion and garlic in good olive oil, served at room temperature as a classic Levantine cold dish.","ingredients":["500 g green beans, trimmed","1 onion, sliced","4 garlic cloves, sliced","400 g ripe tomatoes, chopped","60 ml extra virgin olive oil","1 tsp ground allspice","1 tsp salt","1/2 tsp black pepper","1 tbsp lemon juice"],"steps":["Soften the onion and garlic in the olive oil over medium heat for 5 minutes.","Add the tomatoes, allspice, salt and pepper and cook down for 5 minutes.","Stir in the green beans, cover and braise gently 25 minutes until very tender and glossy.","Finish with lemon juice, cool to room temperature and serve."],"pairing":"Warm flatbread to mop the oil","tags":["beans","braised","make-ahead"],"vegetarian":true,"spicy":false,"calories":190,"protein":4,"carbs":16,"fat":13,"allergens":[],"type":"Salads"},{"id":"it-pizza-margherita","name":"Pizza Margherita","category":"Pizza","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"The benchmark pie made approachable: shop-bought dough, raw crushed tomato, milky mozzarella and fresh basil. Three or four good ingredients doing all the work in a hot home oven.","ingredients":["2 ready-made pizza dough balls (about 250g each)","200g tinned chopped tomatoes, drained slightly","180g mozzarella, torn and patted dry","8 fresh basil leaves","2 tbsp olive oil","plain flour for dusting","pinch of salt"],"steps":["Heat the oven as hot as it goes (250C or higher) with a baking tray or stone inside for at least 20 minutes.","Season the tomatoes with a pinch of salt and a little oil. Do not cook them.","Stretch each dough ball by hand on a floured surface into a round, leaving a thicker rim.","Spread a thin layer of tomato, scatter the mozzarella and drizzle with oil.","Slide onto the hot tray and bake 8 to 10 minutes until the crust is golden and the cheese bubbles.","Finish with fresh basil and a thread of oil. Repeat with the second pizza."],"pairing":"A chilled light red or sparkling water with lemon","tags":["Vegetarian","Crowd-pleaser","Comfort","Quick"],"vegetarian":true,"spicy":false,"calories":620,"protein":24,"carbs":78,"fat":24,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pizza"},{"id":"it-pizza-marinara","name":"Pizza Marinara","category":"Pizza","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"The oldest Neapolitan pizza, dressed only with tomato, garlic, oregano and oil. No cheese at all, proof that a good crust needs almost nothing to sing. Naturally vegan and pantry-friendly.","ingredients":["2 ready-made pizza dough balls (about 250g each)","220g tinned chopped tomatoes","3 garlic cloves, thinly sliced","1 tsp dried oregano","3 tbsp olive oil","plain flour for dusting","pinch of salt"],"steps":["Heat the oven as hot as it goes with a tray or stone inside for at least 20 minutes.","Season the tomatoes with a pinch of salt.","Stretch each dough ball by hand into a round with a raised rim.","Spread the tomato thinly, scatter the sliced garlic and oregano, and drizzle generously with oil.","Bake 8 to 10 minutes until the rim is golden and puffed.","Finish with a last drizzle of oil and serve at once."],"pairing":"A crisp dry white or chilled lager","tags":["Vegan","Crowd-pleaser","Comfort","Quick"],"vegetarian":true,"spicy":false,"calories":570,"protein":13,"carbs":80,"fat":23,"allergens":["Gluten"],"role":"main","cuisineKey":"italian","type":"Pizza"},{"id":"it-pizza-prosciutto-rucola","name":"Pizza with Mozzarella, Rocket and Tomato","category":"Pizza","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"A bistro-style pizza finished cold: melted mozzarella under a tangle of peppery rocket, sweet cherry tomatoes and shaved Parmesan. Fresh, fast and a guaranteed crowd-pleaser with kids and adults alike.","ingredients":["2 ready-made pizza dough balls (about 250g each)","200g mozzarella, torn and patted dry","150g cherry tomatoes, halved","60g rocket","30g Parmesan, shaved","3 tbsp olive oil","plain flour for dusting","salt and pepper"],"steps":["Heat the oven as hot as it goes with a tray inside for 20 minutes.","Stretch each dough ball into a round, brush lightly with oil and scatter over the mozzarella.","Bake 8 to 10 minutes until golden and bubbling.","Toss the rocket and cherry tomatoes with a little oil, salt and pepper.","Pile the salad onto the hot pizzas, shave over the Parmesan and finish with a drizzle of oil.","Slice and serve right away while the base is crisp."],"pairing":"A light Pinot Grigio or sparkling water","tags":["Vegetarian","Quick","Light","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":640,"protein":28,"carbs":75,"fat":26,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pizza"},{"id":"it-pizza-margherita-sbagliata","name":"Margherita Sbagliata","category":"Pizza","course":"Main","meal":"dinner","tier":"signature","inspiration":"Osteria Francescana (Massimo Bottura)","minutes":120,"serves":2,"level":"Project","idea":"Franco Pepe's deconstructed Margherita from Caiazzo, repeatedly crowned among the world's best pizzas. The cheese cream and basil go on the airy, just-baked crust, then tomato is piped on raw in concentric drops so each element reads on its own.","ingredients":["300g tipo 00 flour","210ml cold water","6g fine sea salt","1g instant dry yeast","250g tinned San Marzano tomatoes, blended and lightly seasoned","200g fior di latte mozzarella","60ml double cream","large handful fresh basil, blitzed with a little oil into a bright sauce","extra virgin olive oil","semolina for dusting"],"steps":["Mix flour, water and yeast to a shaggy dough, add salt and knead 10 minutes until smooth. Cover and prove 1 hour, then ball up and rest 4 to 6 hours, or overnight in the fridge.","Blend the mozzarella with the cream into a smooth, spoonable cheese cream and chill. Season the blended tomato lightly and keep it raw.","Heat the oven to its absolute maximum with a steel or stone for at least 45 minutes.","Stretch one dough ball by hand into a 28cm round with a pronounced rim and bake plain, or with just a film of oil, 6 to 8 minutes until blistered and puffed.","On the hot base spread the cold cheese cream, then dot the basil sauce over it.","Pipe the raw tomato in small concentric drops across the top so it stays vivid and uncooked.","Finish with a thread of olive oil and serve immediately, repeating for the second pizza."],"pairing":"A grower Champagne or a dry Falanghina","tags":["Vegetarian","Date night","Comfort"],"vegetarian":true,"spicy":false,"calories":600,"protein":22,"carbs":72,"fat":24,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pizza"},{"id":"it-spaghetti-aglio-olio","name":"Spaghetti Aglio e Olio","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"The midnight classic from four pantry staples: garlic and chilli warmed gently in good oil, tossed through spaghetti with parsley. The fastest real dinner in the Italian repertoire.","ingredients":["200g spaghetti","4 garlic cloves, thinly sliced","0.5 tsp chilli flakes","5 tbsp olive oil","small handful flat-leaf parsley, chopped","salt for the pasta water"],"steps":["Boil the spaghetti in well-salted water until al dente, reserving a mugful of water before draining.","Meanwhile gently warm the oil with the garlic and chilli until the garlic is pale gold, never browned.","Add the drained pasta and a splash of pasta water, tossing hard to bind into a light, glossy sauce.","Stir through the parsley, season and serve at once."],"pairing":"A crisp dry white or sparkling water","tags":["Vegan","Quick","Comfort","One-pan"],"vegetarian":true,"spicy":false,"calories":560,"protein":11,"carbs":70,"fat":27,"allergens":["Gluten"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-penne-pomodoro-basilico","name":"Penne al Pomodoro e Basilico","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"The everyday red sauce done properly: tinned tomatoes simmered with garlic and a knob of butter until sweet and silky, tossed with penne and torn basil. A reliable family workhorse that batch-cooks beautifully.","ingredients":["400g penne","800g tinned chopped tomatoes (2 tins)","3 garlic cloves, sliced","30g butter","3 tbsp olive oil","large handful fresh basil","40g Parmesan, grated, to serve","salt and a pinch of sugar"],"steps":["Soften the garlic in the oil over low heat until fragrant, do not colour.","Add the tomatoes, a pinch of salt and sugar, and simmer 15 to 18 minutes until thick and sweet.","Stir in the butter and torn basil for gloss and roundness.","Cook the penne in well-salted water until al dente and drain, saving a splash of water.","Toss the pasta through the sauce with a little reserved water to coat.","Serve with grated Parmesan."],"pairing":"A young Sangiovese or red grape juice for the kids","tags":["Vegetarian","Batch-cook","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":480,"protein":15,"carbs":78,"fat":12,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-spaghetti-carbonara","name":"Spaghetti alla Carbonara","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Rome's most argued-over plate: egg yolks, Pecorino, crisp guanciale and black pepper emulsified into a glossy, clinging sauce. No cream, the silk comes from technique alone.","ingredients":["200g spaghetti","120g guanciale or pancetta, cut into lardons","3 large egg yolks plus 1 whole egg","60g Pecorino Romano, finely grated","1 tsp freshly cracked black pepper, plus extra","salt for the pasta water"],"steps":["Boil the spaghetti in well-salted water until al dente, reserving a mugful of starchy water before draining.","Render the guanciale in a cold dry pan over medium heat until the fat is golden and the meat crisp, then take off the heat.","Whisk the yolks, whole egg, Pecorino and black pepper into a thick paste.","Add the drained pasta to the guanciale pan off the heat, tossing in the rendered fat.","Loosen the egg mixture with a spoon of hot pasta water, add to the pan and toss vigorously off the heat, adding more water until the sauce turns creamy and coats every strand.","Serve immediately with extra Pecorino and a grind of pepper. The residual heat cooks the egg gently without scrambling it."],"pairing":"A dry Frascati Superiore","tags":["Quick","Comfort","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":720,"protein":31,"carbs":72,"fat":34,"allergens":["Gluten","Egg","Milk"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-cacio-e-pepe","name":"Cacio e Pepe","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Three ingredients, real technique. Pecorino and toasted black pepper bound with starchy water into a creamy sauce. The temperature trick is the whole game.","ingredients":["200g spaghetti or tonnarelli","100g Pecorino Romano, very finely grated","2 tsp whole black peppercorns, coarsely cracked","salt for the pasta water"],"steps":["Boil the pasta in lightly salted water (Pecorino is salty) until just shy of al dente, reserving plenty of starchy water.","Toast the cracked pepper in a dry pan 30 seconds until fragrant, then add a ladle of pasta water to make a peppery broth.","In a bowl, mix the grated Pecorino with a little cool pasta water into a smooth paste, never hot or it will clump.","Drain the pasta into the pepper pan and toss to coat.","Off the heat, add the Pecorino paste and toss hard, loosening with more starchy water until glossy and creamy.","Serve at once, the sauce should cling, never pool."],"pairing":"A mineral white or sparkling water","tags":["Vegetarian","Quick","Comfort"],"vegetarian":true,"spicy":false,"calories":520,"protein":22,"carbs":72,"fat":15,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-penne-all-arrabbiata","name":"Penne all'Arrabbiata","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Angry pasta, the Roman way: garlic and dried chilli bloomed in oil, tomatoes reduced to a punchy sauce. Fiery, fast and built from the storecupboard.","ingredients":["200g penne rigate","400g tinned chopped tomatoes","3 garlic cloves, sliced","1 tsp chilli flakes (or 2 crumbled dried chillies)","4 tbsp olive oil","small handful flat-leaf parsley, chopped","salt"],"steps":["Boil the penne in well-salted water until al dente, reserving some pasta water.","Gently warm the oil with the garlic and chilli until the garlic is pale gold and the oil is fragrant, do not burn it.","Add the tomatoes, season with salt and simmer 12 to 15 minutes until thick and glossy.","Drain the pasta and toss in the sauce with a splash of pasta water to bind.","Stir through the parsley and serve. Traditionally no cheese in Rome.","Adjust the heat with more chilli at the end."],"pairing":"A robust Montepulciano d'Abruzzo","tags":["Vegan","Quick","Spicy"],"vegetarian":true,"spicy":true,"calories":520,"protein":12,"carbs":78,"fat":18,"allergens":["Gluten"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-pasta-al-forno","name":"Pasta al Forno","category":"Pasta","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"The family baked pasta that beats fiddly lasagne on a busy night: penne tossed in a quick tomato sauce with mozzarella and Parmesan, then baked until the top is bubbling and the edges crisp. One dish, big batch, kids clear the plate.","ingredients":["400g penne or rigatoni","800g tinned chopped tomatoes (2 tins)","3 garlic cloves, sliced","3 tbsp olive oil","200g mozzarella, torn and drained","60g Parmesan, grated","large handful fresh basil","salt and a pinch of sugar"],"steps":["Heat the oven to 200C. Soften the garlic in the oil over low heat, then add the tomatoes, a pinch of salt and sugar and simmer 15 minutes until thick. Tear in the basil.","Boil the pasta in well-salted water for two minutes less than the packet says, so it finishes in the oven, then drain.","Toss the pasta through most of the sauce in a baking dish, folding in half the mozzarella.","Top with the rest of the sauce, the remaining mozzarella and the Parmesan.","Bake 15 to 18 minutes until bubbling and golden with crisp edges.","Rest 5 minutes, then serve."],"pairing":"A young Sangiovese or red grape juice for the kids","tags":["Vegetarian","Batch-cook","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":560,"protein":23,"carbs":80,"fat":16,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-rigatoni-vodka","name":"Spicy Rigatoni alla Vodka","category":"Pasta","course":"Main","meal":"dinner","tier":"signature","inspiration":"Carbone","minutes":40,"serves":4,"level":"Weekend","idea":"The dish that broke the internet: Carbone's luxe, blushing vodka sauce with a low hum of Calabrian chilli, clinging to ridged rigatoni and finished with a storm of Parmesan. Restaurant decadence built at home.","ingredients":["400g rigatoni","1 onion, finely chopped","4 garlic cloves, minced","70g tomato puree (double concentrate)","2 tbsp Calabrian chilli paste (or 1 tsp chilli flakes)","60ml vodka","250ml double cream","60g butter","80g Parmesan, finely grated, plus extra","3 tbsp olive oil","fresh basil","salt"],"steps":["Soften the onion gently in the oil and half the butter until sweet and translucent, about 8 minutes, then add the garlic for a minute.","Stir in the tomato puree and Calabrian chilli and cook until the paste darkens and turns rust-red, 4 to 5 minutes, to kill the raw edge.","Pour in the vodka and let it cook off for a minute, then stir in the cream to a smooth, blushing sauce. Simmer gently 5 minutes.","Cook the rigatoni in well-salted water until al dente, reserving a mug of water.","Toss the pasta into the sauce with the remaining butter and the Parmesan, loosening with pasta water until glossy and emulsified.","Finish with extra Parmesan and torn basil, and serve at once."],"pairing":"A bright Barbera or a Negroni to start","tags":["Spicy","Date night","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":true,"calories":680,"protein":18,"carbs":78,"fat":31,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Pasta"},{"id":"it-risotto-parmigiano","name":"Risotto al Parmigiano","category":"Risotto","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"The plain white risotto every Italian cook leans on: rice toasted, fed with stock and finished with butter and Parmesan into something creamy and comforting. The blank canvas, and delicious on its own.","ingredients":["320g Arborio or Carnaroli rice","1 small onion, finely diced","150ml dry white wine (optional)","1.2 litres hot vegetable stock","60g butter","70g Parmesan, grated","2 tbsp olive oil","salt and pepper"],"steps":["Sweat the onion in the oil and half the butter until soft and translucent.","Add the rice and toast 2 minutes until the edges turn glassy. Add the wine if using and let it evaporate.","Add the hot stock a ladle at a time, stirring, letting each addition absorb before the next, about 18 minutes until al dente and creamy.","Off the heat, beat in the cold butter and Parmesan vigorously until glossy.","Rest 1 minute, season and serve loose so it spreads when plated."],"pairing":"A soft Soave or sparkling water","tags":["Vegetarian","Comfort","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":480,"protein":11,"carbs":68,"fat":16,"allergens":["Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Rice & Bowls"},{"id":"it-risotto-ai-funghi","name":"Risotto ai Funghi","category":"Risotto","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":40,"serves":4,"level":"Weekend","idea":"Earthy mushrooms folded into creamy rice, finished with butter and Parmesan. A handful of dried porcini in the stock builds a deep, woodsy flavour that fresh mushrooms alone cannot reach.","ingredients":["320g Carnaroli or Arborio rice","20g dried porcini","250g chestnut mushrooms, sliced","1 small onion, finely diced","150ml dry white wine","1.2 litres hot vegetable stock","60g butter","60g Parmesan, grated","2 tbsp olive oil","small handful parsley, chopped","salt and pepper"],"steps":["Soak the dried porcini in 300ml warm water 20 minutes, then lift out, chop, and strain the liquor into the stock.","Sweat the onion in oil and half the butter, add the fresh mushrooms and porcini and cook until golden.","Stir in the rice and toast 2 minutes, then add the wine and let it evaporate.","Add the hot stock a ladle at a time, stirring, about 18 minutes until al dente and creamy.","Off the heat, beat in the cold butter and Parmesan to mantecare.","Rest 1 minute, scatter parsley and serve loose."],"pairing":"A Barbera d'Alba or earthy red","tags":["Vegetarian","Comfort","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":470,"protein":11,"carbs":67,"fat":15,"allergens":["Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Rice & Bowls"},{"id":"it-risotto-zucca","name":"Risotto alla Zucca","category":"Risotto","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"A sweet, golden butternut squash risotto that kids actually eat. The squash half-melts into the rice for natural creaminess, finished with sage butter and Parmesan. Cosy autumn comfort from supermarket basics.","ingredients":["320g Arborio rice","500g butternut squash, peeled and diced","1 small onion, finely diced","150ml dry white wine (optional)","1.2 litres hot vegetable stock","60g butter","8 sage leaves","60g Parmesan, grated","2 tbsp olive oil","salt and pepper"],"steps":["Sweat the onion in oil and half the butter, then add the squash and cook 5 minutes to soften.","Stir in the rice and toast 2 minutes, add the wine if using and let it evaporate.","Add the hot stock a ladle at a time, stirring, about 18 minutes; the squash will break down and thicken the rice.","Crisp the sage in the remaining butter in a small pan.","Off the heat, beat the Parmesan and sage butter through the risotto until glossy.","Rest 1 minute, season and serve."],"pairing":"A light off-dry white or apple juice for the kids","tags":["Vegetarian","Comfort","Gluten-free option","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":470,"protein":10,"carbs":72,"fat":15,"allergens":["Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Rice & Bowls"},{"id":"it-risotto-oro-zafferano","name":"Riso, Oro e Zafferano","category":"Risotto","course":"Main","meal":"dinner","tier":"signature","inspiration":"Le Calandre","minutes":45,"serves":4,"level":"Weekend","idea":"Gualtiero Marchesi's iconic 1981 reinvention of Risotto alla Milanese: a flawless saffron risotto crowned with a square of edible gold leaf. The defining dish of modern Italian cuisine, all about precision and the all'onda wave.","ingredients":["320g Carnaroli rice","1 small onion, very finely diced","1 generous pinch saffron threads (about 0.2g)","150ml dry white wine","1.2 litres hot vegetable or light chicken stock","100g cold butter, cubed","80g Parmesan, grated","4 squares edible gold leaf (optional, to finish)","salt and white pepper"],"steps":["Bloom the saffron in a small cup of warm stock to release its colour and aroma.","Sweat the onion in a little of the butter until completely soft and translucent, with no colour.","Add the rice dry and toast 2 to 3 minutes until the grains are hot and glassy, then add the wine and let it evaporate.","Add the hot stock a ladle at a time, stirring constantly, for about 16 minutes, stirring in the saffron stock halfway through.","When the rice is al dente, take off the heat and mantecare hard with the cold butter and Parmesan until intensely glossy and rippling.","Plate so the risotto spreads in a smooth all'onda wave, then lay a square of gold leaf at the centre of each plate."],"pairing":"A Franciacorta or a fine oaked Chardonnay","tags":["Vegetarian","Date night","Gluten-free option","Comfort"],"vegetarian":true,"spicy":false,"calories":540,"protein":12,"carbs":66,"fat":23,"allergens":["Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Rice & Bowls"},{"id":"it-pollo-alla-parmigiana","name":"Pollo alla Parmigiana","category":"Secondi","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weekend","idea":"Crisp breaded chicken under a bright tomato sauce and melting mozzarella. A trattoria favourite that hinges on a thin, well-seasoned crumb and a sauce that stays lively. A guaranteed family win.","ingredients":["4 chicken breasts, butterflied and lightly pounded","100g plain flour","2 eggs, beaten","150g fine dried breadcrumbs","50g Parmesan, grated, plus extra","400g tinned chopped tomatoes","2 garlic cloves, sliced","200g mozzarella, sliced and drained","handful fresh basil","olive oil for frying","salt and pepper"],"steps":["Make a quick sauce: soften the garlic in oil, add the tomatoes, season and simmer 15 minutes until thick. Tear in basil.","Season the chicken, then coat in flour, beaten egg, then the breadcrumbs mixed with the grated Parmesan.","Shallow-fry in hot oil until golden and crisp on both sides, then drain on paper.","Heat the oven to 200C. Spread a little sauce in a dish, lay in the chicken, spoon over more sauce and top with mozzarella and Parmesan.","Bake 12 to 15 minutes until the cheese is bubbling and the chicken reaches 74C at the centre.","Finish with basil and rest 5 minutes before serving."],"pairing":"A medium-bodied Chianti Classico","tags":["Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":false,"calories":620,"protein":52,"carbs":38,"fat":28,"allergens":["Gluten","Egg","Milk"],"role":"main","cuisineKey":"italian","type":"Mains"},{"id":"it-melanzane-alla-parmigiana","name":"Melanzane alla Parmigiana","category":"Secondi","course":"Main","meal":"dinner","tier":"signature","inspiration":"Osteria Francescana (Massimo Bottura)","minutes":75,"serves":4,"level":"Weekend","idea":"Layers of aubergine, tomato, basil and cheese baked into a rich southern classic. Comfort food that eats as a hearty main and is even better the next day. Make-ahead friendly.","ingredients":["1kg aubergines, sliced 1cm thick","700g passata","2 garlic cloves, sliced","250g mozzarella, sliced and drained","80g Parmesan, grated","large handful fresh basil","olive oil for frying","1 tsp sugar","salt"],"steps":["Salt the aubergine slices in a colander 30 minutes, then pat dry.","Make the sauce: soften the garlic in oil, add the passata, sugar and salt, and simmer 20 minutes. Tear in basil.","Fry the aubergine in batches in hot oil until golden, draining on paper. (Or brush with oil and roast at 220C to save time.)","Heat the oven to 180C. Layer: sauce, aubergine, mozzarella, Parmesan, basil. Repeat for three or four layers, ending with sauce and Parmesan.","Bake 35 to 40 minutes until bubbling and golden.","Rest at least 15 minutes before serving so it sets and slices cleanly."],"pairing":"A bright Cerasuolo di Vittoria","tags":["Vegetarian","Make-ahead","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":430,"protein":19,"carbs":22,"fat":29,"allergens":["Milk"],"role":"main","cuisineKey":"italian","type":"Mains"},{"id":"it-scaloppine-limone","name":"Chicken Scaloppine al Limone","category":"Secondi","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Thin chicken escalopes dusted in flour, pan-fried and finished in a bright lemon-butter sauce. Elegant enough for guests, fast enough for a Tuesday, made from everyday ingredients.","ingredients":["4 chicken breasts, sliced thin and lightly pounded","60g plain flour for dusting","150ml chicken stock","juice of 1.5 lemons","50g butter","2 tbsp olive oil","small handful parsley, chopped","salt and pepper"],"steps":["Season the chicken and dust lightly in flour, shaking off the excess.","Heat the oil and half the butter and fry the escalopes 2 to 3 minutes a side until golden and just cooked, then set aside.","Pour the stock and lemon juice into the pan, scraping up the browned bits, and reduce by half.","Swirl in the remaining cold butter to make a glossy sauce and check the seasoning.","Return the chicken to coat, scatter with parsley and serve at once with the sauce spooned over."],"pairing":"A crisp Vermentino or sparkling water with lemon","tags":["Quick","Light","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":410,"protein":42,"carbs":13,"fat":20,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"italian","type":"Mains"},{"id":"it-saltimbocca-alla-romana","name":"Saltimbocca alla Romana","category":"Secondi","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Veal escalopes wrapped with prosciutto and sage, pan-fried and finished in a white wine butter sauce. The name means jump in the mouth, and it does, fast and elegant.","ingredients":["4 thin veal escalopes (about 400g)","4 slices prosciutto di Parma","8 fresh sage leaves","30g plain flour for dusting","120ml dry white wine","40g butter","2 tbsp olive oil","salt and black pepper"],"steps":["Lay a sage leaf on each escalope, cover with a slice of prosciutto and press or secure with a cocktail stick.","Lightly dust the veal side with flour, shaking off the excess.","Heat the oil and half the butter, fry prosciutto side down 1 minute, then flip and cook 1 to 2 minutes until just done, keeping the veal tender.","Remove the veal and keep warm. Pour the wine into the pan, scraping up the browned bits, and reduce by half.","Swirl in the remaining cold butter to make a glossy sauce, seasoning carefully as the prosciutto is salty.","Spoon the sauce over the saltimbocca and serve at once."],"pairing":"A dry Vernaccia di San Gimignano","tags":["Quick","Date night"],"vegetarian":false,"spicy":false,"calories":520,"protein":48,"carbs":10,"fat":29,"allergens":["Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Mains"},{"id":"it-osso-buco-alla-milanese","name":"Osso Buco alla Milanese","category":"Secondi","course":"Main","meal":"dinner","tier":"signature","inspiration":"Le Calandre","minutes":150,"serves":4,"level":"Project","idea":"The great Lombard braise that Gualtiero Marchesi paired with his gold-leaf saffron risotto: cross-cut veal shanks cooked low and slow with wine and broth until the meat slips from the bone, finished with a vivid lemon, garlic and parsley gremolata.","ingredients":["4 thick veal shank slices (osso buco), about 1.2kg","plain flour for dusting","1 onion, 1 carrot, 1 celery stick, finely diced","200ml dry white wine","400ml veal or beef stock","2 tbsp tomato puree","40g butter and 2 tbsp olive oil","for the gremolata: zest of 1 lemon, 1 garlic clove and a handful of parsley, all finely chopped","salt and pepper"],"steps":["Tie each shank around the middle with string so it holds shape, season and dust lightly with flour.","Brown the shanks well in the butter and oil, then set aside.","Sweat the onion, carrot and celery in the same pan until soft. Stir in the tomato puree, pour in the wine and reduce by half.","Return the shanks, add the stock to come most of the way up, cover and braise gently (oven at 160C or low on the hob) about 1.5 to 2 hours until fork-tender.","Make the gremolata by mixing the lemon zest, garlic and parsley.","Scatter the gremolata over the shanks, check the seasoning and serve with saffron risotto."],"pairing":"A structured Barolo or Barbaresco","tags":["Make-ahead","Comfort","Date night"],"vegetarian":false,"spicy":false,"calories":540,"protein":58,"carbs":12,"fat":26,"allergens":["Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"italian","type":"Mains"},{"id":"it-tagliatelle-ragu-bolognese","name":"Tagliatelle al Ragu Bolognese","cuisineKey":"italian","category":"Pasta","course":"Main","meal":"both","tier":"signature","inspiration":"Osteria Francescana (Massimo Bottura)","minutes":150,"serves":4,"level":"Weekend","idea":"The list has vodka and cacio e pepe but no slow ragu, the dish parents most want to batch-cook and freeze. Hazan's milk-and-wine method is the authoritative, forgiving reference.","ingredients":["400g fresh tagliatelle","400g beef mince","150g pancetta, finely diced","1 onion, finely diced","1 carrot, finely diced","1 celery stalk, finely diced","250ml whole milk","250ml white wine","400g tinned chopped tomatoes","2 tbsp olive oil","Grated nutmeg","Parmesan to serve","Salt and pepper to taste"],"steps":["Soften the onion, carrot and celery in the olive oil over medium heat until translucent, about 8 minutes. Add the pancetta and cook 3 minutes.","Add the beef and cook, breaking it up, until it loses its raw colour but does not brown hard.","Pour in the milk and a grating of nutmeg, simmer gently until the milk is absorbed.","Add the wine and simmer until evaporated, then stir in the tomatoes and a little salt.","Cook uncovered on the lowest possible heat for 2 hours, stirring occasionally, until rich and thick. Season.","Cook the tagliatelle, toss with the ragu and a splash of pasta water, and serve with Parmesan. Freezes and reheats beautifully."],"pairing":"A glass of Sangiovese","tags":["make-ahead","freezer-friendly","crowd-pleaser","batch-cook"],"vegetarian":false,"spicy":false,"calories":680,"protein":36,"carbs":62,"fat":30,"allergens":["Gluten","Milk","Sulphites"],"role":"main","type":"Pasta"},{"id":"it-bruschetta-pomodoro","name":"Bruschetta al Pomodoro","cuisineKey":"italian","category":"Secondi","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Grilled rustic bread rubbed with garlic and piled with marinated ripe tomatoes and basil.","ingredients":["8 slices rustic sourdough or ciabatta","400g ripe tomatoes, diced","1 garlic clove, halved, plus 1 clove minced","8 fresh basil leaves, torn","4 tbsp extra virgin olive oil","1 tsp red wine vinegar","salt and pepper"],"steps":["Toss the diced tomatoes with minced garlic, basil, 2 tbsp olive oil, the vinegar, salt and pepper. Let sit 10 minutes.","Grill or toast the bread until golden and crisp on both sides.","Rub each warm slice with the cut side of the halved garlic clove.","Spoon the marinated tomatoes over the bread, drizzle with the remaining olive oil and serve immediately."],"pairing":"A chilled glass of Vermentino or sparkling water with lemon","tags":["quick","classic"],"vegetarian":true,"spicy":false,"calories":230,"protein":6,"carbs":29,"fat":10,"allergens":["Gluten","Sulphites"],"type":"Starters"},{"id":"it-arancini-mozzarella","name":"Arancini di Riso","cuisineKey":"italian","category":"Risotto","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":50,"serves":4,"level":"Weekend","idea":"Crisp golden risotto balls with a molten mozzarella centre.","ingredients":["300g cooked risotto rice, cooled","60g Parmesan, grated","2 eggs, beaten","100g mozzarella, cut into small cubes","100g plain flour","150g fine dried breadcrumbs","sunflower oil for frying","salt and pepper"],"steps":["Mix the cooled risotto with the Parmesan, one beaten egg, salt and pepper.","Take a heaped spoonful, press a cube of mozzarella into the centre and shape into a ball, sealing the cheese inside.","Roll each ball in flour, then the remaining beaten egg, then the breadcrumbs.","Heat oil to 175C and fry the arancini in batches until deep golden and crisp, about 3 to 4 minutes.","Drain on kitchen paper, season lightly and serve hot."],"pairing":"A crisp Sicilian white such as Grillo","tags":["fried","sicilian"],"vegetarian":true,"spicy":false,"calories":420,"protein":15,"carbs":48,"fat":18,"allergens":["Gluten","Milk","Egg"],"type":"Starters"},{"id":"it-caponata-siciliana","name":"Caponata Siciliana","cuisineKey":"italian","category":"Secondi","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Sweet and sour Sicilian aubergine relish with celery, capers and olives, served on toasted bread.","ingredients":["2 aubergines, diced","1 onion, chopped","2 celery sticks, diced","200g tinned chopped tomatoes","2 tbsp capers, rinsed","60g green olives, pitted and chopped","2 tbsp red wine vinegar","1 tbsp sugar","4 tbsp olive oil","8 slices toasted bread to serve","salt and pepper"],"steps":["Fry the diced aubergine in olive oil over medium high heat until golden, then set aside.","In the same pan soften the onion and celery, then add the tomatoes, capers and olives.","Stir in the vinegar and sugar and simmer 5 minutes to make a sweet and sour base.","Return the aubergine, season and cook gently 10 minutes until thick. Cool to room temperature.","Pile onto toasted bread and serve."],"pairing":"A glass of dry Marsala or Nero d'Avola","tags":["sicilian","sweet-and-sour"],"vegetarian":true,"spicy":false,"calories":260,"protein":6,"carbs":32,"fat":13,"allergens":["Gluten","Sulphites"],"type":"Starters"},{"id":"it-insalata-caprese","name":"Insalata Caprese","cuisineKey":"italian","category":"Secondi","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":10,"serves":4,"level":"Weeknight","idea":"Layered fresh mozzarella, ripe tomatoes and basil dressed simply with olive oil.","ingredients":["400g buffalo mozzarella, sliced","500g ripe tomatoes, sliced","large handful fresh basil leaves","4 tbsp extra virgin olive oil","flaky sea salt","freshly ground black pepper"],"steps":["Arrange alternating slices of tomato and mozzarella on a platter.","Tuck basil leaves between the slices.","Drizzle generously with extra virgin olive oil.","Finish with flaky salt and black pepper and serve at room temperature."],"pairing":"A chilled glass of Fiano di Avellino","tags":["no-cook","classic"],"vegetarian":true,"spicy":false,"calories":290,"protein":16,"carbs":7,"fat":23,"allergens":["Milk"],"type":"Salads"},{"id":"it-panzanella","name":"Panzanella","cuisineKey":"italian","category":"Secondi","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Tuscan bread salad of toasted sourdough soaked in ripe tomato juices with cucumber, red onion and basil.","ingredients":["300g stale sourdough, torn into chunks","500g ripe tomatoes, cut into wedges","1 cucumber, diced","0.5 red onion, thinly sliced","large handful fresh basil leaves","4 tbsp extra virgin olive oil","2 tbsp red wine vinegar","salt and pepper"],"steps":["Toast the bread chunks until crisp and golden, then let cool.","Toss the tomatoes with a good pinch of salt and let them release their juices for 10 minutes.","Combine the bread, tomatoes and their juices, cucumber, red onion and basil.","Dress with olive oil and red wine vinegar, season and let stand 10 minutes so the bread softens slightly before serving."],"pairing":"A light Chianti served cool","tags":["tuscan","bread-salad"],"vegetarian":true,"spicy":false,"calories":280,"protein":7,"carbs":38,"fat":11,"allergens":["Gluten","Sulphites"],"type":"Salads"},{"id":"it-insalata-rucola-parmigiano","name":"Insalata di Rucola e Parmigiano","cuisineKey":"italian","category":"Secondi","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":10,"serves":4,"level":"Weeknight","idea":"Peppery rocket with shaved Parmesan, lemon and good olive oil.","ingredients":["120g rocket","60g Parmesan, shaved","3 tbsp extra virgin olive oil","juice of 0.5 lemon","30g pine nuts, lightly toasted","salt and pepper"],"steps":["Whisk the olive oil with the lemon juice, salt and pepper to make a light dressing.","Place the rocket in a bowl and toss gently with just enough dressing to coat.","Scatter over the shaved Parmesan and toasted pine nuts.","Add a final crack of pepper and serve immediately."],"pairing":"A glass of Gavi di Gavi","tags":["quick","no-cook"],"vegetarian":true,"spicy":false,"calories":210,"protein":8,"carbs":4,"fat":18,"allergens":["Milk","Tree nuts"],"type":"Salads"},{"id":"ja-salmon-teriyaki-donburi","name":"Salmon Teriyaki Donburi","category":"Sushi & Rice bowls","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"Pan-seared salmon lacquered in a four-ingredient teriyaki reduction over hot rice. The sauce caramelises around the fillet so the skin stays crisp while the flesh stays just-set and silky.","ingredients":["2 salmon fillets, skin on (about 150 g each)","300 g Japanese short-grain rice","360 ml water","4 tbsp soy sauce","3 tbsp mirin","2 tbsp sake","1 tbsp caster sugar","1 tsp neutral oil","2 spring onions, finely sliced","1 tsp toasted white sesame seeds"],"steps":["Rinse the rice until the water runs clear, drain, then cook with the 360 ml water (rice cooker or covered pan, 12 minutes plus 10 minutes steam off the heat).","Mix soy sauce, mirin, sake and sugar in a small bowl until the sugar dissolves.","Pat the salmon dry. Heat the oil in a non-stick pan over medium-high and sear skin-side down 3 to 4 minutes until crisp, then flip and cook 2 minutes more until the flesh is just opaque.","Pour in the teriyaki mix and let it bubble and reduce 2 to 3 minutes, spooning it over the fish until it turns glossy and thickly coats the fillets.","Divide rice between two bowls, top with salmon, spoon over the pan sauce, and finish with spring onion and sesame seeds."],"pairing":"An off-dry Riesling or a cold glass of Junmai sake.","tags":["Quick","Comfort","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":620,"protein":34,"carbs":72,"fat":20,"allergens":["Fish","Gluten","Soy","Sesame","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Rice & Bowls"},{"id":"ja-gyudon","name":"Gyudon (Simmered Beef Rice Bowl)","category":"Sushi & Rice bowls","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Thinly sliced beef and sweet onion simmered in a dashi-soy broth until meltingly tender, then piled on rice. Japan's ultimate fast comfort food, done properly at home in under half an hour.","ingredients":["300 g thinly sliced beef (ribeye or sirloin)","300 g Japanese short-grain rice","360 ml water for rice","1 large onion, thinly sliced","200 ml dashi stock","3 tbsp soy sauce","2 tbsp mirin","2 tbsp sake","1 tbsp caster sugar","2 egg yolks","2 spring onions, sliced","1 tsp pickled red ginger (beni shoga)"],"steps":["Rinse and cook the rice with the 360 ml water.","In a wide pan, bring dashi, soy sauce, mirin, sake and sugar to a simmer, add the onion and cook 4 to 5 minutes until soft.","Add the beef, separating the slices, and simmer gently 3 to 4 minutes just until no longer pink, skimming any foam.","Spoon the beef and onion with plenty of broth over bowls of rice.","Top each bowl with a raw egg yolk, sliced spring onion and a pinch of beni shoga."],"pairing":"A cold lager such as Asahi or Sapporo.","tags":["Quick","Comfort","Crowd-pleaser","One-pan"],"vegetarian":false,"spicy":false,"calories":680,"protein":35,"carbs":75,"fat":26,"allergens":["Fish","Gluten","Soy","Egg","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Rice & Bowls"},{"id":"ja-chicken-soboro-don","name":"Chicken Soboro Donburi","category":"Sushi & Rice bowls","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Two-tone rice bowl of savoury-sweet minced chicken alongside a fluffy ribbon of seasoned scrambled egg. A genuine Japanese home-cooking staple that is fast, cheap and a guaranteed hit with kids.","ingredients":["300 g chicken mince","300 g Japanese short-grain rice","360 ml water for rice","3 eggs","3 tbsp soy sauce","2 tbsp mirin","1 tbsp sake","1 tbsp caster sugar","10 g ginger, grated","1 tsp neutral oil","2 spring onions, sliced","1 tsp toasted white sesame seeds"],"steps":["Rinse and cook the rice with the 360 ml water.","Put the chicken mince in a cold pan with soy sauce, mirin, sake, sugar and ginger, then cook over medium heat, stirring to break up clumps, 5 to 6 minutes until the liquid has mostly cooked away.","Beat the eggs with a pinch of salt. Heat the oil in a second pan over low heat and scramble the egg slowly into soft small curds, then remove.","Divide rice between two bowls and spoon the chicken over one half and the egg over the other.","Finish with spring onion and sesame seeds."],"pairing":"Cold barley tea (mugicha) or a light lager.","tags":["Quick","Comfort","Crowd-pleaser","Lunchbox","Make-ahead"],"vegetarian":false,"spicy":false,"calories":640,"protein":38,"carbs":68,"fat":22,"allergens":["Egg","Gluten","Soy","Sesame","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Rice & Bowls"},{"id":"ja-tsujihan-kaisendon","name":"Tsujihan-Style Kaisen Don","category":"Sushi & Rice bowls","course":"Main","meal":"dinner","tier":"signature","inspiration":"Tsujihan (Tsukiji, Tokyo)","minutes":50,"serves":2,"level":"Weekend","idea":"A homage to the queue-out-the-door bowl that made Tsujihan famous: a mound of sashimi-grade fish and ikura over vinegared rice, eaten halfway, then transformed at the table when you pour hot sea bream dashi over the rest to finish it as a silky ochazuke.","ingredients":["300 g Japanese short-grain rice","360 ml water","3 tbsp rice vinegar","1 tbsp caster sugar","1 tsp fine salt","150 g sashimi-grade tuna, sliced","120 g sashimi-grade sea bream or sea bass, sliced","100 g sashimi-grade salmon, sliced","3 tbsp salmon roe (ikura)","400 ml dashi stock","1 tsp light soy sauce","2 sheets nori, shredded","1 tbsp grated wasabi","1 tbsp pickled ginger (gari)"],"steps":["Rinse and cook the rice with the water, then tip into a wide bowl.","Warm the rice vinegar, sugar and salt until dissolved, fold through the hot rice with a cutting motion, and fan to cool to body temperature.","Slice all the fish cleanly and evenly, reserving two slices of sea bream per person for the second course.","Pack the seasoned rice into two deep bowls and arrange the tuna, sea bream, salmon and a generous spoon of ikura on top, then scatter with shredded nori and add the wasabi and gari.","Eat the bowl roughly halfway, then warm the dashi with the light soy until just below a simmer.","Lay the reserved sea bream over the remaining rice, pour the hot dashi over the top to gently set the fish, and finish the bowl as ochazuke."],"pairing":"Chilled Junmai Daiginjo sake or hot hojicha to match the dashi finish.","tags":["Date night","Crowd-pleaser","Light"],"vegetarian":false,"spicy":false,"calories":540,"protein":40,"carbs":70,"fat":10,"allergens":["Fish","Soy","Gluten","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Rice & Bowls"},{"id":"ja-yaki-udon","name":"Chicken Yaki Udon","category":"Ramen & Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Thick, chewy udon stir-fried hard and fast with chicken and cabbage in a savoury-sweet soy and oyster sauce. A 20-minute wok dinner with proper smoky wok hei character.","ingredients":["400 g pre-cooked udon noodles","250 g chicken thigh, thinly sliced","200 g white cabbage, roughly chopped","1 carrot, julienned","2 spring onions, cut into batons","2 tbsp soy sauce","1 tbsp oyster sauce","1 tbsp mirin","1 tsp dashi powder","1 tbsp neutral oil","1 tbsp bonito flakes to finish","1 tsp pickled red ginger (beni shoga)"],"steps":["Loosen the udon under warm water and drain. Mix soy sauce, oyster sauce, mirin and dashi powder.","Heat the oil in a wok over high heat and stir-fry the chicken until lightly browned and cooked through.","Add cabbage and carrot and stir-fry 2 minutes until just wilted but still crisp.","Add the udon and the sauce, toss vigorously over high heat 2 minutes until everything is glossy and coated.","Toss through the spring onions, plate up, and finish with bonito flakes and a little beni shoga."],"pairing":"A cold highball (whisky and soda) or green tea.","tags":["Quick","Comfort","One-pan","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":560,"protein":32,"carbs":62,"fat":20,"allergens":["Gluten","Soy","Fish","Shellfish"],"role":"main","cuisineKey":"japanese","type":"Noodles & Ramen"},{"id":"ja-zaru-soba","name":"Zaru Soba with Dipping Sauce","category":"Ramen & Noodles","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Chilled buckwheat noodles served on a bamboo mat with an icy kombu-dashi and soy dipping sauce. Clean, nutty and refreshing, the dish Japan turns to on a hot day.","ingredients":["200 g dried soba noodles (check 100% buckwheat for gluten-free)","300 ml kombu dashi stock","4 tbsp soy sauce","3 tbsp mirin","1 sheet nori, finely shredded","2 spring onions, finely sliced","1 tbsp grated wasabi","1 tsp toasted white sesame seeds"],"steps":["Make the tsuyu: simmer the kombu dashi, soy sauce and mirin for 2 minutes, then chill thoroughly in the fridge or over ice.","Cook the soba in plenty of boiling water per packet, usually 4 to 5 minutes, stirring so they do not clump.","Drain and rinse the noodles under cold running water, rubbing gently to remove surface starch, then chill in iced water and drain well.","Mound the noodles on a bamboo mat or plate and scatter with shredded nori.","Serve the cold tsuyu in cups alongside the spring onion, wasabi and sesame, to stir in and dip each mouthful."],"pairing":"Cold soba-yu (the noodle cooking water) or a chilled dry sake.","tags":["Light","Quick","Make-ahead","Lunchbox"],"vegetarian":false,"spicy":false,"calories":420,"protein":17,"carbs":80,"fat":4,"allergens":["Gluten","Soy","Sesame","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Noodles & Ramen"},{"id":"ja-easy-chicken-shoyu-ramen","name":"Weeknight Chicken Shoyu Ramen","category":"Ramen & Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"A real soy-seasoned ramen built from supermarket chicken stock and a quick soy tare, topped with poached chicken and a jammy egg. All the slurpable comfort of a ramen shop with none of the all-day simmering.","ingredients":["1.2 litres chicken stock","2 chicken thigh fillets (about 250 g)","5 tbsp soy sauce","2 tbsp mirin","1 tbsp sake","1 tsp toasted sesame oil","2 garlic cloves, smashed","10 g ginger, sliced","2 portions fresh ramen noodles (about 240 g)","2 eggs","2 spring onions, sliced","1 sheet nori, halved","100 g sweetcorn"],"steps":["Soft-boil the eggs for 6.5 minutes, cool in cold water and peel.","Simmer the chicken stock with the garlic, ginger and chicken thighs for 12 minutes until the chicken is cooked, then lift out the chicken and slice it.","Make the tare by mixing soy sauce, mirin, sake and sesame oil, and divide between two warmed bowls.","Cook the noodles per packet, usually 90 seconds to 2 minutes, and drain well.","Ladle the hot strained stock over the tare, nest in the noodles, and top with sliced chicken, halved egg, sweetcorn, spring onion and nori."],"pairing":"An ice-cold Japanese lager or cold barley tea.","tags":["Comfort","Quick","Crowd-pleaser","One-pan"],"vegetarian":false,"spicy":false,"calories":600,"protein":38,"carbs":60,"fat":22,"allergens":["Gluten","Soy","Egg","Sesame","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Noodles & Ramen"},{"id":"ja-shoyu-ramen","name":"Ivan Ramen Shoyu","category":"Ramen & Noodles","course":"Main","meal":"dinner","tier":"signature","inspiration":"Ivan Ramen (Ivan Orkin)","minutes":120,"serves":2,"level":"Project","idea":"A homage to Ivan Orkin's double-soup shoyu: a clean chicken and dashi broth married to a rich, slow-toasted soy tare, springy noodles, chashu and a jammy marinated egg. The Tokyo benchmark every ramen lover chases.","ingredients":["1.2 litres chicken stock","10 g kombu","10 g bonito flakes (katsuobushi)","5 tbsp soy sauce","2 tbsp mirin","1 tbsp sake","1 tsp caster sugar","2 portions fresh ramen noodles (about 240 g)","2 eggs","150 g chashu pork or cooked sliced pork belly","2 spring onions, sliced","1 sheet nori, halved","50 g menma (bamboo shoots)"],"steps":["Soft-boil the eggs 6.5 minutes, cool in iced water, peel, and marinate in 2 tbsp of the soy sauce mixed with a splash of water for at least 30 minutes.","Warm the chicken stock with the kombu over low heat; just before it simmers remove the kombu, add bonito flakes, steep 2 minutes off the heat, then strain.","For the tare, gently warm the remaining soy sauce, mirin, sake and sugar until just below a simmer so the soy deepens and mellows, then divide between two warmed bowls.","Ladle the hot broth into each bowl over the tare and stir to combine.","Cook the noodles in boiling water per packet (usually 90 seconds to 2 minutes), drain well, and nest into the bowls.","Top with sliced chashu, halved marinated egg, menma, spring onion and nori, then serve immediately."],"pairing":"Cold barley tea (mugicha) or a crisp Japanese lager.","tags":["Comfort","Crowd-pleaser","Make-ahead"],"vegetarian":false,"spicy":false,"calories":680,"protein":36,"carbs":58,"fat":34,"allergens":["Gluten","Soy","Egg","Fish","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Noodles & Ramen"},{"id":"ja-chicken-yakitori","name":"Chicken Yakitori (Negima)","category":"Yakimono (grilled)","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weekend","idea":"Skewers of thigh and spring onion lacquered in a sticky tare that you build by repeated dipping and grilling. Charred, sweet and savoury, the heart of any izakaya night.","ingredients":["600 g boneless chicken thigh, skin on, cut into chunks","4 thick spring onions, cut into 3 cm batons","120 ml soy sauce","120 ml mirin","60 ml sake","2 tbsp caster sugar","1 spring onion white, smashed","12 bamboo skewers, soaked 30 minutes","1 tsp shichimi togarashi to serve"],"steps":["Make the tare: simmer soy sauce, mirin, sake, sugar and the smashed spring onion white until reduced by a third and lightly syrupy, about 8 minutes, then strain.","Thread chicken and spring onion batons alternately onto the soaked skewers.","Grill over high heat or a hot griddle, turning, for 4 to 5 minutes until the chicken is coloured and almost cooked.","Brush generously with tare and return to the heat; repeat the dip-and-grill twice more until lacquered and the chicken reads 74 C.","Serve hot with a dusting of shichimi togarashi."],"pairing":"Cold draft lager or a smoky highball.","tags":["Crowd-pleaser","Date night","Make-ahead"],"vegetarian":false,"spicy":false,"calories":380,"protein":30,"carbs":14,"fat":22,"allergens":["Soy","Gluten","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Grills & BBQ"},{"id":"ja-saba-shioyaki","name":"Saba Shioyaki (Salt-Grilled Mackerel)","category":"Yakimono (grilled)","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Mackerel salted to firm the flesh and draw out moisture, then grilled until the skin blisters and crackles. Pure, honest Japanese home cooking that lets the oily fish sing.","ingredients":["2 mackerel fillets, skin on (about 140 g each)","1.5 tsp fine sea salt","1 tbsp sake","150 g daikon radish, grated and lightly drained","1 lemon, cut into wedges","2 tbsp soy sauce","300 g steamed Japanese rice to serve"],"steps":["Pat the fillets dry, sprinkle evenly with salt on both sides, and rest 20 minutes; blot away the moisture that beads on the surface.","Brush off excess salt and rub the skin with the sake to help it crisp.","Heat the grill to high. Grill skin-side up first for 5 minutes, then flip and grill 3 to 4 minutes until the flesh flakes and the skin is blistered.","Mound the grated daikon alongside and add a lemon wedge.","Serve with hot rice and a small dish of soy sauce for the daikon."],"pairing":"A dry Junmai sake, served cool.","tags":["Quick","Light","Gluten-free option","Comfort"],"vegetarian":false,"spicy":false,"calories":520,"protein":30,"carbs":42,"fat":26,"allergens":["Fish","Soy","Gluten","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Grills & BBQ"},{"id":"ja-chicken-tsukune","name":"Chicken Tsukune Meatballs","category":"Yakimono (grilled)","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Juicy grilled chicken meatballs glazed in a glossy yakitori tare, with an optional egg-yolk dip the izakaya way. Easy to shape, forgiving to cook, and the kind of thing kids and adults both devour.","ingredients":["500 g chicken mince","2 spring onions, finely chopped","15 g ginger, grated","1 tbsp white miso","1 tbsp potato starch or cornflour","1 tsp toasted sesame oil","4 tbsp soy sauce","4 tbsp mirin","1 tbsp caster sugar","1 tbsp neutral oil","1 tsp toasted white sesame seeds"],"steps":["Mix the chicken mince with the spring onion, ginger, miso, potato starch and sesame oil until sticky, then shape into 16 small oval meatballs.","Warm the soy sauce, mirin and sugar in a small pan until lightly syrupy to make the tare.","Heat the neutral oil in a non-stick pan over medium and cook the meatballs 6 to 8 minutes, turning, until browned and cooked through.","Pour in the tare and turn the meatballs to coat, letting it bubble and glaze for a minute.","Plate up, spoon over the pan glaze, and finish with sesame seeds."],"pairing":"Cold lager or a dry highball.","tags":["Quick","Crowd-pleaser","Comfort","Lunchbox","Make-ahead"],"vegetarian":false,"spicy":false,"calories":300,"protein":24,"carbs":12,"fat":17,"allergens":["Soy","Gluten","Sesame","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Grills & BBQ"},{"id":"ja-nobu-miso-black-cod","name":"Miso-Marinated Black Cod (Saikyo Yaki)","category":"Yakimono (grilled)","course":"Main","meal":"dinner","tier":"signature","inspiration":"Nobu / Matsuhisa (Nobu Matsuhisa)","minutes":30,"serves":2,"level":"Project","idea":"Nobu's most iconic plate: black cod steeped for days in a sweet white-miso marinade, then grilled until the surface caramelises and the flesh turns to silk. Simple to cook, but the long marinade makes it unforgettable.","ingredients":["2 black cod fillets (about 150 g each), or use sablefish","120 g white (saikyo) miso","3 tbsp mirin","3 tbsp sake","2 tbsp caster sugar","2 pieces pickled ginger stem (hajikami), optional","200 g steamed Japanese rice to serve"],"steps":["Bring the sake and mirin to a gentle simmer to cook off the alcohol, then whisk in the miso and sugar over low heat until smooth, and cool completely.","Pat the cod dry, coat all over in the cooled miso marinade, and refrigerate in a sealed dish for 2 to 3 days for the true effect (a minimum of 24 hours will work).","Wipe most of the marinade off the fillets so they do not scorch.","Heat the grill to medium-high and grill the cod 7 to 10 minutes, watching closely, until deeply caramelised on top and just flaking through.","Serve with a piece of hajikami and steamed rice alongside."],"pairing":"Chilled Junmai Daiginjo sake or a lightly oaked Chardonnay.","tags":["Date night","Make-ahead","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":480,"protein":30,"carbs":48,"fat":15,"allergens":["Fish","Soy","Sulphites"],"role":"main","cuisineKey":"japanese","type":"Grills & BBQ"},{"id":"ja-agedashi-tofu","name":"Agedashi Tofu","category":"Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Silken tofu dusted in potato starch and fried until crisp-shelled and custardy within, sitting in a warm kombu and shiitake dashi. A delicate, restaurant-favourite small plate that comes together fast.","ingredients":["300 g silken tofu","4 tbsp potato starch (katakuriko)","200 ml kombu and shiitake dashi stock","2 tbsp soy sauce","2 tbsp mirin","50 g daikon radish, grated and drained","10 g ginger, grated","2 spring onions, finely sliced","500 ml neutral oil for frying"],"steps":["Drain the tofu on kitchen paper for 15 minutes, then cut into large cubes and pat dry.","Warm the kombu and shiitake dashi, soy sauce and mirin together to make the broth and keep hot.","Coat the tofu cubes all over in potato starch, brushing off the excess.","Heat the oil to 180 C and fry the tofu 3 to 4 minutes until the coating is crisp and pale gold; drain on a rack.","Sit the tofu in shallow bowls, pour the warm broth around it, and top with grated daikon, ginger and spring onion."],"pairing":"Warm or room-temperature Junmai sake.","tags":["Vegetarian","Quick","Light","Comfort"],"vegetarian":true,"spicy":false,"calories":280,"protein":10,"carbs":22,"fat":17,"allergens":["Soy","Gluten","Fish","Sulphites"],"role":"appetizer","cuisineKey":"japanese","type":"Starters"},{"id":"ja-prawn-gyoza","name":"Prawn and Cabbage Gyoza","category":"Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weekend","idea":"Pan-fried dumplings with a sweet, juicy prawn and cabbage filling, crisp lace-bottomed and steam-finished. The izakaya staple everyone reaches for, with a sharp soy-vinegar dip.","ingredients":["30 gyoza wrappers","300 g raw prawns, peeled and roughly chopped","200 g Chinese cabbage, finely chopped","2 cloves garlic, grated","15 g ginger, grated","2 spring onions, finely chopped","1 tbsp soy sauce","1 tbsp sesame oil","1 tsp caster sugar","2 tbsp neutral oil for frying","3 tbsp rice vinegar and 3 tbsp soy sauce for dipping","1 tsp chilli oil (rayu) to serve"],"steps":["Salt the cabbage lightly, rest 10 minutes, then squeeze out as much water as possible.","Mix the prawns, cabbage, garlic, ginger, spring onion, soy sauce, sesame oil and sugar until sticky and well combined.","Place a teaspoon of filling on each wrapper, wet the edge, and pleat to seal into a crescent.","Heat the oil in a non-stick pan, arrange the gyoza flat-side down, and fry 2 minutes until the bases are golden.","Add 80 ml water, cover immediately, and steam 5 minutes until the water evaporates and the prawn is cooked through; uncover and crisp the bases another minute.","Serve crisp-side up with a dip of rice vinegar, soy sauce and a few drops of rayu."],"pairing":"Ice-cold lager or a dry sparkling sake.","tags":["Crowd-pleaser","Make-ahead","Date night"],"vegetarian":false,"spicy":false,"calories":290,"protein":17,"carbs":30,"fat":11,"allergens":["Gluten","Shellfish","Soy","Sesame"],"role":"appetizer","cuisineKey":"japanese","type":"Starters"},{"id":"ja-tamagoyaki","name":"Tamagoyaki (Rolled Omelette)","category":"Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"The sweet-savoury rolled egg omelette built layer by layer into a tender, golden log. A breakfast and bento mainstay that is endlessly comforting and ready in minutes.","ingredients":["4 eggs","3 tbsp dashi stock","1 tbsp mirin","1 tbsp soy sauce","1 tsp caster sugar","1 tbsp neutral oil","50 g daikon radish, grated to serve","1 tsp soy sauce to serve"],"steps":["Beat the eggs with the dashi, mirin, soy sauce and sugar until just combined, avoiding too many bubbles.","Heat a non-stick pan over medium-low and wipe with a little oil on kitchen paper.","Pour in a thin layer of egg, and once just set, roll it to one side of the pan with a spatula.","Oil the pan again, pour in another thin layer letting it run under the roll, set, then roll back over the new layer; repeat until all the egg is used.","Tip out, shape gently, cool a minute, then slice into thick pieces and serve with grated daikon and a drop of soy."],"pairing":"Green tea or a light Junmai sake.","tags":["Vegetarian","Quick","Lunchbox","Comfort"],"vegetarian":true,"spicy":false,"calories":210,"protein":13,"carbs":6,"fat":14,"allergens":["Egg","Fish","Soy","Gluten","Sulphites"],"role":"appetizer","cuisineKey":"japanese","type":"Starters"},{"id":"ja-vegetable-miso-soup","name":"Root Vegetable and Tofu Miso Soup","category":"Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A hearty everyday miso soup loaded with sweet root vegetables and tofu, simmered in dashi and finished with miso off the boil. The home-cooked bowl that turns a simple meal into a warming one.","ingredients":["800 ml dashi stock","100 g daikon radish, quartered and sliced","1 carrot, sliced into half-moons","1 small potato, cubed","100 g shiitake mushrooms, sliced","150 g firm tofu, cubed","4 tbsp miso paste","1 tsp toasted sesame oil","2 spring onions, sliced","shichimi togarashi to serve"],"steps":["Heat the sesame oil in a pot and stir-fry the daikon, carrot, potato and shiitake for a minute until glossy.","Pour in the dashi, bring to a simmer, and cook gently 12 to 15 minutes, skimming any foam, until the vegetables are tender.","Add the tofu, then turn the heat to low and whisk in the miso through a ladle until dissolved; do not let it boil.","Ladle into bowls and finish with spring onion and a pinch of shichimi togarashi."],"pairing":"Hot green tea or a warm Junmai sake.","tags":["Vegetarian","Comfort","Quick","One-pan","Make-ahead"],"vegetarian":true,"spicy":false,"calories":140,"protein":8,"carbs":12,"fat":7,"allergens":["Soy","Fish","Sesame"],"role":"appetizer","cuisineKey":"japanese","type":"Starters"},{"id":"ja-kikunoi-chawanmushi","name":"Dashi Chawanmushi with Prawn and Ginkgo","category":"Small plates","course":"Starter","meal":"dinner","tier":"signature","inspiration":"Kikunoi (Yoshihiro Murata)","minutes":45,"serves":2,"level":"Weekend","idea":"A homage to the kaiseki dashi mastery Yoshihiro Murata is known for: a barely-set savoury egg custard built on a clean ichiban dashi, trembling and silken, hiding prawn, chicken and ginkgo beneath a glossy surface. The dish that proves restraint is the hardest technique of all.","ingredients":["3 eggs","450 ml ichiban dashi (kombu and bonito), cooled","1 tbsp light soy sauce (usukuchi)","1 tbsp mirin","0.5 tsp fine salt","4 raw prawns, peeled","60 g chicken thigh, diced small","8 ginkgo nuts or edamame, peeled","4 slices kamaboko fish cake","mitsuba or a few coriander leaves to finish","yuzu zest to finish"],"steps":["Make a clean ichiban dashi by steeping kombu in water warmed to just below a simmer, removing it, adding bonito flakes off the heat for 2 minutes, then straining and cooling.","Beat the eggs gently without frothing, then stir in the cooled dashi, light soy, mirin and salt and pass the mixture through a fine sieve for a smooth set.","Divide the prawn, chicken, ginkgo and kamaboko between two heatproof cups and pour the strained custard over, skimming off any surface bubbles.","Cover each cup with foil and steam over low heat 12 to 15 minutes, keeping the steam gentle, until just set with a soft wobble in the centre.","Finish with mitsuba and a fine grating of yuzu zest, and serve warm with a spoon."],"pairing":"Warm Junmai sake or a delicate green sencha.","tags":["Date night","Light","Make-ahead"],"vegetarian":false,"spicy":false,"calories":180,"protein":16,"carbs":5,"fat":10,"allergens":["Egg","Fish","Shellfish","Soy","Gluten","Sulphites"],"role":"appetizer","cuisineKey":"japanese","type":"Starters"},{"id":"ja-oyakodon","name":"Oyakodon (Chicken and Egg Rice Bowl)","cuisineKey":"japanese","category":"Sushi & Rice bowls","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"A genuine Japanese home staple: one pan, four pantry seasonings, deeply kid-friendly and mild. Faster and more approachable than the 2-hour shoyu ramen anchoring the category.","ingredients":["400g boneless chicken thigh, sliced","4 eggs, lightly beaten","1 onion, thinly sliced","200ml dashi","3 tbsp soy sauce","2 tbsp mirin","1 tbsp sugar","4 portions cooked Japanese short-grain rice","2 spring onions, sliced"],"steps":["In a wide pan combine the dashi, soy, mirin and sugar and bring to a simmer.","Add the onion and simmer 3 minutes until soft.","Add the chicken and cook 5-6 minutes until just cooked through.","Pour the beaten eggs over the surface in a swirl, cover and cook 1-2 minutes until just set but still soft.","Slide each portion over a bowl of hot rice.","Scatter with spring onion and serve immediately."],"pairing":"Miso soup and quick-pickled cucumber","tags":["kid-friendly","quick","one-pan"],"vegetarian":false,"spicy":false,"calories":520,"protein":32,"carbs":62,"fat":15,"allergens":["Egg","Fish","Soy","Gluten","Sulphites"],"role":"main","type":"Rice & Bowls"},{"id":"ja-unagi-don-signature","name":"Charcoal Unagi Don with Sansho","cuisineKey":"japanese","category":"Sushi & Rice bowls","role":"main","course":"Main","meal":"lunch","tier":"signature","inspiration":"Den (Zaiyu Hasegawa)","minutes":45,"serves":2,"level":"Weekend","idea":"Glazed grilled eel over rice with a lacquered tare and a lift of sansho pepper, a refined lunch bowl in the spirit of Den.","ingredients":["2 ready-grilled unagi (eel) fillets, about 130 g each","300 g Japanese short-grain rice","360 ml water","6 tbsp soy sauce","6 tbsp mirin","3 tbsp sake","2 tbsp caster sugar","1 tsp ground sansho pepper","1 sheet nori, finely shredded","2 tbsp pickled ginger (gari)"],"steps":["Rinse and cook the rice with the water until fluffy, then rest covered for 10 minutes.","Simmer soy sauce, mirin, sake and sugar in a small pan until glossy and slightly thickened to make the tare.","Brush the unagi fillets with tare and grill or blast under a hot grill for 4 to 5 minutes until lacquered and hot through.","Divide the rice between bowls and spoon over a little tare.","Lay the glazed unagi on top, brush again with tare, dust with sansho and finish with shredded nori and pickled ginger."],"pairing":"Cold barley tea or a crisp dry sake","tags":["eel","rice bowl","grilled","lunch"],"vegetarian":false,"spicy":false,"calories":640,"protein":34,"carbs":78,"fat":20,"allergens":["Gluten","Fish","Soy"],"type":"Rice & Bowls"},{"id":"ja-katsudon-easy","name":"Pork Katsudon","cuisineKey":"japanese","category":"Sushi & Rice bowls","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":2,"level":"Weeknight","idea":"Crisp panko pork cutlet simmered with onion and silky egg over rice, the ultimate comfort donburi.","ingredients":["2 boneless pork loin steaks, about 150 g each","60 g plain flour","1 egg, beaten, for coating","100 g panko breadcrumbs","500 ml neutral oil for frying","300 g Japanese short-grain rice","360 ml water for rice","1 onion, thinly sliced","200 ml dashi stock","3 tbsp soy sauce","2 tbsp mirin","1 tbsp caster sugar","4 eggs, lightly beaten","2 spring onions, sliced"],"steps":["Cook the rice with the water and keep warm.","Coat the pork in flour, then beaten egg, then panko, and deep-fry at 175C for 5 to 6 minutes until golden. Drain and slice into strips.","Simmer onion in dashi, soy sauce, mirin and sugar for 4 minutes until soft.","Lay the sliced cutlet over the onion, pour the beaten eggs around it and cover until just set.","Slide each portion onto a bowl of rice and finish with spring onions."],"pairing":"Green tea or a light lager","tags":["pork","katsu","rice bowl","comfort"],"vegetarian":false,"spicy":false,"calories":760,"protein":38,"carbs":82,"fat":30,"allergens":["Gluten","Egg","Soy"],"type":"Rice & Bowls"},{"id":"ja-tonkotsu-style-ramen","name":"Quick Miso Tonkotsu-Style Ramen","cuisineKey":"japanese","category":"Ramen & Noodles","role":"main","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":40,"serves":2,"level":"Weeknight","idea":"A rich, creamy miso broth with chashu-style pork and soft egg for a hearty bowl on a cold night.","ingredients":["1.2 litres chicken stock","200 ml whole milk","3 tbsp white miso","1 tbsp tahini or sesame paste","2 garlic cloves, grated","10 g ginger, grated","1 tbsp soy sauce","1 tsp toasted sesame oil","200 g cooked sliced pork belly","2 portions fresh ramen noodles, about 240 g","2 eggs","2 spring onions, sliced","50 g sweetcorn","100 g beansprouts"],"steps":["Soft-boil the eggs for 6.5 minutes, cool in iced water and peel.","Warm the stock with garlic and ginger, then whisk in milk, miso, tahini, soy sauce and sesame oil and keep below a simmer.","Crisp the pork belly slices in a dry pan for 2 minutes each side.","Cook the ramen noodles to packet timing and divide between deep bowls.","Pour over the broth, top with pork, halved eggs, sweetcorn, beansprouts and spring onions."],"pairing":"Cold beer or sparkling water with yuzu","tags":["ramen","miso","pork","dinner"],"vegetarian":false,"spicy":false,"calories":720,"protein":40,"carbs":68,"fat":32,"allergens":["Gluten","Milk","Egg","Soy","Sesame"],"type":"Noodles & Ramen"},{"id":"ja-nobu-tiradito","name":"Sea Bass Tiradito with Yuzu and Aji","cuisineKey":"japanese","category":"Small plates","role":"appetizer","course":"Starter","meal":"both","tier":"signature","inspiration":"Nobu / Matsuhisa (Nobu Matsuhisa)","minutes":20,"serves":2,"level":"Weekend","idea":"Paper-thin sashimi of sea bass dressed in a sharp yuzu and aji amarillo sauce, the signature Nobu-Peruvian plate.","ingredients":["200 g sashimi-grade sea bass, very thinly sliced","3 tbsp yuzu juice or lime juice","1 tbsp light soy sauce","1 tsp aji amarillo paste","1 tsp grated ginger","1 small garlic clove, grated","1 tbsp coriander, finely chopped","1 mild red chilli, finely sliced","1 tsp toasted white sesame seeds","flaky sea salt"],"steps":["Lay the sliced sea bass in a single overlapping layer on a chilled plate.","Whisk yuzu juice, soy sauce, aji amarillo, ginger and garlic into a smooth dressing.","Spoon the dressing evenly over the fish just before serving.","Scatter with coriander, sliced chilli, sesame seeds and a few flakes of sea salt."],"pairing":"Chilled junmai sake or a dry Riesling","tags":["sashimi","ceviche","fish","starter"],"vegetarian":false,"spicy":true,"calories":160,"protein":22,"carbs":4,"fat":6,"allergens":["Fish","Soy","Sesame"],"type":"Starters"},{"id":"ja-edamame-garlic","name":"Charred Garlic Edamame","cuisineKey":"japanese","category":"Small plates","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":12,"serves":2,"level":"Weeknight","idea":"Blistered edamame pods tossed in garlic, sesame oil and flaky salt, the easiest izakaya starter.","ingredients":["300 g frozen edamame in the pod","1 tbsp toasted sesame oil","3 garlic cloves, thinly sliced","1 tsp flaky sea salt","0.5 tsp shichimi togarashi","1 tsp toasted white sesame seeds"],"steps":["Boil the edamame for 4 minutes, then drain well.","Heat the sesame oil and gently fry the garlic until just golden.","Add the edamame and toss over high heat for 2 minutes until lightly blistered.","Tip into a bowl and toss with salt, shichimi and sesame seeds. Serve hot, squeezing the beans from the pods."],"pairing":"Cold beer or iced green tea","tags":["edamame","izakaya","starter"],"vegetarian":true,"spicy":true,"calories":190,"protein":13,"carbs":12,"fat":10,"allergens":["Soy","Sesame"],"type":"Starters"},{"id":"ja-jiro-tamago-nigiri","name":"Tamago Nigiri, Jiro Style","cuisineKey":"japanese","category":"Sushi & Rice bowls","role":"appetizer","course":"Starter","meal":"both","tier":"signature","inspiration":"Sukiyabashi Jiro (Jiro Ono)","minutes":40,"serves":2,"level":"Project","idea":"A dense, cake-like sweet tamago set on vinegared rice and bound with nori, the famous closing piece at Jiro.","ingredients":["4 eggs","2 raw prawns, peeled and pureed","20 g grated yamaimo or 1 tsp cornflour","1 tbsp caster sugar","1 tsp mirin","0.5 tsp light soy sauce","pinch of salt","1 tbsp neutral oil","200 g cooked Japanese short-grain rice","1.5 tbsp rice vinegar","1 tsp sugar for the rice","0.5 tsp salt for the rice","1 sheet nori, cut into strips"],"steps":["Season the warm rice with rice vinegar, sugar and salt and cool to body temperature.","Blend the eggs, prawn puree, yamaimo, sugar, mirin, soy sauce and salt until smooth.","Pour into an oiled square pan over low heat and cook slowly, covered, for 20 to 25 minutes until set and cake-like, then cool and cut into thick slabs.","Press small ovals of rice and lay a slab of tamago on each.","Wrap a band of nori around the middle to hold each piece together."],"pairing":"Hot hojicha or a delicate sake","tags":["sushi","tamago","nigiri","starter"],"vegetarian":false,"spicy":false,"calories":300,"protein":16,"carbs":34,"fat":11,"allergens":["Egg","Shellfish","Soy"],"type":"Starters"},{"id":"ja-sunomono-salad","name":"Cucumber and Wakame Sunomono","cuisineKey":"japanese","category":"Small plates","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"Cool ribbons of cucumber and wakame in a bright sweet-sour rice vinegar dressing, the classic Japanese salad.","ingredients":["2 cucumbers, very thinly sliced","10 g dried wakame seaweed","4 tbsp rice vinegar","1 tbsp caster sugar","1 tbsp light soy sauce","0.5 tsp salt","1 tsp toasted white sesame seeds","10 g ginger, finely julienned"],"steps":["Toss the cucumber slices with the salt and leave for 10 minutes, then squeeze out the excess water.","Soak the wakame in cold water for 5 minutes until soft, then drain well.","Whisk the rice vinegar, sugar and soy sauce until the sugar dissolves.","Toss the cucumber, wakame and ginger in the dressing and chill briefly.","Finish with toasted sesame seeds before serving."],"pairing":"Cold green tea or a light lager","tags":["salad","cucumber","seaweed"],"vegetarian":true,"spicy":false,"calories":80,"protein":3,"carbs":14,"fat":2,"allergens":["Soy","Sesame"],"type":"Salads"},{"id":"ja-goma-spinach-salad","name":"Spinach Gomaae with Sesame Dressing","cuisineKey":"japanese","category":"Small plates","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"Blanched spinach dressed in a nutty toasted-sesame paste, a deeply savoury little salad.","ingredients":["300 g spinach","3 tbsp toasted white sesame seeds","1 tbsp soy sauce","1 tbsp mirin","1 tsp caster sugar","1 tsp dashi stock or water"],"steps":["Blanch the spinach for 30 seconds, refresh in iced water, then squeeze out all the water and cut into bite lengths.","Toast the sesame seeds until fragrant and grind two thirds to a coarse paste in a mortar.","Stir the soy sauce, mirin, sugar and dashi into the sesame paste to make a thick dressing.","Toss the spinach through the dressing and pile into bowls.","Scatter with the reserved whole sesame seeds."],"pairing":"Steamed rice and miso soup, or green tea","tags":["salad","spinach","sesame"],"vegetarian":true,"spicy":false,"calories":140,"protein":7,"carbs":9,"fat":9,"allergens":["Soy","Sesame"],"type":"Salads"},{"id":"ja-kani-avocado-salad","name":"Crab and Avocado Salad with Wasabi Mayo","cuisineKey":"japanese","category":"Small plates","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"Creamy crab and avocado over crisp leaves with a wasabi-spiked Japanese mayo, an izakaya-style salad.","ingredients":["150 g white crab meat or seafood sticks, flaked","1 ripe avocado, diced","80 g mixed salad leaves","2 tbsp Japanese (Kewpie) mayonnaise","0.5 tsp wasabi paste","1 tsp light soy sauce","1 tsp rice vinegar","1 spring onion, sliced","1 tsp toasted white sesame seeds","1 sheet nori, finely shredded"],"steps":["Whisk the mayonnaise, wasabi, soy sauce and rice vinegar into a smooth dressing.","Gently fold the crab and most of the dressing together.","Arrange the salad leaves and avocado on plates.","Spoon the dressed crab over the top and drizzle with the remaining dressing.","Finish with spring onion, sesame seeds and shredded nori."],"pairing":"Chilled sake or sparkling water with lime","tags":["salad","crab","avocado","seafood"],"vegetarian":false,"spicy":true,"calories":260,"protein":14,"carbs":8,"fat":19,"allergens":["Fish","Shellfish","Egg","Soy","Sesame","Mustard"],"type":"Salads"},{"id":"am-classic-smash-burger","name":"Classic Smash Burger","category":"Burgers","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Loose balls of fatty beef smashed hard onto a screaming-hot pan so the edges fry into lacy, crisp brown lace. The deep Maillard crust is the whole reward, so reach for 20 percent fat mince and never lean.","ingredients":["600 g beef mince, 20% fat","8 slices American cheese","4 soft brioche burger buns","1 large white onion, very thinly sliced","2 tbsp neutral oil","Salt and freshly ground black pepper","4 tbsp mayonnaise","2 tbsp yellow mustard","8 dill pickle slices"],"steps":["Divide the mince into 8 loose 75 g balls without compacting them. Do not season yet.","Heat a heavy cast-iron pan over high heat until smoking, then add the oil.","Smash each ball flat with a stiff spatula for 10 seconds until very thin, working in batches. Season the tops with salt and pepper.","Scatter a little onion onto each patty and press in lightly. After about 2 minutes the edges will be deeply browned and lacy.","Flip, top each with cheese, and cook 1 minute more until melted and cooked through to 71 C.","Stack two patties per bun. Spread the buns with mayonnaise mixed with mustard, add pickles, and serve at once."],"pairing":"An ice-cold lager or a chocolate malt shake","tags":["Quick","Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":false,"calories":680,"protein":36,"carbs":34,"fat":44,"allergens":["Gluten","Milk","Egg","Mustard"],"role":"main","cuisineKey":"american","type":"Burgers"},{"id":"am-bacon-cheeseburger","name":"Bacon Cheeseburger","category":"Burgers","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"A thick, juicy pub-style burger layered with smoky streaky bacon and sharp aged cheddar. Pressing a shallow dimple into each patty stops it ballooning so it grills flat and even.","ingredients":["700 g beef mince, 20% fat","8 rashers smoked streaky bacon","4 slices mature cheddar","4 sesame burger buns","1 beef tomato, sliced","4 crisp lettuce leaves","2 tbsp neutral oil","Salt and freshly ground black pepper","4 tbsp burger sauce, or ketchup and mayonnaise"],"steps":["Fry the bacon in a dry pan over medium heat until crisp, then drain on kitchen paper, leaving the fat in the pan.","Gently form the mince into 4 patties slightly wider than the buns, pressing a shallow dimple in the centre of each. Season both sides well.","Heat the oil in a fresh pan over high heat and cook the patties 3 to 4 minutes on the first side until well crusted.","Flip, lay cheddar on each, and cook a further 3 minutes for medium, to 71 C.","Toast the cut buns in the reserved bacon fat until golden.","Build with sauce on the base, lettuce, tomato, the patty, then two bacon rashers crossed on top. Rest 1 minute and serve."],"pairing":"A hoppy IPA or a smoky bourbon on the rocks","tags":["Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":false,"calories":720,"protein":42,"carbs":33,"fat":46,"allergens":["Gluten","Milk","Egg","Sesame"],"role":"main","cuisineKey":"american","type":"Burgers"},{"id":"am-turkey-burger","name":"Juicy Turkey Burger","category":"Burgers","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A lighter weeknight burger that stays moist thanks to grated onion and a spoon of mayonnaise worked into the mince. Lean turkey dries out fast, so the hidden moisture and a quick sear are what save it.","ingredients":["600 g turkey mince","1 small onion, coarsely grated","2 tbsp mayonnaise","1 garlic clove, minced","1 tsp dried oregano","4 slices Swiss or Monterey Jack cheese","4 soft burger buns","1 tbsp neutral oil","Salt and freshly ground black pepper","4 lettuce leaves and tomato slices, to serve"],"steps":["Mix the turkey with the grated onion, mayonnaise, garlic, oregano, salt and pepper until just combined.","Shape into 4 patties slightly wider than the buns and chill 5 minutes to firm up.","Heat the oil in a pan over medium-high and cook the patties 4 to 5 minutes per side until cooked through to 74 C.","Top each with cheese in the last minute and cover the pan to melt.","Toast the buns, then build with lettuce, tomato and the patty.","Serve hot with extra mayonnaise or mustard."],"pairing":"A crisp green salad and sparkling water with lime","tags":["Quick","Light","Comfort"],"vegetarian":false,"spicy":false,"calories":520,"protein":40,"carbs":32,"fat":25,"allergens":["Gluten","Milk","Egg"],"role":"main","cuisineKey":"american","type":"Burgers"},{"id":"am-black-bean-burger","name":"Black Bean Veggie Burger","category":"Burgers","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"A hearty meat-free patty of mashed black beans, breadcrumbs and smoky spice that holds together and crisps in the pan. Drying the beans well is the trick to a patty that sears instead of crumbling.","ingredients":["2 x 400 g tins black beans, drained","80 g breadcrumbs","1 small onion, finely diced","1 egg, beaten","2 tsp ground cumin","1 tsp smoked paprika","1 tbsp tomato puree","4 burger buns","2 tbsp neutral oil","Salt and pepper, lettuce and sliced avocado to serve"],"steps":["Pat the beans dry on a tray, then mash about three quarters of them, leaving some whole for texture.","Mix in the breadcrumbs, onion, egg, cumin, paprika, tomato puree, salt and pepper until it holds together.","Shape into 4 firm patties and chill 10 minutes.","Heat the oil in a pan over medium and cook the patties 4 to 5 minutes per side until crisp and heated through.","Toast the buns while the patties finish.","Build with lettuce, avocado and the patty, adding mayonnaise or salsa to taste."],"pairing":"Sweet potato fries and an amber ale","tags":["Vegetarian","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":440,"protein":17,"carbs":62,"fat":13,"allergens":["Gluten","Egg"],"role":"main","cuisineKey":"american","type":"Burgers"},{"id":"am-shake-shack-burger","name":"ShackBurger-Style Griddle Burger","category":"Burgers","course":"Main","meal":"both","tier":"signature","inspiration":"Shake Shack (Danny Meyer)","minutes":35,"serves":4,"level":"Weekend","idea":"A homage to Danny Meyer's ShackBurger: a thin, deeply seared beef patty on a buttered, griddle-toasted potato bun with American cheese, crisp lettuce, tomato and the cult ShackSauce. Restraint is the point, every element dialled for balance rather than size.","ingredients":["600 g beef mince, 20% fat, in 4 loose balls","4 slices American cheese","4 soft potato buns","4 green-leaf lettuce leaves","4 thin plum tomato slices","30 g butter, softened","For the sauce: 120 g mayonnaise, 1 tbsp ketchup, 1 tbsp yellow mustard, 1 tbsp finely chopped pickle, 0.25 tsp each garlic powder, smoked paprika and cayenne","Salt and pepper"],"steps":["Whisk all the sauce ingredients together and chill so the flavours meld.","Butter the cut sides of the buns and toast face-down on a griddle until deep gold, then set aside.","Heat a heavy flat pan or griddle until very hot. Smash each ball into a thin patty, season, and sear 2 to 3 minutes until a dark crust forms.","Flip, top with American cheese and cook 1 minute more to 71 C as the cheese melts.","Spread sauce on both bun halves, lay lettuce and a tomato slice on the base.","Add the cheesy patty, close, and serve straight away with fries."],"pairing":"A frozen custard shake or a craft lager","tags":["Crowd-pleaser","Comfort","Date night"],"vegetarian":false,"spicy":false,"calories":700,"protein":34,"carbs":35,"fat":47,"allergens":["Gluten","Milk","Egg","Mustard"],"role":"main","cuisineKey":"american","type":"Burgers"},{"id":"am-bbq-glazed-meatballs","name":"BBQ Glazed Meatballs","category":"BBQ & Grill","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Tender beef meatballs baked fast and tossed in a sticky barbecue glaze, the cookout-and-potluck staple that comes together in one tray. A milk-soaked breadcrumb binder keeps them soft while the high oven heat sets a savoury crust for the sauce to cling to.","ingredients":["700 g beef mince","50 g breadcrumbs","4 tbsp whole milk","1 egg, beaten","1 small onion, finely grated","1 tsp garlic powder","1 tsp smoked paprika","250 ml barbecue sauce","1 tbsp honey","Salt and freshly ground black pepper"],"steps":["Heat the oven to 220 C and line a baking tray. Soak the breadcrumbs in the milk for 5 minutes.","Mix the mince with the soaked breadcrumbs, egg, onion, garlic powder, paprika, salt and pepper until just combined.","Roll into 20 even balls and space them out on the tray.","Bake 12 to 14 minutes until browned and cooked through to 71 C.","Warm the barbecue sauce with the honey in a wide pan, add the meatballs and toss to coat in the sticky glaze.","Serve over rice or with cocktail sticks as sliders, scattered with extra sauce."],"pairing":"Buttered rice and a cold lager","tags":["Quick","Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":false,"calories":520,"protein":38,"carbs":38,"fat":24,"allergens":["Gluten","Milk","Egg"],"role":"main","cuisineKey":"american","type":"Grills & BBQ"},{"id":"am-grilled-bbq-chicken","name":"Grilled BBQ Chicken","category":"BBQ & Grill","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Bone-in thighs and drumsticks grilled over moderate heat, then mopped with sauce only at the very end so the sugars char rather than scorch. A quick dry-salt keeps the meat juicy through the fire.","ingredients":["8 bone-in, skin-on chicken thighs and drumsticks, about 1.2 kg","1 tbsp sea salt","2 tsp smoked paprika","1 tsp garlic powder","1 tsp ground black pepper","2 tbsp neutral oil","200 ml barbecue sauce","1 tbsp cider vinegar","1 tsp hot sauce"],"steps":["Pat the chicken dry and toss with the salt, paprika, garlic powder, pepper and oil. Leave 20 minutes at room temperature.","Heat a barbecue or griddle to medium. Place the chicken skin-side down and grill 6 to 7 minutes until well marked.","Turn and continue cooking over moderate heat, turning occasionally, for about 20 minutes.","Stir the vinegar and hot sauce into the barbecue sauce.","When the chicken reaches 75 C, brush with sauce and grill 2 minutes per side to glaze, watching for flare-ups.","Rest 5 minutes and serve with extra sauce on the side."],"pairing":"Grilled corn and a crisp rosé","tags":["Crowd-pleaser","Gluten-free option","Spicy"],"vegetarian":false,"spicy":true,"calories":560,"protein":48,"carbs":22,"fat":31,"allergens":[],"role":"main","cuisineKey":"american","type":"Grills & BBQ"},{"id":"am-grilled-corn-elote","name":"Grilled Street Corn (Elote)","category":"BBQ & Grill","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Charred corn slathered in a lime-spiked crema, dusted with chilli and crumbled cotija. A Mexican-American grill staple where the smoky char playing against the cool, creamy coating is the whole magic.","ingredients":["4 corn cobs, husked","4 tbsp mayonnaise","3 tbsp soured cream","60 g cotija or feta, crumbled","1 lime, juiced and zested","1 tsp chilli powder","0.5 tsp smoked paprika","2 tbsp coriander, chopped","1 tbsp neutral oil"],"steps":["Heat a barbecue or griddle to high. Lightly oil the corn.","Grill the cobs, turning, for 8 to 10 minutes until charred in spots and tender.","Mix the mayonnaise, soured cream and lime juice into a loose coating.","Brush the hot corn all over with the crema mixture.","Sprinkle with the crumbled cheese, chilli powder, smoked paprika and lime zest.","Finish with chopped coriander and serve at once with lime wedges."],"pairing":"A cold Mexican lager with lime","tags":["Vegetarian","Quick","Gluten-free option","Spicy"],"vegetarian":true,"spicy":true,"calories":260,"protein":6,"carbs":22,"fat":18,"allergens":["Milk"],"role":"appetizer","cuisineKey":"american","type":"Starters"},{"id":"am-bbq-chicken-skewers","name":"BBQ Chicken Skewers","category":"BBQ & Grill","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Cubes of thigh threaded with peppers and onion, grilled fast and glazed with barbecue sauce for a quick, colourful plate. Thigh meat over breast is the choice that keeps the skewers juicy on a hot grill.","ingredients":["700 g boneless, skinless chicken thighs, cubed","2 bell peppers, cut into chunks","1 red onion, cut into wedges","2 tbsp neutral oil","1 tsp smoked paprika","1 tsp garlic powder","150 ml barbecue sauce","Salt and pepper","Wooden or metal skewers"],"steps":["If using wooden skewers, soak them in water for 15 minutes.","Toss the chicken with oil, paprika, garlic powder, salt and pepper.","Thread the chicken, peppers and onion alternately onto the skewers.","Heat a barbecue or griddle to medium-high and grill 10 to 12 minutes, turning, until the chicken reaches 75 C.","Brush with barbecue sauce in the last 3 minutes and turn to glaze without burning.","Rest 3 minutes and serve over rice or with salad."],"pairing":"Fluffy rice and a cold lager","tags":["Quick","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":410,"protein":36,"carbs":24,"fat":19,"allergens":[],"role":"main","cuisineKey":"american","type":"Grills & BBQ"},{"id":"am-grilled-brisket","name":"Central Texas Smoked Brisket","category":"BBQ & Grill","course":"Main","meal":"dinner","tier":"signature","inspiration":"Franklin Barbecue (Aaron Franklin)","minutes":900,"serves":8,"level":"Project","idea":"A homage to Aaron Franklin's Austin brisket: a whole packer rubbed simply with salt and coarse pepper, smoked low over post oak until the bark turns mahogany and the fat renders to butter. Patience and a steady fire, not seasoning tricks, are the whole craft, and the leftovers make the finest lunch sandwiches.","ingredients":["1 whole beef brisket, about 5 kg, fat cap trimmed to 6 mm","60 g coarse sea salt","60 g coarse-ground black pepper","Post oak or hickory wood for smoking","Butcher paper, for wrapping","Water, for the smoker pan"],"steps":["Trim the brisket, leaving an even 6 mm fat cap, and bring it to room temperature.","Mix the salt and pepper in equal parts and coat the brisket evenly on all sides.","Set a smoker to a steady 110 to 120 C with post oak and a water pan. Smoke the brisket fat-side up for about 6 hours until the bark is set and deep mahogany.","When the internal temperature hits 70 C and the bark holds, wrap tightly in butcher paper and return to the smoker.","Continue until the thickest point reads 95 to 96 C and probes like soft butter. Do not cook to a clock: a brisket stalls for hours around 70 C, so total smoking time is commonly 12 to 18 hours. Push through the stall and judge by feel.","Rest wrapped in a cool oven or cooler for at least 1 hour, then slice against the grain into pencil-thick slices."],"pairing":"White bread, pickles, raw onion and a cold longneck beer","tags":["Make-ahead","Crowd-pleaser","Comfort","Gluten-free option","Batch-cook"],"vegetarian":false,"spicy":false,"calories":650,"protein":52,"carbs":1,"fat":48,"allergens":[],"role":"main","cuisineKey":"american","type":"Grills & BBQ"},{"id":"am-mac-and-cheese","name":"Baked Macaroni and Cheese","category":"Comfort classics","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":50,"serves":4,"level":"Weeknight","idea":"A proper baked mac built on a silky béchamel and a two-cheese blend, finished with a crunchy buttered panko crust. Cheddar brings the sharp bite while Gruyère gives the molten stretch.","ingredients":["350 g elbow macaroni","50 g butter, plus 15 g for the topping","50 g plain flour","700 ml whole milk","250 g mature cheddar, grated","100 g Gruyère, grated","1 tsp Dijon mustard","0.5 tsp grated nutmeg","50 g panko breadcrumbs","Salt and white pepper"],"steps":["Heat the oven to 200 C. Cook the macaroni in salted water 2 minutes short of the packet time, then drain.","Melt the 50 g butter in a saucepan, whisk in the flour and cook 1 minute to a pale roux.","Gradually whisk in the milk and simmer, stirring, for 5 minutes until thickened enough to coat the back of a spoon.","Off the heat, stir in most of the cheddar and Gruyère, the mustard, nutmeg, salt and white pepper until smooth.","Fold in the macaroni, tip into a baking dish, and scatter with the remaining cheese, the panko and the 15 g melted topping butter.","Bake 20 to 25 minutes until bubbling and golden. Rest 5 minutes before serving."],"pairing":"A lightly oaked Chardonnay or a green salad with sharp vinaigrette","tags":["Vegetarian","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":830,"protein":37,"carbs":78,"fat":42,"allergens":["Gluten","Milk","Mustard"],"role":"main","cuisineKey":"american","type":"Mains"},{"id":"am-meatloaf","name":"Classic Glazed Meatloaf","category":"Comfort classics","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":80,"serves":4,"level":"Weeknight","idea":"A tender beef-and-pork loaf bound with a milk-soaked panade and lacquered with a tangy ketchup glaze. The panade is the trick that keeps every slice moist instead of dense and dry.","ingredients":["500 g beef mince","250 g pork mince","80 g fresh breadcrumbs","100 ml whole milk","1 onion, finely diced","2 garlic cloves, minced","1 egg, beaten","1 tbsp Worcestershire sauce","1 tsp sea salt","120 g ketchup","2 tbsp light brown sugar","1 tbsp cider vinegar"],"steps":["Heat the oven to 180 C. Soak the breadcrumbs in the milk for 5 minutes to form a panade.","Soften the onion and garlic in a little oil over medium heat for 5 minutes, then cool slightly.","Combine the beef, pork, panade, onion mixture, egg, Worcestershire and salt, mixing just until bound, not overworked.","Shape into a loaf on a lined tray. Mix the ketchup, brown sugar and vinegar and brush half over the top.","Bake 45 minutes, brush with the remaining glaze, then bake a further 15 minutes until 71 C.","Rest 10 minutes before slicing so it holds together."],"pairing":"Buttery mashed potato and a glass of Merlot","tags":["Comfort","Make-ahead","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":620,"protein":40,"carbs":35,"fat":35,"allergens":["Gluten","Milk","Egg","Sulphites"],"role":"main","cuisineKey":"american","type":"Mains"},{"id":"am-buffalo-wings","name":"Buffalo Wings","category":"Comfort classics","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Crisp baked wings tossed in the original Buffalo emulsion of cayenne hot sauce and butter. The butter rounds the vinegar heat into something glossy and addictive rather than just fiery.","ingredients":["1 kg chicken wings, split at the joint","1 tbsp baking powder","1 tsp sea salt","1 tsp garlic powder","120 ml cayenne pepper hot sauce, such as Frank's","60 g butter","1 tbsp white vinegar","100 g blue cheese","100 ml soured cream","2 tbsp mayonnaise"],"steps":["Heat the oven to 220 C. Pat the wings very dry and toss with the baking powder, salt and garlic powder, which helps them crisp.","Spread on a rack over a tray and bake 40 to 45 minutes, turning once, until deep golden and crisp at 75 C.","Gently warm the hot sauce, butter and vinegar in a pan, whisking into a smooth emulsified sauce.","Toss the hot wings in the sauce until fully coated.","Mash the blue cheese into the soured cream and mayonnaise for a dip.","Serve the wings with celery sticks and the blue cheese dip alongside."],"pairing":"An ice-cold lager and a blue cheese dip","tags":["Spicy","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":true,"calories":620,"protein":42,"carbs":6,"fat":47,"allergens":["Milk"],"role":"appetizer","cuisineKey":"american","type":"Starters"},{"id":"am-cornbread","name":"Skillet Cornbread","category":"Comfort classics","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Golden cornbread baked in a sizzling buttered cast-iron skillet for a deep, crunchy crust and a tender, faintly sweet crumb. Preheating the skillet with butter is what gives that prized fried-edge bottom.","ingredients":["200 g fine cornmeal","100 g plain flour","2 tbsp caster sugar","2 tsp baking powder","0.5 tsp bicarbonate of soda","1 tsp sea salt","250 ml buttermilk","2 eggs, beaten","60 g butter, melted, plus 1 tbsp for the skillet"],"steps":["Heat the oven to 200 C and put a 23 cm cast-iron skillet inside with the 1 tbsp butter to heat.","Whisk together the cornmeal, flour, sugar, baking powder, bicarbonate of soda and salt.","In a second bowl whisk the buttermilk, eggs and 60 g melted butter.","Fold the wet into the dry just until combined, leaving the batter slightly lumpy.","Pour the batter into the hot skillet, which should sizzle, and bake 20 to 25 minutes until golden and a skewer comes out clean.","Rest 5 minutes, then cut into wedges and serve warm with butter."],"pairing":"A bowl of chilli or a drizzle of honey","tags":["Vegetarian","Quick","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":420,"protein":10,"carbs":58,"fat":16,"allergens":["Gluten","Milk","Egg"],"role":"appetizer","cuisineKey":"american","type":"Starters"},{"id":"am-tuna-melt","name":"Diner Tuna Melt","category":"Comfort classics","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"A griddled open sandwich of creamy tuna mayo under a blanket of melted cheddar on buttery toasted bread. Toasting the bread first keeps it from going soggy under the warm filling.","ingredients":["2 x 145 g tins tuna in spring water, drained","4 tbsp mayonnaise","1 celery stick, finely diced","2 tbsp finely diced red onion","1 tsp Dijon mustard","1 tbsp lemon juice","8 slices sourdough or bloomer bread","6 slices mature cheddar","30 g butter, softened","Salt and pepper"],"steps":["Flake the tuna and mix with the mayonnaise, celery, onion, mustard, lemon juice, salt and pepper.","Butter the bread on the outsides. Heat a pan or griddle over medium.","Lay 4 slices butter-side down, pile on the tuna and top with cheddar.","Close with the remaining slices, butter-side up.","Griddle 3 to 4 minutes per side, pressing lightly, until golden and the cheese melts.","Cut in half and serve hot with pickles or crisps."],"pairing":"A bowl of tomato soup and an iced tea","tags":["Quick","Lunchbox","Comfort"],"vegetarian":false,"spicy":false,"calories":620,"protein":33,"carbs":48,"fat":33,"allergens":["Gluten","Milk","Fish","Mustard"],"role":"main","cuisineKey":"american","type":"Mains"},{"id":"am-cobb-salad","name":"Chicken Cobb Salad","category":"Comfort classics","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"The classic American chopped salad of chicken, egg, avocado, tomato and blue cheese in tidy rows over crisp lettuce with a sharp dressing. Arranging the toppings in stripes before tossing is what makes it feel composed rather than thrown together.","ingredients":["2 cooked chicken breasts, sliced","1 romaine lettuce, chopped","4 eggs, hard-boiled and halved","2 ripe avocados, sliced","200 g cherry tomatoes, halved","100 g blue cheese, crumbled","6 rashers cooked bacon, chopped","For the dressing: 4 tbsp olive oil, 2 tbsp red wine vinegar, 1 tsp Dijon mustard, salt and pepper"],"steps":["Spread the chopped lettuce over a large platter.","Arrange the chicken, eggs, avocado, tomatoes, blue cheese and bacon in neat rows on top.","Whisk the olive oil, vinegar, mustard, salt and pepper into a dressing.","Drizzle the dressing over just before serving.","Toss at the table or serve as composed for everyone to help themselves."],"pairing":"A chilled Sauvignon Blanc or sparkling water with lemon","tags":["Light","Quick","Gluten-free option","Lunchbox"],"vegetarian":false,"spicy":false,"calories":580,"protein":38,"carbs":12,"fat":42,"allergens":["Milk","Egg","Mustard","Sulphites"],"role":"salad","cuisineKey":"american","type":"Salads"},{"id":"am-buttermilk-fried-chicken","name":"Buttermilk Fried Chicken, Keller Style","category":"Comfort classics","course":"Main","meal":"both","tier":"signature","inspiration":"Ad Hoc (Thomas Keller)","minutes":90,"serves":4,"level":"Weekend","idea":"Thomas Keller's Ad Hoc method: a long lemon-and-herb buttermilk brine, then a double dredge fried in two stages so white and dark meat both finish perfectly. The herb-and-lemon brine and staggered frying are what raise this above ordinary fried chicken.","ingredients":["1 whole chicken, jointed into 8 pieces","For the brine: 1.5 litres water, 60 g salt, 2 tbsp honey, 1 lemon halved, 4 garlic cloves, a small bunch each of thyme and parsley, 1 tbsp black peppercorns","500 ml buttermilk","400 g plain flour","2 tsp garlic powder, 2 tsp onion powder, 2 tsp smoked paprika, 1 tsp cayenne","2 tsp salt and 1 tsp black pepper","2 litres neutral oil, for frying"],"steps":["Simmer the brine ingredients for 5 minutes, cool completely, then submerge the chicken and brine 8 to 12 hours in the fridge.","Drain and pat dry. Whisk the flour with the garlic and onion powders, paprika, cayenne, salt and pepper.","Dredge each piece in the seasoned flour, dip in buttermilk, then dredge again for a craggy crust.","Heat the oil to 165 C. Fry the dark meat first for 12 to 14 minutes to 75 C, keeping the oil near 160 C.","Fry the white meat for 10 to 12 minutes to 74 C, then drain on a rack.","Season lightly with salt while hot and rest 5 minutes before serving."],"pairing":"Buttermilk biscuits, hot honey and a cold Pilsner","tags":["Make-ahead","Comfort","Crowd-pleaser","Date night","Spicy"],"vegetarian":false,"spicy":true,"calories":780,"protein":48,"carbs":48,"fat":42,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"american","type":"Mains"},{"id":"am-mac-and-cheese-keller","name":"Three-Cheese Baked Mac and Cheese","cuisineKey":"american","category":"Comfort classics","course":"Main","meal":"both","tier":"signature","inspiration":"Ad Hoc (Thomas Keller)","minutes":50,"serves":4,"level":"Weekend","idea":"The defining busy-parent crowd-pleaser, absent from the American list. Keller's Ad Hoc version builds a proper bechamel and folds in three cheeses before baking, which lifts it above the boxed version while staying genuinely make-ahead and freezer-friendly.","ingredients":["300g dried elbow macaroni","60g unsalted butter","60g plain flour","700ml whole milk, warmed","150g sharp cheddar, grated","100g Gruyere, grated","60g Parmesan, grated","60g panko breadcrumbs","1/2 tsp Dijon mustard","Pinch of grated nutmeg","Salt and black pepper to taste"],"steps":["Heat oven to 190C. Boil the macaroni 2 minutes short of the packet time, drain and set aside.","Melt 45g of the butter in a saucepan, whisk in the flour and cook 2 minutes without colouring.","Whisk in the warm milk a little at a time until smooth, then simmer 5 minutes until it coats the back of a spoon. Off the heat stir in the Dijon, nutmeg, cheddar and Gruyere until melted. Season.","Fold the macaroni through the sauce and tip into a buttered baking dish.","Melt the remaining 15g butter, toss with the panko and Parmesan, and scatter over the top.","Bake 20-25 minutes until bubbling and golden. Rest 5 minutes before serving. Freezes well unbaked; add 10 minutes from chilled."],"pairing":"A crisp green salad with a sharp vinaigrette to cut the richness","tags":["kid-friendly","make-ahead","freezer-friendly","vegetarian"],"vegetarian":true,"spicy":false,"calories":760,"protein":34,"carbs":68,"fat":40,"allergens":["Gluten","Milk","Mustard"],"role":"main","type":"Mains"},{"id":"am-grilled-chicken-club","name":"Grilled Chicken Club Sandwich","cuisineKey":"american","category":"Comfort classics","role":"main","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A toasted triple-decker stacked with grilled chicken, bacon, lettuce and tomato for a satisfying lunch plate.","ingredients":["4 boneless skinless chicken breasts, about 600 g","12 slices white sandwich bread","8 rashers streaky bacon","2 beef tomatoes, sliced","8 crisp lettuce leaves","6 tbsp mayonnaise","1 tbsp Dijon mustard","2 tbsp olive oil","1 tsp garlic powder","Salt and freshly ground black pepper"],"steps":["Season the chicken with garlic powder, salt and pepper, then rub with olive oil.","Grill or pan-fry the chicken over medium-high heat for 6 to 7 minutes per side until cooked through, then rest and slice.","Fry the bacon until crisp and drain on kitchen paper.","Toast the bread and mix the mayonnaise with the Dijon mustard.","Spread each slice with the mustard mayo, then build triple-deckers with chicken, bacon, lettuce and tomato.","Secure with picks, halve and serve."],"pairing":"Crisp dill pickle spears and kettle chips","tags":["sandwich","chicken","lunch","family"],"vegetarian":false,"spicy":false,"calories":620,"protein":48,"carbs":42,"fat":29,"allergens":["Gluten","Egg","Mustard"],"type":"Mains"},{"id":"am-pulled-pork-sandwich","name":"Carolina Pulled Pork Sandwich","cuisineKey":"american","category":"BBQ & Grill","role":"main","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":40,"serves":4,"level":"Weekend","idea":"Slow-cooker pork shoulder pulled into a vinegary, smoky pile and piled on soft buns with slaw.","ingredients":["1.2 kg boneless pork shoulder","1 tbsp smoked paprika","1 tbsp light brown sugar","1 tsp garlic powder","1 tsp onion powder","1 tsp sea salt","200 ml cider vinegar","150 ml barbecue sauce","4 soft burger buns","200 g white cabbage, finely shredded","3 tbsp mayonnaise"],"steps":["Rub the pork with paprika, sugar, garlic powder, onion powder and salt.","Slow-cook with 100 ml of the vinegar on low for 8 hours, or pressure-cook for 75 minutes, until fork-tender.","Shred the pork and toss with the remaining vinegar and the barbecue sauce.","Toss the cabbage with the mayonnaise and a pinch of salt for a quick slaw.","Pile the pork onto toasted buns, top with slaw and serve."],"pairing":"Skillet cornbread and extra hot sauce","tags":["pork","bbq","sandwich","slow-cook"],"vegetarian":false,"spicy":false,"calories":640,"protein":45,"carbs":44,"fat":30,"allergens":["Gluten","Egg","Mustard","Sulphites"],"type":"Grills & BBQ"},{"id":"am-ad-hoc-roast-chicken","name":"Ad Hoc Buttermilk-Brined Roast Chicken","cuisineKey":"american","category":"Comfort classics","role":"main","course":"Main","meal":"lunch","tier":"signature","inspiration":"Ad Hoc (Thomas Keller)","minutes":120,"serves":4,"level":"Project","idea":"A buttermilk-brined whole chicken roasted to a lacquered, herb-scented finish in the Keller family-style tradition.","ingredients":["1 whole chicken, about 1.6 kg","1 litre buttermilk","30 g sea salt, plus extra for roasting","2 garlic cloves, smashed","4 sprigs thyme","1 lemon, halved","2 tbsp olive oil","20 g butter, softened","Freshly ground black pepper"],"steps":["Whisk the buttermilk with the salt, garlic and thyme, then submerge the chicken and brine in the fridge for 12 to 24 hours.","Remove the chicken, pat very dry and let it sit at room temperature for 30 minutes.","Heat the oven to 220 C. Rub the chicken with olive oil and softened butter, season with salt and pepper, and tuck the lemon inside.","Roast for 50 to 60 minutes until the juices run clear and the skin is deep golden.","Rest for 15 minutes, then carve and serve family-style."],"pairing":"Skillet cornbread and a green salad","tags":["chicken","roast","signature","sunday"],"vegetarian":false,"spicy":false,"calories":580,"protein":52,"carbs":6,"fat":38,"allergens":["Milk"],"type":"Mains"},{"id":"am-bbq-baby-back-ribs","name":"Sticky Oven Baby Back Ribs","cuisineKey":"american","category":"BBQ & Grill","role":"main","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":180,"serves":4,"level":"Weekend","idea":"Low-and-slow oven ribs with a smoky dry rub finished under a sticky barbecue glaze.","ingredients":["2 racks baby back pork ribs, about 1.6 kg","2 tbsp smoked paprika","2 tbsp light brown sugar","1 tbsp garlic powder","1 tbsp sea salt","1 tsp ground black pepper","250 ml barbecue sauce","2 tbsp cider vinegar","1 tbsp honey"],"steps":["Heat the oven to 150 C and peel the membrane from the back of the ribs.","Mix the paprika, sugar, garlic powder, salt and pepper, then rub all over the ribs.","Wrap each rack tightly in foil and bake for 2.5 hours until tender.","Mix the barbecue sauce with the vinegar and honey.","Unwrap, brush generously with the glaze and grill or roast at 220 C for 12 minutes until sticky.","Rest for 10 minutes, then cut between the bones and serve."],"pairing":"Grilled street corn and coleslaw","tags":["pork","ribs","bbq","dinner"],"vegetarian":false,"spicy":false,"calories":720,"protein":48,"carbs":32,"fat":44,"allergens":["Mustard","Sulphites"],"type":"Grills & BBQ"},{"id":"am-philly-cheesesteak","name":"Philly Cheesesteak","cuisineKey":"american","category":"Comfort classics","role":"main","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Thin-sliced ribeye griddled with onions and melted cheese piled into soft hoagie rolls.","ingredients":["700 g ribeye steak, very thinly sliced","2 white onions, thinly sliced","1 green bell pepper, thinly sliced","8 slices provolone, or 200 g Cheez Whiz","4 hoagie or sub rolls","3 tbsp neutral oil","20 g butter","Salt and freshly ground black pepper"],"steps":["Heat the oil on a griddle or large frying pan over high heat.","Cook the onions and pepper with the butter until soft and golden, then push to one side.","Add the sliced ribeye, season and cook quickly, chopping with the spatula until just browned.","Combine the meat and onions, lay the cheese over the top and let it melt.","Scoop into split, lightly toasted rolls and serve hot."],"pairing":"Crinkle-cut fries and pickles","tags":["beef","sandwich","cheese","dinner"],"vegetarian":false,"spicy":false,"calories":760,"protein":46,"carbs":46,"fat":44,"allergens":["Gluten","Milk"],"type":"Mains"},{"id":"am-french-laundry-short-rib","name":"Braised Beef Short Ribs with Red Wine","cuisineKey":"american","category":"Comfort classics","role":"main","course":"Main","meal":"dinner","tier":"signature","inspiration":"The French Laundry (Thomas Keller)","minutes":210,"serves":4,"level":"Project","idea":"Wine-braised bone-in short ribs cooked until spoon-tender with a glossy reduction, in the French Laundry style.","ingredients":["1.4 kg bone-in beef short ribs","2 tbsp neutral oil","1 onion, diced","2 carrots, diced","2 celery sticks, diced","3 garlic cloves, crushed","500 ml dry red wine","500 ml beef stock","2 tbsp tomato puree","3 sprigs thyme","Salt and freshly ground black pepper"],"steps":["Heat the oven to 160 C. Season the ribs well and sear in the oil in a casserole until deeply browned on all sides, then remove.","Soften the onion, carrots, celery and garlic in the same pan for 8 minutes.","Stir in the tomato puree, pour in the red wine and simmer to reduce by half.","Return the ribs, add the stock and thyme, bring to a simmer, cover and braise in the oven for 3 hours until tender.","Lift out the ribs, strain and reduce the sauce until glossy, then spoon over the ribs to serve."],"pairing":"Buttery mashed potatoes and a glass of red","tags":["beef","braise","signature","dinner"],"vegetarian":false,"spicy":false,"calories":680,"protein":50,"carbs":12,"fat":42,"allergens":["Sulphites"],"type":"Mains"},{"id":"am-deviled-eggs","name":"Classic Deviled Eggs","cuisineKey":"american","category":"Comfort classics","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Halved hard-boiled eggs filled with a creamy, tangy mustard yolk mixture and dusted with paprika.","ingredients":["8 eggs","4 tbsp mayonnaise","1 tsp Dijon mustard","1 tsp white wine vinegar","0.25 tsp smoked paprika, plus extra to dust","2 spring onions, finely sliced","Salt and freshly ground black pepper"],"steps":["Boil the eggs for 9 minutes, then cool in iced water and peel.","Halve the eggs and scoop the yolks into a bowl.","Mash the yolks with the mayonnaise, mustard, vinegar, salt and pepper until smooth.","Pipe or spoon the filling back into the whites.","Dust with paprika, scatter the spring onions over and serve chilled."],"pairing":"A platter alongside cold beer","tags":["eggs","starter","party","make-ahead"],"vegetarian":true,"spicy":false,"calories":190,"protein":11,"carbs":2,"fat":15,"allergens":["Egg","Mustard"],"type":"Starters"},{"id":"am-loaded-potato-skins","name":"Loaded Potato Skins","cuisineKey":"american","category":"Comfort classics","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":60,"serves":4,"level":"Weeknight","idea":"Crisp baked potato shells filled with melted cheddar and bacon, topped with soured cream and chives.","ingredients":["6 medium baking potatoes","6 rashers streaky bacon, chopped","150 g mature cheddar, grated","3 tbsp neutral oil","100 ml soured cream","3 tbsp chives, snipped","Salt and freshly ground black pepper"],"steps":["Heat the oven to 200 C and bake the potatoes for 50 minutes until tender.","Fry the bacon until crisp and drain.","Halve the potatoes and scoop out most of the flesh, leaving a shell.","Brush the shells with oil, season and bake for a further 10 minutes until crisp.","Fill with cheddar and bacon and return to the oven until melted.","Top with soured cream and chives and serve hot."],"pairing":"Buffalo wings and a cold drink","tags":["potato","cheese","bacon","party"],"vegetarian":false,"spicy":false,"calories":340,"protein":13,"carbs":30,"fat":19,"allergens":["Milk"],"type":"Starters"},{"id":"am-jalapeno-poppers","name":"Baked Jalapeno Poppers","cuisineKey":"american","category":"BBQ & Grill","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Jalapenos stuffed with a creamy cheese filling, wrapped in bacon and baked until bubbling.","ingredients":["12 large jalapeno peppers","200 g cream cheese","80 g mature cheddar, grated","12 rashers thin streaky bacon","1 tsp garlic powder","2 tbsp chives, snipped","Salt and freshly ground black pepper"],"steps":["Heat the oven to 200 C. Halve the jalapenos lengthways and scrape out the seeds.","Beat the cream cheese with the cheddar, garlic powder, chives, salt and pepper.","Spoon the filling into each jalapeno half.","Wrap each with a piece of bacon and set on a lined tray.","Bake for 20 to 25 minutes until the bacon is crisp and the filling is golden. Serve warm."],"pairing":"Soured cream dip and cold beer","tags":["cheese","bacon","party"],"vegetarian":false,"spicy":true,"calories":280,"protein":12,"carbs":5,"fat":24,"allergens":["Milk"],"type":"Starters"},{"id":"am-wedge-salad","name":"Steakhouse Wedge Salad","cuisineKey":"american","category":"Comfort classics","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"A crisp iceberg wedge drenched in blue cheese dressing with bacon, tomatoes and chives.","ingredients":["1 large iceberg lettuce, quartered into wedges","100 g blue cheese, crumbled","100 ml buttermilk","3 tbsp mayonnaise","2 tbsp soured cream","6 rashers cooked bacon, chopped","150 g cherry tomatoes, halved","2 tbsp chives, snipped","Salt and freshly ground black pepper"],"steps":["Whisk the buttermilk, mayonnaise, soured cream and half the blue cheese into a dressing, then season.","Set each iceberg wedge on a plate.","Spoon the dressing generously over each wedge.","Scatter with the remaining blue cheese, bacon, tomatoes and chives.","Finish with black pepper and serve at once."],"pairing":"Grilled steak or burgers","tags":["salad","blue cheese","starter","steakhouse"],"vegetarian":false,"spicy":false,"calories":280,"protein":12,"carbs":9,"fat":22,"allergens":["Milk"],"type":"Salads"},{"id":"am-classic-coleslaw","name":"Creamy Buttermilk Coleslaw","cuisineKey":"american","category":"BBQ & Grill","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Crunchy shredded cabbage and carrot in a tangy buttermilk dressing, the classic barbecue side.","ingredients":["400 g white cabbage, finely shredded","100 g red cabbage, finely shredded","2 carrots, grated","5 tbsp mayonnaise","3 tbsp buttermilk","1 tbsp cider vinegar","1 tsp Dijon mustard","1 tsp caster sugar","Salt and freshly ground black pepper"],"steps":["Combine the white cabbage, red cabbage and carrots in a large bowl.","Whisk the mayonnaise, buttermilk, vinegar, mustard and sugar into a dressing.","Pour over the vegetables and toss to coat.","Season with salt and pepper and chill for at least 30 minutes.","Toss again and serve cold."],"pairing":"Pulled pork or barbecue ribs","tags":["salad","slaw","bbq","make-ahead"],"vegetarian":true,"spicy":false,"calories":190,"protein":2,"carbs":12,"fat":15,"allergens":["Egg","Milk","Mustard","Sulphites"],"type":"Salads"},{"id":"am-classic-potato-salad","name":"All-American Potato Salad","cuisineKey":"american","category":"BBQ & Grill","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Tender potatoes folded with a creamy mustard dressing, celery, egg and pickles for the cookout table.","ingredients":["800 g waxy potatoes, peeled and cubed","3 eggs, hard-boiled and chopped","2 celery sticks, finely diced","4 tbsp finely diced dill pickle","5 tbsp mayonnaise","1 tbsp yellow mustard","2 spring onions, sliced","Salt and freshly ground black pepper"],"steps":["Boil the potatoes in salted water for 12 to 15 minutes until just tender, then drain and cool.","Whisk the mayonnaise with the mustard and season.","Fold the potatoes with the celery, pickle, egg and spring onions.","Stir through the dressing until evenly coated.","Chill for 30 minutes, season again and serve cold."],"pairing":"Burgers, hot dogs or grilled chicken","tags":["salad","potato","bbq","make-ahead"],"vegetarian":true,"spicy":false,"calories":300,"protein":7,"carbs":34,"fat":15,"allergens":["Egg","Mustard"],"type":"Salads"},{"id":"me-tacos-de-pollo","name":"Tacos de Pollo","category":"Tacos","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Quick chicken tacos with a warm rub of cumin, paprika and oregano, pan-charred and piled into soft corn tortillas with onion, coriander and lime. The everyday taco that comes together while the kids' bath runs.","ingredients":["500 g chicken breast or thigh, sliced","1 tsp ground cumin","1 tsp paprika","1 tsp dried oregano","1 clove garlic, grated","1 tbsp neutral oil","12 small corn tortillas","1 white onion, finely chopped","1 small bunch coriander, chopped","2 limes, cut into wedges"],"steps":["Toss the chicken with cumin, paprika, oregano, garlic, oil and a good pinch of salt.","Heat a pan over medium-high and cook the chicken for 6 to 8 minutes until lightly charred and cooked through.","Warm the tortillas in a dry pan until soft and pliable.","Fill each tortilla with chicken, onion and coriander.","Serve with lime wedges to squeeze over."],"pairing":"A cold lager or a sparkling limeade.","tags":["Quick","Crowd-pleaser","Gluten-free option","Lunchbox"],"vegetarian":false,"spicy":false,"calories":380,"protein":33,"carbs":36,"fat":12,"allergens":[],"role":"main","cuisineKey":"mexican","type":"Tacos"},{"id":"me-tacos-carne-asada","name":"Tacos de Carne Asada","category":"Tacos","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Steak quickly marinated in lime, garlic and cumin, seared hard and chopped into tender, charred pieces for warm tortillas with onion and coriander. Fast, juicy and a guaranteed family favourite.","ingredients":["600 g skirt or flank steak","2 limes, juiced","2 cloves garlic, grated","1 tsp ground cumin","1 tbsp neutral oil","12 small corn tortillas","1 white onion, finely chopped","1 small bunch coriander, chopped","1 lime, cut into wedges"],"steps":["Mix the lime juice, garlic, cumin, oil and 1 tsp salt, then coat the steak and leave 15 minutes.","Heat a heavy pan very hot and sear the steak for 2 to 3 minutes a side for medium, then rest 5 minutes.","Chop the steak into small pieces against the grain.","Warm the tortillas in a dry pan until pliable.","Fill with steak, onion and coriander, and serve with lime wedges."],"pairing":"A cold Mexican lager or a michelada.","tags":["Quick","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":430,"protein":36,"carbs":35,"fat":16,"allergens":[],"role":"main","cuisineKey":"mexican","type":"Tacos"},{"id":"me-tacos-de-camaron","name":"Tacos de Camaron","category":"Tacos","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Garlicky prawns flashed in a hot pan with chilli and lime, folded into warm tortillas with crunchy cabbage and a quick lime crema. Light, fresh and on the table in twenty minutes.","ingredients":["500 g raw prawns, peeled","2 cloves garlic, grated","1 tsp paprika","1/2 tsp chilli flakes","1 tbsp neutral oil","150 g white cabbage, finely shredded","120 g sour cream","1 lime, juiced, plus wedges","12 small corn tortillas","1 small bunch coriander, chopped"],"steps":["Toss the prawns with garlic, paprika, chilli flakes and a pinch of salt.","Stir the sour cream with the lime juice and a pinch of salt to make a quick crema.","Heat the oil in a pan over high heat and cook the prawns for 2 to 3 minutes until pink and just firm.","Warm the tortillas in a dry pan until pliable.","Fill each tortilla with cabbage, prawns and a drizzle of lime crema.","Finish with coriander and serve with lime wedges."],"pairing":"A crisp Sauvignon Blanc or a cold lager.","tags":["Quick","Light","Spicy","Gluten-free option"],"vegetarian":false,"spicy":true,"calories":390,"protein":28,"carbs":37,"fat":14,"allergens":["Shellfish","Milk"],"role":"main","cuisineKey":"mexican","type":"Tacos"},{"id":"me-tacos-de-pescado","name":"Baja Fish Tacos","category":"Tacos","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"The classic of Ensenada: beer-battered white fish fried shatteringly crisp, piled onto warm corn tortillas with shredded cabbage and a tangy chipotle-lime crema. Light, crunchy and built for a hot day.","ingredients":["600 g firm white fish (cod or pollock), cut into 12 strips","120 g plain flour","1 tsp baking powder","180 ml cold Mexican lager","1 tsp paprika","200 g white cabbage, finely shredded","120 g Mexican crema (or sour cream)","1 lime, juiced, plus wedges to serve","1 tbsp chipotle in adobo, mashed","12 small corn tortillas","Neutral oil, for frying","1 small bunch coriander, chopped"],"steps":["Whisk the flour, baking powder, paprika and 1 tsp salt, then whisk in the cold beer to a smooth, just-pourable batter.","Stir the crema with lime juice, mashed chipotle and a pinch of salt to make the dressing.","Heat oil to 180 C. Dip the fish strips in batter and fry in batches for 3 to 4 minutes until golden and crisp and cooked through, then drain on paper.","Warm the tortillas on a dry comal until pliable.","Fill each tortilla with cabbage, a fish strip and a drizzle of chipotle crema.","Finish with coriander and serve with lime wedges."],"pairing":"A crisp Mexican lager or a chilled Sauvignon Blanc.","tags":["Quick","Crowd-pleaser","Light","Spicy"],"vegetarian":false,"spicy":true,"calories":480,"protein":34,"carbs":48,"fat":17,"allergens":["Fish","Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"mexican","type":"Tacos"},{"id":"me-tacos-al-pastor","name":"Tacos al Pastor","category":"Tacos","course":"Main","meal":"dinner","tier":"signature","inspiration":"Cosme (Enrique Olvera)","minutes":90,"serves":4,"level":"Weekend","idea":"Mexico City's emblematic spit-roasted pork, marinated in dried guajillo and ancho chiles, achiote and pineapple, then crisped and tucked into warm corn tortillas with charred pineapple, raw onion and coriander. The fruit's acidity cuts the richness beautifully.","ingredients":["800 g pork shoulder, sliced 5 mm thick","3 dried guajillo chiles, stemmed and seeded","2 dried ancho chiles, stemmed and seeded","30 g achiote (annatto) paste","3 cloves garlic","60 ml white vinegar","60 ml pineapple juice","1 tsp dried oregano","1 tsp ground cumin","300 g fresh pineapple, finely diced","1 white onion, finely chopped","16 small corn tortillas","1 small bunch coriander, chopped","2 limes, cut into wedges"],"steps":["Toast the guajillo and ancho chiles in a dry pan for 30 seconds until fragrant, then soak in hot water for 15 minutes until soft.","Blend the soaked chiles with achiote, garlic, vinegar, pineapple juice, oregano, cumin and 1 tsp salt into a smooth marinade.","Coat the pork slices fully and marinate overnight in the fridge for the deepest colour and flavour.","Sear the pork in batches over high heat in a hot pan or griddle until charred at the edges and cooked through to at least 63 C, then rest and chop finely.","Char the diced pineapple in the same pan for 2 minutes to caramelise.","Warm the tortillas on a dry comal until pliable and just blistered.","Fill each tortilla with pork, top with charred pineapple, raw onion and coriander, and serve with lime wedges to squeeze over."],"pairing":"An ice-cold Mexican lager with lime, or a tart hibiscus agua de jamaica.","tags":["Spicy","Make-ahead","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":true,"calories":560,"protein":42,"carbs":52,"fat":20,"allergens":["Sulphites"],"role":"main","cuisineKey":"mexican","type":"Tacos"},{"id":"me-burrito-bowl","name":"Chipotle Chicken Burrito Bowl","category":"Bowls & Enchiladas","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"A fresh, balanced bowl of coriander-lime rice, cumin black beans and smoky chipotle chicken topped with quick pico de gallo and sliced avocado. Fast, vibrant and endlessly satisfying on a weeknight.","ingredients":["300 g cooked chicken thigh, sliced","2 tbsp chipotle in adobo, chopped","180 g long-grain rice","1 lime, juiced, plus wedges","1 small bunch coriander, chopped","240 g cooked black beans, drained","1 tsp ground cumin","2 plum tomatoes, diced","1/2 white onion, finely chopped","1 avocado, sliced","1 tbsp neutral oil"],"steps":["Cook the rice until tender, then fork through half the lime juice, half the coriander and a pinch of salt.","Toss the chicken with chopped chipotle, then warm through in the oil over medium-high heat until lightly charred.","Warm the black beans with cumin and a splash of water until saucy.","Make a quick pico de gallo by mixing the tomatoes, onion, remaining coriander and a squeeze of lime with salt.","Divide the rice between two bowls and top with beans, chipotle chicken, pico de gallo and avocado.","Serve with lime wedges to squeeze over."],"pairing":"A cold lager, or a sparkling lime agua mineral.","tags":["Quick","Light","Spicy","Gluten-free option","Lunchbox"],"vegetarian":false,"spicy":true,"calories":720,"protein":42,"carbs":78,"fat":26,"allergens":[],"role":"main","cuisineKey":"mexican","type":"Rice & Bowls"},{"id":"me-enchiladas-verdes","name":"Enchiladas Verdes de Pollo","category":"Bowls & Enchiladas","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Corn tortillas rolled around shredded chicken and bathed in a roasted tomatillo and serrano salsa verde, finished with crema and crumbled queso fresco. Tangy, comforting and gently spicy.","ingredients":["500 g tomatillos, husked","2 serrano chiles","3 cloves garlic","1/2 white onion","1 small bunch coriander","400 g cooked chicken, shredded","12 corn tortillas","150 ml Mexican crema","120 g queso fresco, crumbled","1 white onion, thinly sliced, to serve","2 tbsp neutral oil"],"steps":["Boil the tomatillos and serranos for 8 minutes until soft and olive-green, then blend with the garlic, onion, coriander and 1 tsp salt.","Fry the blended salsa in 1 tbsp hot oil for 5 minutes to deepen the flavour, then keep warm.","Lightly fry each tortilla in the remaining oil for a few seconds to soften, then drain.","Fill each tortilla with shredded chicken, roll up and arrange seam-side down in a dish.","Pour the warm salsa verde generously over the top.","Finish with crema, crumbled queso fresco and sliced onion, then serve at once."],"pairing":"A dry Mexican rosado, or a tamarind agua fresca.","tags":["Comfort","Crowd-pleaser","Spicy","Make-ahead"],"vegetarian":false,"spicy":true,"calories":480,"protein":32,"carbs":38,"fat":22,"allergens":["Milk"],"role":"main","cuisineKey":"mexican","type":"Rice & Bowls"},{"id":"me-enchiladas-frijol-queso","name":"Black Bean & Cheese Enchiladas","category":"Bowls & Enchiladas","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Corn tortillas rolled around mashed cumin black beans and melting cheese, baked under a quick tomato-chipotle sauce. A hearty meat-free tray bake that pleases the whole table.","ingredients":["480 g cooked black beans, drained","1 tsp ground cumin","200 g grated cheddar or Monterey Jack","400 g tinned chopped tomatoes","1 tbsp chipotle in adobo, mashed","1 clove garlic, grated","12 corn tortillas","1/2 white onion, finely chopped","2 tbsp neutral oil","1 small bunch coriander, chopped"],"steps":["Warm the tomatoes with the chipotle, garlic and a pinch of salt for 5 minutes to make a quick sauce.","Mash the black beans with the cumin, onion and a splash of water until spreadable.","Soften the tortillas briefly in the oil, then fill each with beans and a little cheese and roll up.","Arrange seam-side down in a baking dish, pour over the sauce and scatter the remaining cheese.","Bake at 200 C for 15 minutes until bubbling and golden.","Scatter with coriander and serve."],"pairing":"A light Mexican lager or a hibiscus agua fresca.","tags":["Vegetarian","Comfort","Make-ahead","Crowd-pleaser","Batch-cook"],"vegetarian":true,"spicy":false,"calories":470,"protein":21,"carbs":48,"fat":22,"allergens":["Milk"],"role":"main","cuisineKey":"mexican","type":"Rice & Bowls"},{"id":"me-bowl-carne-frijol","name":"Beef & Black Bean Rice Bowl","category":"Bowls & Enchiladas","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Spiced beef mince browned with cumin and tomato, spooned over rice and black beans with corn, avocado and a squeeze of lime. A one-pan, batch-friendly bowl kids actually finish.","ingredients":["500 g beef mince","1 tsp ground cumin","1 tsp paprika","1/2 white onion, chopped","1 clove garlic, grated","2 tbsp tomato paste","240 g cooked black beans, drained","150 g sweetcorn","250 g cooked rice","1 avocado, sliced","1 lime, cut into wedges","1 tbsp neutral oil"],"steps":["Heat the oil and soften the onion and garlic for 3 minutes.","Add the beef, cumin and paprika and brown well, breaking it up, for 6 minutes.","Stir in the tomato paste, beans and a splash of water and simmer 3 minutes until saucy.","Warm the corn through with the rice.","Divide rice and beans between bowls, top with the spiced beef, corn and avocado.","Serve with lime wedges."],"pairing":"A cold lager or a sparkling limeade.","tags":["Quick","One-pan","Batch-cook","Comfort","Gluten-free option","Lunchbox"],"vegetarian":false,"spicy":false,"calories":520,"protein":33,"carbs":42,"fat":25,"allergens":[],"role":"main","cuisineKey":"mexican","type":"Rice & Bowls"},{"id":"me-enchiladas-mole","name":"Enchiladas de Mole Poblano","category":"Bowls & Enchiladas","course":"Main","meal":"dinner","tier":"signature","inspiration":"Pujol (Enrique Olvera)","minutes":75,"serves":4,"level":"Project","idea":"Tortillas folded into a velvety Pueblan mole built on a trinity of dried chiles, toasted seeds and nuts, ripe tomato and a whisper of Mexican chocolate. Deep, layered and faintly sweet, this is Mexican cooking at its most celebratory.","ingredients":["3 dried ancho chiles, stemmed and seeded","2 dried mulato chiles, stemmed and seeded","2 dried pasilla chiles, stemmed and seeded","2 plum tomatoes","1/2 white onion, chopped","2 cloves garlic","40 g sesame seeds, plus extra to garnish","30 g raisins","30 g almonds","30 g Mexican chocolate (or dark chocolate 70%)","1 corn tortilla, torn (for thickening)","1 tsp ground cinnamon","750 ml chicken stock","400 g cooked chicken, shredded","12 corn tortillas","80 g queso fresco, crumbled","2 tbsp neutral oil"],"steps":["Toast the dried chiles in a dry pan for 30 seconds until fragrant, then soak in hot water for 15 minutes.","Char the tomatoes, onion and garlic in a dry pan until softened and blistered.","Toast the sesame, almonds, raisins and torn tortilla until golden, then blend with the drained chiles, charred tomato, onion, garlic, cinnamon and enough stock to make a smooth paste.","Fry the paste in the oil for 8 minutes, stirring constantly, then loosen with the remaining stock and simmer 20 minutes until glossy.","Stir in the chocolate until melted and season with salt; the mole should coat the back of a spoon.","Soften the 12 tortillas briefly in a little oil, fill with shredded chicken and fold into quarters.","Nap the folded enchiladas with warm mole, scatter with sesame and crumbled queso fresco, and serve."],"pairing":"A medium-bodied Mexican red such as Nebbiolo from Valle de Guadalupe.","tags":["Comfort","Date night","Spicy","Make-ahead"],"vegetarian":false,"spicy":true,"calories":540,"protein":32,"carbs":45,"fat":27,"allergens":["Sesame","Tree nuts","Milk","Sulphites"],"role":"main","cuisineKey":"mexican","type":"Rice & Bowls"},{"id":"me-guacamole","name":"Guacamole","category":"Sides & Salsas","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"The proper molcajete way: ripe avocado coarsely mashed with onion, serrano, coriander and lime, kept chunky and bright with a little diced tomato. Simple, but only as good as the avocados.","ingredients":["3 ripe avocados","1/2 white onion, finely chopped","1 serrano chile, finely chopped","1 small bunch coriander, chopped","1 lime, juiced","1 plum tomato, deseeded and diced","1/2 tsp fine salt"],"steps":["Mash the onion, serrano, half the coriander and the salt to a rough paste in a molcajete or bowl.","Halve and stone the avocados, scoop the flesh in and mash coarsely, keeping plenty of texture.","Fold through the lime juice, diced tomato and remaining coriander.","Taste and adjust salt and lime, then serve immediately to keep the colour fresh."],"pairing":"Warm totopos (corn tortilla chips) and a cold beer.","tags":["Vegetarian","Vegan","Quick","Spicy","Gluten-free option","Crowd-pleaser"],"vegetarian":true,"spicy":true,"calories":230,"protein":3,"carbs":13,"fat":20,"allergens":[],"role":"appetizer","cuisineKey":"mexican","type":"Starters"},{"id":"me-salsa-roja","name":"Salsa Roja Asada","category":"Sides & Salsas","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A smoky table salsa of charred tomatoes, garlic and chiles de arbol blended with raw onion and lime. Roasting the vegetables on a dry comal gives it that unmistakable depth.","ingredients":["500 g plum tomatoes","3 dried chiles de arbol","2 cloves garlic, unpeeled","1/4 white onion","1 small bunch coriander","1 lime, juiced","1/2 tsp fine salt"],"steps":["Char the tomatoes and unpeeled garlic on a dry comal or hot pan, turning, until blackened in spots and softened.","Toast the chiles de arbol for 20 seconds until fragrant, taking care not to burn them.","Peel the garlic, then blend with the tomatoes, chiles, onion, coriander, lime juice and salt to a coarse salsa.","Taste for salt and heat, then cool slightly before serving. Keeps 3 days in the fridge."],"pairing":"Spoon over tacos, eggs or grilled meats.","tags":["Vegetarian","Vegan","Spicy","Make-ahead","Quick","Gluten-free option"],"vegetarian":true,"spicy":true,"calories":45,"protein":2,"carbs":9,"fat":1,"allergens":[],"role":"appetizer","cuisineKey":"mexican","type":"Starters"},{"id":"me-elote","name":"Elote (Mexican Street Corn)","category":"Sides & Salsas","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Grilled corn cobs slathered in lime-spiked mayo and crema, rolled in salty cotija and dusted with chile powder. The street snack of Mexico: smoky, creamy and tangy all at once.","ingredients":["4 corn cobs, husked","60 g mayonnaise","60 g Mexican crema (or sour cream)","80 g cotija cheese, finely crumbled","1 tsp chile powder (ancho or chile piquin)","1 lime, cut into wedges","1 small bunch coriander, chopped"],"steps":["Grill or char the corn over high heat, turning, for 8 to 10 minutes until blistered and tender.","Mix the mayonnaise and crema together with a pinch of salt.","Brush each hot cob all over with the mayo-crema mixture.","Roll in crumbled cotija until well coated.","Dust with chile powder, scatter with coriander and serve with lime wedges to squeeze over."],"pairing":"A cold michelada or a tamarind agua fresca.","tags":["Vegetarian","Spicy","Quick","Crowd-pleaser","Gluten-free option"],"vegetarian":true,"spicy":true,"calories":260,"protein":7,"carbs":24,"fat":16,"allergens":["Milk","Egg"],"role":"appetizer","cuisineKey":"mexican","type":"Starters"},{"id":"me-pico-de-gallo","name":"Pico de Gallo","category":"Sides & Salsas","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":10,"serves":4,"level":"Weeknight","idea":"The fresh, raw salsa that brightens everything: ripe tomato, onion, jalapeno, coriander and lime, chopped fine and seasoned well. No cooking, no equipment, ready in minutes.","ingredients":["4 ripe plum tomatoes, deseeded and diced","1/2 white onion, finely chopped","1 jalapeno, finely chopped","1 small bunch coriander, chopped","1 lime, juiced","1/2 tsp fine salt"],"steps":["Combine the tomato, onion, jalapeno and coriander in a bowl.","Stir through the lime juice and salt.","Let it sit for 5 minutes for the flavours to come together, then taste and adjust.","Serve with chips, tacos or grilled meats."],"pairing":"Spoon over tacos, eggs, grilled chicken or fish.","tags":["Vegetarian","Vegan","Quick","Spicy","Gluten-free option","Light"],"vegetarian":true,"spicy":true,"calories":35,"protein":1,"carbs":8,"fat":0,"allergens":[],"role":"appetizer","cuisineKey":"mexican","type":"Starters"},{"id":"me-esquites-cosme","name":"Esquites with Lime and Epazote","category":"Sides & Salsas","course":"Starter","meal":"both","tier":"signature","inspiration":"Cosme (Enrique Olvera)","minutes":30,"serves":4,"level":"Weekend","idea":"The celebrated corn dish reimagined in the Cosme spirit: sweetcorn charred hard then folded warm through a whipped lime crema heady with epazote, finished with cotija, chile and a snowfall of cured egg yolk. Smoky, creamy and quietly luxurious.","ingredients":["500 g sweetcorn kernels (from 4 cobs)","2 tbsp neutral oil","100 g Mexican crema","60 g mayonnaise","1 lime, zested and juiced","1 tbsp chopped epazote (or coriander)","60 g cotija cheese, finely crumbled","1 tsp chile piquin or ancho powder","1 cured or grated hard egg yolk, to finish","1/2 tsp fine salt"],"steps":["Heat the oil in a wide pan until almost smoking, add the corn in a single layer and leave undisturbed for 3 minutes to char, then toss and char again.","Whisk the crema, mayonnaise, lime zest and juice, epazote and salt into a light, whipped dressing.","Fold the hot charred corn through the dressing while still warm so it loosens and coats.","Spoon into bowls and top with crumbled cotija and a dusting of chile powder.","Finish with a fine grating of cured egg yolk over the top and serve warm with spoons."],"pairing":"A mezcal sour, or a chilled dry Mexican rosado.","tags":["Vegetarian","Spicy","Date night","Gluten-free option"],"vegetarian":true,"spicy":true,"calories":290,"protein":7,"carbs":24,"fat":20,"allergens":["Milk","Egg"],"role":"appetizer","cuisineKey":"mexican","type":"Starters"},{"id":"me-ensalada-nopales","name":"Ensalada de Nopales","cuisineKey":"mexican","category":"Sides & Salsas","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Grilled cactus paddle salad tossed with tomato, onion and queso fresco, a classic Mexican market salad.","ingredients":["6 fresh nopales (cactus paddles), spines removed","2 ripe plum tomatoes, diced","1/2 white onion, finely chopped","100 g queso fresco, crumbled","1 small bunch coriander, chopped","2 limes, juiced","2 tbsp olive oil","1 serrano chile, finely chopped","1/2 tsp dried oregano","1/2 tsp fine salt"],"steps":["Grill or boil the nopales until tender, about 8 minutes, then dice.","Rinse to remove any sliminess and drain well.","Combine nopales with tomato, onion, coriander and serrano.","Whisk lime juice, olive oil, oregano and salt, then toss through.","Scatter crumbled queso fresco over the top and serve."],"pairing":"Warm corn tortillas","tags":["salad","fresh","grilled"],"vegetarian":true,"spicy":true,"calories":180,"protein":7,"carbs":12,"fat":12,"allergens":["Milk"],"type":"Salads"},{"id":"me-ensalada-jicama","name":"Jicama, Orange and Chile Salad","cuisineKey":"mexican","category":"Sides & Salsas","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Crisp jicama matchsticks with juicy orange segments, lime and chile piquin, bright and refreshing.","ingredients":["1 large jicama (about 500 g), peeled and cut into matchsticks","3 oranges, segmented","2 limes, juiced","1 tsp chile piquin or ancho powder","1/2 tsp fine salt","1 small bunch coriander, chopped","1 cucumber, diced"],"steps":["Toss jicama and cucumber matchsticks in a bowl.","Add orange segments and any captured juice.","Dress with lime juice and salt.","Dust with chile powder and scatter coriander.","Chill 10 minutes and serve cold."],"pairing":"Grilled fish or tacos","tags":["salad","refreshing","no-cook"],"vegetarian":true,"spicy":true,"calories":120,"protein":2,"carbs":27,"fat":1,"allergens":[],"type":"Salads"},{"id":"me-ensalada-frijol-aguacate","name":"Black Bean, Corn and Avocado Salad","cuisineKey":"mexican","category":"Sides & Salsas","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"A hearty bean and corn salad with avocado, lime and coriander, the kind kids actually finish.","ingredients":["320 g cooked black beans, drained","200 g sweetcorn kernels","2 avocados, diced","2 plum tomatoes, diced","1/2 red onion, finely chopped","1 small bunch coriander, chopped","2 limes, juiced","2 tbsp olive oil","1/2 tsp ground cumin","1/2 tsp fine salt"],"steps":["Combine black beans, sweetcorn, tomato and onion in a bowl.","Whisk lime juice, olive oil, cumin and salt.","Pour dressing over and toss gently.","Fold in diced avocado just before serving.","Finish with coriander."],"pairing":"Grilled chicken or as a taco side","tags":["salad","hearty","no-cook"],"vegetarian":true,"spicy":false,"calories":290,"protein":9,"carbs":31,"fat":16,"allergens":[],"type":"Salads"},{"id":"me-queso-fundido","name":"Queso Fundido con Chorizo","cuisineKey":"mexican","category":"Sides & Salsas","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Molten melted cheese baked with chorizo, scooped up with warm tortillas, a sizzling table starter.","ingredients":["300 g Oaxaca or mozzarella cheese, grated","150 g Mexican chorizo, casing removed","1/2 white onion, finely chopped","1 poblano chile, diced","8 small corn tortillas, to serve","1 small bunch coriander, chopped"],"steps":["Cook chorizo in an ovenproof skillet, breaking it up, until browned.","Add onion and poblano and soften for 4 minutes.","Spoon off excess fat, then scatter grated cheese over the top.","Bake or grill until the cheese is fully melted and bubbling.","Scatter coriander and serve with warm tortillas for scooping."],"pairing":"Warm corn tortillas","tags":["appetizer","cheese","sharing","hot"],"vegetarian":false,"spicy":false,"calories":380,"protein":22,"carbs":18,"fat":25,"allergens":["Milk"],"type":"Starters"},{"id":"me-tostada-tinga","name":"Tostadas de Tinga de Pollo","cuisineKey":"mexican","category":"Tacos","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Crisp tostadas topped with smoky chipotle chicken tinga, crema and queso fresco.","ingredients":["8 corn tostadas (crisp shells)","350 g cooked chicken, shredded","2 plum tomatoes, blended","1/2 white onion, thinly sliced","2 tbsp chipotle in adobo, mashed","1 clove garlic, grated","120 ml Mexican crema","80 g queso fresco, crumbled","1 avocado, sliced","1 tbsp neutral oil"],"steps":["Soften onion and garlic in oil for 3 minutes.","Add blended tomato and chipotle and simmer 5 minutes.","Stir in shredded chicken and cook until coated and saucy.","Spread tinga over each tostada shell.","Top with avocado, crema and crumbled queso fresco."],"pairing":"Pico de gallo","tags":["appetizer","chicken","smoky","crisp"],"vegetarian":false,"spicy":true,"calories":310,"protein":21,"carbs":22,"fat":16,"allergens":["Milk"],"type":"Starters"},{"id":"me-quesadillas-flor","name":"Quesadillas de Flor de Calabaza","cuisineKey":"mexican","category":"Tacos","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Griddled corn quesadillas filled with squash blossom and melting Oaxaca cheese, a Mexico City market classic.","ingredients":["8 small corn tortillas","200 g Oaxaca or mozzarella cheese, grated","150 g squash blossoms (flor de calabaza), cleaned","1/2 white onion, finely chopped","1 serrano chile, finely chopped","2 epazote leaves, chopped (or coriander)","1 tbsp neutral oil"],"steps":["Soften onion and serrano in oil for 3 minutes.","Add squash blossoms and epazote and wilt for 2 minutes.","Lay cheese and blossom mix on each tortilla and fold over.","Griddle the quesadillas until golden and the cheese melts.","Cut and serve warm with salsa."],"pairing":"Salsa roja asada","tags":["appetizer","cheese","griddled"],"vegetarian":true,"spicy":true,"calories":280,"protein":13,"carbs":26,"fat":14,"allergens":["Milk"],"type":"Starters"},{"id":"me-pollo-pibil","name":"Cochinita-Style Pollo Pibil","cuisineKey":"mexican","category":"Bowls & Enchiladas","role":"main","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":50,"serves":4,"level":"Weeknight","idea":"Achiote-marinated chicken roasted until tender, served with pickled red onion and rice, lighter than the pork classic.","ingredients":["700 g chicken thighs, boneless","40 g achiote (annatto) paste","3 oranges, juiced","2 limes, juiced","3 cloves garlic","1 tsp dried oregano","1 tsp ground cumin","1 red onion, thinly sliced","60 ml white vinegar","250 g cooked rice, to serve","1 tbsp neutral oil","1/2 tsp fine salt"],"steps":["Blend achiote, orange juice, half the lime juice, garlic, oregano and cumin.","Coat chicken in the marinade and rest 20 minutes.","Pickle red onion in vinegar, remaining lime juice and salt.","Roast chicken at 200C for 30 minutes until cooked and tender.","Slice and serve over rice topped with pickled onion."],"pairing":"Warm corn tortillas","tags":["main","chicken","achiote","roasted"],"vegetarian":false,"spicy":false,"calories":480,"protein":38,"carbs":34,"fat":20,"allergens":[],"type":"Rice & Bowls"},{"id":"me-chiles-rellenos","name":"Chiles Rellenos de Queso","cuisineKey":"mexican","category":"Bowls & Enchiladas","role":"main","course":"Main","meal":"lunch","tier":"signature","inspiration":"Quintonil (Jorge Vallejo)","minutes":70,"serves":4,"level":"Weekend","idea":"Roasted poblano chiles stuffed with cheese, dipped in airy egg batter and bathed in tomato caldillo.","ingredients":["4 large poblano chiles","250 g Oaxaca or mozzarella cheese, in batons","4 eggs, separated","60 g plain flour","500 g plum tomatoes","1/2 white onion","1 clove garlic","250 ml chicken or vegetable stock","1 tsp dried oregano","Neutral oil, for frying","1/2 tsp fine salt"],"steps":["Char poblanos, steam in a bag, then peel and slit to deseed.","Stuff each chile with cheese batons and dust in flour.","Whisk egg whites to stiff peaks, then fold in beaten yolks.","Coat chiles in the batter and fry until golden, then drain.","Blend tomato, onion and garlic, simmer with stock and oregano, then serve the chiles in the caldillo."],"pairing":"Mexican red rice","tags":["main","poblano","signature"],"vegetarian":true,"spicy":false,"calories":520,"protein":24,"carbs":28,"fat":34,"allergens":["Milk","Egg","Gluten"],"type":"Rice & Bowls"},{"id":"me-pescado-veracruz","name":"Pescado a la Veracruzana","cuisineKey":"mexican","category":"Bowls & Enchiladas","role":"main","course":"Main","meal":"lunch","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"White fish fillets simmered in a bright tomato sauce with olives, capers and herbs, a Gulf coast classic.","ingredients":["4 white fish fillets (cod or hake, about 600 g)","500 g plum tomatoes, chopped","1/2 white onion, sliced","2 cloves garlic, sliced","60 g green olives, sliced","2 tbsp capers","2 bay leaves","1 tsp dried oregano","2 pickled jalapenos, sliced","2 tbsp olive oil","250 g cooked rice, to serve","1/2 tsp fine salt"],"steps":["Soften onion and garlic in olive oil for 4 minutes.","Add tomato, bay, oregano and salt, simmer 10 minutes.","Stir in olives, capers and jalapenos.","Nestle fish fillets into the sauce and poach gently for 8 minutes.","Serve over rice spooned with the sauce."],"pairing":"Crusty bread or rice","tags":["main","fish","tomato","coastal"],"vegetarian":false,"spicy":false,"calories":420,"protein":36,"carbs":30,"fat":16,"allergens":["Fish"],"type":"Rice & Bowls"},{"id":"me-carnitas","name":"Carnitas con Tortillas","cuisineKey":"mexican","category":"Bowls & Enchiladas","role":"main","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":180,"serves":6,"level":"Weekend","idea":"Slow-braised pork shoulder confit until meltingly tender, then crisped, piled into tortillas.","ingredients":["1.2 kg pork shoulder, in chunks","2 oranges, halved","1 white onion, quartered","4 cloves garlic","2 bay leaves","1 tsp ground cumin","1 tsp dried oregano","100 g lard or neutral oil","18 small corn tortillas","1 white onion, finely chopped, to serve","1 small bunch coriander, chopped","2 limes, cut into wedges","1 tsp fine salt"],"steps":["Place pork, onion, garlic, bay, cumin, oregano and salt in a heavy pot.","Squeeze oranges over, drop in the spent halves, and add lard.","Cover with water and simmer gently for 2 hours until very tender.","Raise the heat to evaporate liquid and crisp the pork in its own fat.","Shred and serve in warm tortillas with onion, coriander and lime."],"pairing":"Salsa verde and pickled onion","tags":["main","pork","braised","crispy"],"vegetarian":false,"spicy":false,"calories":620,"protein":42,"carbs":34,"fat":34,"allergens":[],"type":"Rice & Bowls"},{"id":"me-birria-res","name":"Birria de Res","cuisineKey":"mexican","category":"Bowls & Enchiladas","role":"main","course":"Main","meal":"dinner","tier":"signature","inspiration":"Quintonil (Jorge Vallejo)","minutes":210,"serves":6,"level":"Project","idea":"Deeply spiced beef stew in a guajillo and ancho chile broth, served with consome for dipping.","ingredients":["1.4 kg beef chuck or short rib","4 dried guajillo chiles, stemmed and seeded","3 dried ancho chiles, stemmed and seeded","2 dried chiles de arbol","4 plum tomatoes","1 white onion, halved","5 cloves garlic","1 tbsp cider vinegar","1 tsp ground cumin","1 tsp dried oregano","2 bay leaves","1 cinnamon stick","18 small corn tortillas","1 white onion, finely chopped, to serve","1 small bunch coriander, chopped","2 limes, cut into wedges","1 tsp fine salt"],"steps":["Toast and soak the dried chiles, then blend with tomato, onion, garlic, vinegar and spices.","Brown the beef, then pour over the chile sauce and add bay and cinnamon.","Cover with water and braise gently for 3 hours until the beef pulls apart.","Shred the meat and strain the rich consome.","Serve the birria with consome on the side, tortillas, onion, coriander and lime."],"pairing":"Dip tortillas in the consome quesabirria style","tags":["main","beef","stew","signature","chile"],"vegetarian":false,"spicy":true,"calories":640,"protein":48,"carbs":32,"fat":36,"allergens":[],"type":"Rice & Bowls"},{"id":"in-quick-chicken-curry","name":"Everyday Chicken Curry","category":"Curries","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"A no-fuss home-style chicken curry built on onion, tomato and pantry spices. No marinating, no blending, just one pan and twenty minutes of gentle simmering for a curry that tastes like it took far longer.","ingredients":["600g boneless chicken thighs, cut into chunks","3 tbsp vegetable oil","2 onions, finely chopped","2 tbsp ginger-garlic paste","400g tin chopped tomatoes","1 tsp ground turmeric","1 tbsp ground coriander","1 tsp ground cumin","1 tsp Kashmiri chilli powder","1 tsp garam masala","Fresh coriander, chopped","Salt to taste"],"steps":["Fry the onions in oil over medium heat until soft and golden, about 8 minutes.","Stir in the ginger-garlic paste, turmeric, coriander, cumin and chilli powder and cook 1 minute until fragrant.","Add the tomatoes and cook 5 minutes until they break down and thicken.","Add the chicken, season with salt, and stir to coat in the masala.","Pour in a splash of water, cover and simmer 12 to 15 minutes until the chicken is cooked through.","Stir in the garam masala, finish with fresh coriander and serve."],"pairing":"Steamed basmati or warm chapati","tags":["Quick","One-pan","Comfort","Gluten-free option","Make-ahead"],"vegetarian":false,"spicy":false,"calories":380,"protein":31,"carbs":11,"fat":24,"allergens":[],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-palak-paneer","name":"Palak Paneer","category":"Curries","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Soft cubes of paneer in a vibrant, lightly spiced spinach gravy. Blanching the spinach briefly and shocking it in ice water keeps the colour a bright living green rather than a dull khaki.","ingredients":["400g fresh spinach leaves","250g paneer, cubed","2 tbsp ghee","1 large onion, finely chopped","1 tbsp ginger-garlic paste","2 green chillies, slit","1 tsp ground cumin","1 tsp garam masala","1 medium tomato, chopped","60ml double cream","1 tsp dried fenugreek leaves","Salt to taste"],"steps":["Blanch the spinach for 60 seconds, plunge into ice water, then blend to a coarse puree.","Lightly fry the paneer cubes in 1 tbsp ghee until golden, then set aside (soak in warm water to keep them soft).","In the remaining ghee fry the onion until soft, add ginger-garlic paste, chillies and cumin and cook until fragrant.","Add the tomato and cook until broken down, then stir in the spinach puree and simmer 5 minutes.","Add the paneer, cream, garam masala and crushed fenugreek, then simmer 3 minutes until everything is hot.","Season and finish with a swirl of cream."],"pairing":"Hot tandoori roti and a cucumber raita","tags":["Vegetarian","Gluten-free option","Comfort","Quick"],"vegetarian":true,"spicy":false,"calories":340,"protein":15,"carbs":12,"fat":26,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-chana-masala","name":"Chana Masala","category":"Curries","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":40,"serves":4,"level":"Weeknight","idea":"Chickpeas in a tangy, deeply spiced tomato-onion masala sharpened with amchur and a final lift of garam masala. Naturally vegan, satisfying and quick enough for a weeknight.","ingredients":["2 x 400g tins chickpeas, drained","3 tbsp vegetable oil","2 onions, finely chopped","1 tbsp ginger-garlic paste","2 green chillies, chopped","400g tin chopped tomatoes","1.5 tsp ground coriander","1 tsp ground cumin","1 tsp Kashmiri chilli powder","1 tsp amchur (dried mango powder)","1 tsp garam masala","Fresh coriander, chopped","Salt to taste"],"steps":["Fry the onions in oil until golden brown, then add ginger-garlic paste and green chillies.","Add the coriander, cumin and chilli powder and toast for 30 seconds until fragrant.","Stir in the tomatoes and cook 10 to 12 minutes until thick and the oil separates.","Add the chickpeas with a splash of water and simmer 12 minutes, lightly crushing a few to thicken the gravy.","Stir in the amchur and garam masala, season well and simmer 2 more minutes.","Finish with fresh coriander."],"pairing":"Bhatura or steamed rice with sliced red onion and lemon","tags":["Vegan","Vegetarian","Quick","One-pan","Gluten-free option"],"vegetarian":true,"spicy":true,"calories":300,"protein":12,"carbs":34,"fat":13,"allergens":[],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-egg-curry","name":"Anda Curry (Egg Curry)","category":"Curries","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Boiled eggs simmered in a quick, spiced onion-tomato gravy. A brilliant cheap and fast protein when the fridge is bare, ready in half an hour from store-cupboard basics and gentle enough for the whole table.","ingredients":["6 large eggs","3 tbsp vegetable oil","2 onions, finely chopped","1 tbsp ginger-garlic paste","400g tin chopped tomatoes","1 tsp ground turmeric","1 tsp Kashmiri chilli powder","1 tbsp ground coriander","1 tsp garam masala","Fresh coriander, chopped","Salt to taste"],"steps":["Hard-boil the eggs for 9 minutes, cool, peel and prick each a few times with a fork.","Fry the onions in oil until golden, then add ginger-garlic paste, turmeric, chilli powder and coriander.","Add the tomatoes and cook 8 to 10 minutes until thick and glossy.","Add a splash of water to loosen into a gravy, season with salt and simmer 5 minutes.","Slip in the eggs, spoon over the sauce and simmer 5 minutes.","Stir in garam masala and finish with fresh coriander."],"pairing":"Jeera rice or buttered chapati","tags":["Quick","One-pan","Comfort","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":250,"protein":12,"carbs":12,"fat":17,"allergens":["Egg"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-dal-tadka","name":"Dal Tadka","category":"Curries","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Everyday yellow lentils simmered soft and finished with a sizzling tempering of cumin, garlic and chilli in ghee. Comforting, cheap, freezer-friendly and naturally gentle enough for kids.","ingredients":["250g toor dal or red lentils","1 tsp ground turmeric","1 tomato, chopped","3 tbsp ghee","1 tsp cumin seeds","4 cloves garlic, sliced","2 dried red chillies","1 small onion, finely chopped","1 tsp Kashmiri chilli powder","Fresh coriander, chopped","Salt to taste"],"steps":["Rinse the lentils, then simmer with the turmeric, tomato and plenty of water for 20 to 25 minutes until soft, topping up water as needed.","Whisk the cooked dal until creamy and season with salt, loosening to a soft pouring consistency.","Heat the ghee in a small pan, add the cumin seeds and let them crackle.","Add the garlic, dried chillies and onion and fry until the garlic is golden.","Stir in the chilli powder off the heat, then pour the sizzling tempering over the dal.","Stir through, finish with coriander and serve."],"pairing":"Steamed rice or chapati and a spoon of yoghurt","tags":["Vegetarian","Comfort","Make-ahead","Batch-cook","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":290,"protein":13,"carbs":35,"fat":11,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-dal-bukhara","name":"Dal Bukhara","category":"Curries","course":"Main","meal":"dinner","tier":"signature","inspiration":"Bukhara (ITC Maurya)","minutes":150,"serves":4,"level":"Project","idea":"The legendary black dal of Bukhara at ITC Maurya: whole black urad slow-simmered for hours over the gentlest heat with butter, tomato and cream until glossy and unctuous. No rajma, no shortcuts. Time and a low flame are the real ingredients.","ingredients":["250g whole black urad dal (sabut urad)","80g unsalted butter","2 tbsp ginger-garlic paste","1 large onion, finely chopped","300g tomato puree (passata)","1 tsp Kashmiri chilli powder","1 tsp ground cumin","1 tsp garam masala","120ml double cream","1 tbsp dried fenugreek leaves","Salt to taste"],"steps":["Soak the urad dal overnight, then pressure-cook with salt and plenty of water until completely soft, around 40 minutes.","Melt half the butter, fry the onion until golden, add ginger-garlic paste and cook off the rawness.","Add the tomato puree, chilli powder and cumin and cook 10 minutes until the fat separates.","Tip in the cooked dal with its liquid and simmer uncovered on the lowest heat for at least 60 to 90 minutes, stirring often and mashing some lentils against the pan until thick and glossy.","Stir through the cream, garam masala, crushed fenugreek and remaining butter and cook a final 10 minutes.","Season and finish with an extra drizzle of cream."],"pairing":"Naan or jeera rice and a glass of Shiraz","tags":["Vegetarian","Make-ahead","Comfort","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":400,"protein":15,"carbs":35,"fat":24,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-butter-chicken","name":"Butter Chicken (Murgh Makhani)","category":"Curries","course":"Main","meal":"both","tier":"signature","inspiration":"Dishoom","minutes":75,"serves":4,"level":"Weekend","idea":"A faithful homage to the Dishoom house murgh makhani: yoghurt-marinated chicken charred for smoke, then folded into a velvety tomato gravy enriched with butter and cream. Cashews add silk and crushed kasuri methi gives that unmistakable restaurant aroma.","ingredients":["800g boneless chicken thighs, cut into chunks","150g full-fat Greek yoghurt","2 tbsp ginger-garlic paste","2 tsp Kashmiri chilli powder","600g ripe tomatoes, roughly chopped (or 400g tin plus 200g fresh)","80g unsalted butter","150ml double cream","1 tsp garam masala","1 tbsp dried fenugreek leaves (kasuri methi)","1 tbsp sugar","30g cashews, soaked","Salt to taste"],"steps":["Marinate the chicken in yoghurt, half the ginger-garlic paste, 1 tsp chilli powder and salt for at least 30 minutes, ideally overnight.","Char the chicken under a hot grill or in a screaming-hot pan until edges blacken and it is just cooked through, then set aside.","Simmer the tomatoes with the remaining ginger-garlic paste, cashews and chilli powder for 15 minutes until pulpy, then blend until silky and pass through a sieve.","Melt the butter, add the smooth tomato base and cook gently for 10 minutes until it deepens in colour and the fat separates.","Stir in the cream, sugar, garam masala and crushed kasuri methi, then fold in the chicken and any resting juices.","Simmer 5 minutes until the sauce coats the chicken, check salt and finish with a knob of butter."],"pairing":"Garlic naan and a glass of off-dry Riesling","tags":["Crowd-pleaser","Comfort","Make-ahead","Date night","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":620,"protein":44,"carbs":14,"fat":44,"allergens":["Milk","Tree nuts"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-rogan-josh","name":"Lamb Rogan Josh","category":"Curries","course":"Main","meal":"dinner","tier":"signature","inspiration":"Indian Accent","minutes":120,"serves":4,"level":"Weekend","idea":"A Michelin-chef take on the aromatic Kashmiri lamb curry, built on browned onions, whisked yoghurt and Kashmiri chilli for a deep red colour without ferocious heat. Slow cooking renders the lamb fork-tender in a glossy sauce scented with fennel and cardamom.","ingredients":["800g lamb shoulder, cut into 4cm pieces","3 tbsp ghee or mustard oil","2 large onions, finely sliced","2 tbsp ginger-garlic paste","150g Greek yoghurt, whisked","2 tsp Kashmiri chilli powder","1 tsp ground fennel","1 tsp ground ginger","4 green cardamom pods","2 cloves and 1 small cinnamon stick","2 bay leaves","1 tsp garam masala","Salt to taste"],"steps":["Heat the ghee and brown the lamb in batches, then set aside.","Fry the onions in the same pan until deep golden, add the whole spices and bay leaves and let them sizzle.","Stir in the ginger-garlic paste, then lower the heat and add the whisked yoghurt a spoonful at a time so it does not split.","Add the chilli powder, fennel and ground ginger and cook into a thick paste.","Return the lamb with a splash of water, cover and simmer gently for 75 to 90 minutes until fork-tender.","Finish with garam masala, check seasoning and rest 5 minutes before serving."],"pairing":"Steamed basmati and a glass of Syrah","tags":["Comfort","Make-ahead","Gluten-free option","Date night"],"vegetarian":false,"spicy":false,"calories":520,"protein":40,"carbs":12,"fat":35,"allergens":["Milk","Mustard"],"role":"main","cuisineKey":"indian","type":"Curry"},{"id":"in-chicken-tikka","name":"Chicken Tikka","category":"Tandoori & Grills","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Boneless chicken in a quick yoghurt and spice coating, charred hard so the edges catch and smoke. The classic starter and the building block of tikka masala, simple enough for any weeknight.","ingredients":["700g boneless chicken thighs, cut into large chunks","150g thick Greek yoghurt","2 tbsp ginger-garlic paste","2 tsp Kashmiri chilli powder","1 tsp ground cumin","1 tsp garam masala","2 tbsp lemon juice","2 tbsp vegetable oil","1 tbsp dried fenugreek leaves","Salt to taste"],"steps":["Mix the yoghurt with the ginger-garlic paste, chilli powder, cumin, garam masala, lemon juice, oil, crushed fenugreek and salt.","Coat the chicken in the marinade and chill at least 30 minutes, ideally 2 hours.","Thread onto skewers, or spread on a lined tray.","Grill on the highest heat, or under a hot grill, turning until charred and cooked through, around 12 to 15 minutes.","Brush with a little butter or oil in the last minute for shine.","Rest briefly and serve with lemon and onion."],"pairing":"Mint-coriander chutney and a cold lager","tags":["Gluten-free option","Quick","Crowd-pleaser","Make-ahead","Lunchbox"],"vegetarian":false,"spicy":true,"calories":340,"protein":40,"carbs":6,"fat":17,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Grills & BBQ"},{"id":"in-paneer-tikka","name":"Paneer Tikka","category":"Tandoori & Grills","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Cubes of paneer and peppers in a spiced yoghurt marinade, char-grilled until the edges blister. The vegetarian centrepiece of the grill, smoky outside and soft within.","ingredients":["400g paneer, cut into 3cm cubes","1 red pepper and 1 green pepper, in chunks","1 red onion, cut into petals","200g thick Greek yoghurt","2 tbsp ginger-garlic paste","1 tbsp gram flour (besan)","2 tsp Kashmiri chilli powder","1 tsp garam masala","1 tsp ground cumin","2 tbsp vegetable oil","1 tbsp dried fenugreek leaves","Salt to taste"],"steps":["Toast the gram flour in a dry pan until fragrant, then whisk into the yoghurt with the ginger-garlic paste, spices, oil and crushed fenugreek.","Fold in the paneer, peppers and onion and marinate at least 30 minutes.","Thread onto skewers, alternating paneer and vegetables.","Grill on high heat or under a hot grill, turning, until the edges char and blister, around 10 minutes.","Brush with a little oil or butter for gloss.","Finish with a squeeze of lemon and a dusting of chaat masala if you have it."],"pairing":"Mint-coriander chutney and a crisp Sauvignon Blanc","tags":["Vegetarian","Gluten-free option","Crowd-pleaser","Quick"],"vegetarian":true,"spicy":true,"calories":390,"protein":18,"carbs":16,"fat":28,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Grills & BBQ"},{"id":"in-tandoori-prawns","name":"Tandoori Prawns","category":"Tandoori & Grills","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Big prawns in a quick spiced yoghurt marinade, grilled fast and hot until smoky and just firm. A fifteen-minute marinade and a screaming pan put a restaurant starter on the table in no time.","ingredients":["500g large raw prawns, peeled and deveined","120g thick Greek yoghurt","2 tbsp ginger-garlic paste","2 tsp Kashmiri chilli powder","1 tsp garam masala","1 tsp ground turmeric","2 tbsp lemon juice","2 tbsp vegetable oil","Fresh coriander, chopped","Salt to taste"],"steps":["Pat the prawns dry, then toss with the yoghurt, ginger-garlic paste, chilli powder, garam masala, turmeric, lemon juice, oil and salt.","Marinate 15 minutes while you heat a grill pan or grill until very hot.","Thread onto skewers, or lay flat on a hot pan.","Grill 2 to 3 minutes per side until charred at the edges and just opaque through, taking care not to overcook.","Squeeze over more lemon and scatter with coriander.","Serve hot with chutney."],"pairing":"Mint chutney, lemon wedges and a chilled white","tags":["Gluten-free option","Quick","Light","Date night"],"vegetarian":false,"spicy":true,"calories":190,"protein":26,"carbs":5,"fat":8,"allergens":["Shellfish","Milk"],"role":"main","cuisineKey":"indian","type":"Grills & BBQ"},{"id":"in-seekh-kebab","name":"Chicken Seekh Kebabs","category":"Tandoori & Grills","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Spiced minced chicken pressed onto skewers and grilled until juicy and charred. Mix, shape, grill: a fast, kid-friendly favourite that needs nothing more than a squeeze of lemon.","ingredients":["600g chicken mince","1 small onion, very finely chopped","2 tbsp ginger-garlic paste","2 green chillies, finely chopped","1 tsp garam masala","1 tsp ground cumin","1 tsp Kashmiri chilli powder","3 tbsp chopped fresh coriander","2 tbsp gram flour (besan)","2 tbsp vegetable oil","Salt to taste"],"steps":["Mix all the ingredients except the oil thoroughly until the mince becomes slightly sticky.","Chill 15 minutes to firm up, which helps it hold on the skewer.","With wet hands, press the mixture into sausage shapes around skewers or roll into logs.","Brush with oil and grill on high heat or under a hot grill, turning, until browned and cooked through, around 12 minutes.","Rest 2 minutes so the juices settle.","Serve with lemon, sliced onion and mint chutney."],"pairing":"Mint-coriander chutney and warm naan","tags":["Gluten-free option","Quick","Crowd-pleaser","Lunchbox","Make-ahead"],"vegetarian":false,"spicy":true,"calories":290,"protein":29,"carbs":7,"fat":16,"allergens":[],"role":"main","cuisineKey":"indian","type":"Grills & BBQ"},{"id":"in-tandoori-chicken","name":"Tandoori Chicken","category":"Tandoori & Grills","course":"Main","meal":"dinner","tier":"signature","inspiration":"Bukhara (ITC Maurya)","minutes":60,"serves":4,"level":"Weekend","idea":"The dish Moti Mahal made famous: bone-in chicken slashed to the bone, marinated in spiced yoghurt, then roasted hard so the surface blisters and the meat stays juicy. The deep colour comes from Kashmiri chilli, never food dye.","ingredients":["1.2kg chicken legs and thighs, skin removed, slashed deeply","200g thick Greek yoghurt","2 tbsp ginger-garlic paste","2 tsp Kashmiri chilli powder","1 tsp ground turmeric","1 tbsp garam masala","2 tbsp lemon juice","3 tbsp mustard oil","1 tsp ground cumin","1 tbsp dried fenugreek leaves","Salt to taste"],"steps":["Rub the slashed chicken with lemon juice, half the chilli powder and salt and leave 20 minutes.","Mix the yoghurt with ginger-garlic paste, remaining spices, mustard oil and crushed fenugreek.","Coat the chicken thoroughly, working the marinade into the slashes, and chill at least 4 hours or overnight.","Roast in a very hot oven at 240C, or on a hot barbecue, for 30 to 35 minutes, turning once, until charred and the juices run clear.","Finish under a high grill for a few minutes to blister the surface.","Squeeze over lemon and serve hot."],"pairing":"Onion salad, mint chutney and a chilled rosé","tags":["Gluten-free option","Crowd-pleaser","Make-ahead","Date night"],"vegetarian":false,"spicy":true,"calories":420,"protein":52,"carbs":7,"fat":20,"allergens":["Milk","Mustard"],"role":"main","cuisineKey":"indian","type":"Grills & BBQ"},{"id":"in-jeera-rice","name":"Jeera Rice","category":"Rice & Breads","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Fluffy basmati tempered with cumin seeds bloomed in ghee, the everyday partner to any dal or curry. The trick is soaking the rice so the grains stay long, separate and never sticky.","ingredients":["300g basmati rice","2 tbsp ghee","2 tsp cumin seeds (jeera)","1 small bay leaf","2 green cardamom pods","1 small cinnamon stick","600ml water","Salt to taste","Fresh coriander, chopped"],"steps":["Rinse the rice until the water runs clear, then soak for 20 minutes and drain.","Heat the ghee, add the cumin seeds and whole spices and let them sizzle until the cumin crackles and smells nutty.","Tip in the drained rice and toss gently for a minute to coat the grains.","Add the water and salt, bring to a boil, then cover and cook on the lowest heat for 12 minutes.","Rest covered off the heat for 5 minutes, then fluff with a fork.","Scatter with coriander and serve."],"pairing":"Dal bukhara, chana masala or any rich curry","tags":["Vegetarian","Quick","Comfort","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":330,"protein":6,"carbs":58,"fat":7,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Rice & Bowls"},{"id":"in-lemon-rice","name":"Lemon Rice","category":"Rice & Breads","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"A bright South Indian rice tossed with a mustard-seed and curry-leaf tempering, turmeric and fresh lemon. The fastest way to turn leftover rice into something zingy, and excellent cold in a lunchbox.","ingredients":["500g cooked basmati rice, cooled","3 tbsp vegetable oil","1 tsp mustard seeds","1 tbsp chana dal or peanuts","10 fresh curry leaves","2 dried red chillies","1 tsp ground turmeric","3 tbsp lemon juice","Salt to taste","Fresh coriander, chopped"],"steps":["Heat the oil, add the mustard seeds and let them pop.","Add the chana dal or peanuts and fry until golden, then add curry leaves and dried chillies.","Stir in the turmeric off the heat so it does not burn.","Add the cooled rice and salt and toss gently to coat every grain yellow.","Squeeze in the lemon juice and fold through.","Finish with coriander and serve warm or at room temperature."],"pairing":"Coconut chutney or a simple yoghurt","tags":["Vegan","Vegetarian","Quick","One-pan","Light","Lunchbox","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":270,"protein":5,"carbs":42,"fat":10,"allergens":["Peanut"],"role":"main","cuisineKey":"indian","type":"Rice & Bowls"},{"id":"in-chapati","name":"Chapati (Roti)","category":"Rice & Breads","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Soft everyday wholemeal flatbreads cooked on a dry pan and puffed over the flame. Just flour and water, no yeast and no proving, the daily bread that goes with everything.","ingredients":["300g chapati flour (atta) or wholemeal flour","Around 200ml warm water","1 tsp vegetable oil","1/2 tsp salt","A little extra flour for dusting","A little butter or ghee to finish"],"steps":["Mix the flour and salt, then add the water a little at a time, bringing it together into a soft, pliable dough.","Knead 5 minutes, rub with the oil, cover and rest 15 minutes.","Divide into 8 balls and roll each into a thin round on a floured surface.","Cook on a hot dry pan for about 30 seconds a side until brown spots appear.","Press the edges gently or hold over a flame so the chapati puffs up.","Brush with a little butter and keep warm under a cloth."],"pairing":"Any dal or curry","tags":["Vegetarian","Vegan","Quick","Comfort","Make-ahead"],"vegetarian":true,"spicy":false,"calories":270,"protein":8,"carbs":51,"fat":4,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"indian","type":"Rice & Bowls"},{"id":"in-garlic-naan","name":"Quick Garlic Naan","category":"Rice & Breads","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"A fast no-yeast naan leavened with yoghurt and baking powder, slapped onto a screaming-hot pan and finished with garlic butter and coriander. Soft, blistered and on the table in half an hour with no proving.","ingredients":["350g plain flour, plus extra for dusting","1 tsp baking powder","1/2 tsp bicarbonate of soda","1 tsp sugar","150g plain yoghurt","60ml warm milk","2 tbsp vegetable oil","1 tsp salt","4 cloves garlic, finely minced","50g butter, melted","Fresh coriander, chopped"],"steps":["Mix the flour, baking powder, bicarbonate of soda, sugar and salt, then stir in the yoghurt, warm milk and oil to form a soft dough.","Knead 3 to 4 minutes until smooth, cover and rest just 15 minutes.","Divide into 6 balls and roll each into a teardrop about 5mm thick.","Heat a heavy skillet until smoking, slap on a naan, cook until large bubbles form, then flip and press until charred in spots.","Mix the garlic into the melted butter and brush generously over the hot naan, scattering coriander.","Keep warm under a cloth and serve straight away."],"pairing":"Any rich curry such as butter chicken or dal bukhara","tags":["Vegetarian","Quick","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":420,"protein":11,"carbs":66,"fat":12,"allergens":["Gluten","Milk"],"role":"main","cuisineKey":"indian","type":"Rice & Bowls"},{"id":"in-chicken-biryani","name":"Hyderabadi Dum Biryani","category":"Rice & Breads","course":"Main","meal":"dinner","tier":"signature","inspiration":"Dishoom","minutes":90,"serves":4,"level":"Project","idea":"The slow-sealed dum biryani in the Dum Pukht tradition: marinated chicken layered with par-cooked saffron basmati and sealed to steam in its own aromas. The reward is separate, perfumed grains over tender, spiced meat.","ingredients":["700g bone-in chicken pieces","400g aged basmati rice","200g Greek yoghurt","3 onions, finely sliced and fried golden (birista)","2 tbsp ginger-garlic paste","2 tsp Kashmiri chilli powder","1 tbsp biryani masala","Large pinch saffron soaked in 60ml warm milk","5 green cardamom, 4 cloves, 1 cinnamon stick, 2 bay leaves","4 tbsp ghee","Handful each chopped mint and coriander","2 tbsp lemon juice","Salt to taste"],"steps":["Marinate the chicken in yoghurt, ginger-garlic paste, chilli powder, biryani masala, half the fried onions, lemon juice and salt for at least 1 hour.","Soak the rice 30 minutes, then boil in heavily salted water with the whole spices until 70 percent cooked, and drain.","Layer the marinated chicken in a heavy pot, top with the par-cooked rice, then scatter the remaining fried onions, mint, coriander, saffron milk and ghee.","Seal the pot tightly with a lid or foil and cook on the lowest heat (dum) for 25 to 30 minutes until the chicken is cooked through and the rice is steamed.","Rest sealed for 10 minutes off the heat so the steam settles.","Open at the table and fold gently from the edges to bring up the layers."],"pairing":"Cooling boondi raita and a glass of Gewürztraminer","tags":["Crowd-pleaser","Date night","Gluten-free option","Make-ahead"],"vegetarian":false,"spicy":true,"calories":620,"protein":35,"carbs":62,"fat":26,"allergens":["Milk"],"role":"main","cuisineKey":"indian","type":"Rice & Bowls"},{"id":"in-samosa-chaat","name":"Samosa Chaat","cuisineKey":"indian","category":"Tandoori & Grills","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Crushed crisp samosas smothered in spiced chickpeas, yoghurt, and tangy chutneys, the classic Indian street-food starter.","ingredients":["4 ready-made vegetable samosas","400g tin chickpeas, drained and warmed","200g plain yoghurt, whisked","4 tbsp tamarind chutney","3 tbsp coriander-mint chutney","1 tsp chaat masala","1 tsp roasted cumin powder","1 small red onion, finely chopped","30g sev (crisp gram-flour noodles)","Fresh coriander, chopped","Salt to taste"],"steps":["Bake or fry the samosas until hot and crisp, then roughly crush them onto a serving plate.","Spoon the warm chickpeas over the crushed samosas.","Drizzle generously with whisked yoghurt, then the tamarind and coriander-mint chutneys.","Scatter over chopped red onion, then dust with chaat masala and roasted cumin.","Top with sev and fresh coriander and serve immediately while crisp."],"pairing":"Masala chai or a cold lassi","tags":["street food","chaat","sharing"],"vegetarian":true,"spicy":true,"calories":340,"protein":11,"carbs":45,"fat":13,"allergens":["Gluten","Milk"],"type":"Starters"},{"id":"in-aloo-tikki","name":"Aloo Tikki with Chutneys","cuisineKey":"indian","category":"Tandoori & Grills","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Golden pan-fried spiced potato cakes served with green and tamarind chutneys, a crisp, comforting starter.","ingredients":["600g floury potatoes, boiled and mashed","3 tbsp cornflour","2 green chillies, finely chopped","1 tbsp ginger, grated","1 tsp ground cumin","1 tsp garam masala","1 tsp amchur (dried mango powder)","3 tbsp chopped fresh coriander","4 tbsp vegetable oil for shallow frying","4 tbsp coriander-mint chutney","4 tbsp tamarind chutney","Salt to taste"],"steps":["Mix the mashed potato with cornflour, chillies, ginger, cumin, garam masala, amchur, coriander, and salt.","Shape the mixture into 8 flat round patties about 2cm thick.","Heat the oil in a frying pan and shallow-fry the tikkis over medium heat until deep golden and crisp on both sides.","Drain on kitchen paper.","Serve hot with coriander-mint and tamarind chutneys spooned alongside."],"pairing":"Cold mint lassi","tags":["street food","crispy","sharing"],"vegetarian":true,"spicy":true,"calories":290,"protein":5,"carbs":42,"fat":12,"allergens":[],"type":"Starters"},{"id":"in-onion-bhaji","name":"Onion Bhaji","cuisineKey":"indian","category":"Tandoori & Grills","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Crisp, lacy gram-flour onion fritters spiced with cumin and chilli, the ultimate Indian starter to share.","ingredients":["3 large onions, thinly sliced","150g gram flour (besan)","2 tbsp rice flour","1 tsp ground turmeric","1 tsp Kashmiri chilli powder","1 tsp cumin seeds","1 tsp ground coriander","2 green chillies, finely chopped","3 tbsp chopped fresh coriander","Around 80ml cold water","Vegetable oil for deep frying","Salt to taste"],"steps":["Toss the sliced onions with salt and leave for 10 minutes to soften and release moisture.","Add gram flour, rice flour, turmeric, chilli powder, cumin seeds, ground coriander, green chillies, and fresh coriander.","Mix well, adding only enough cold water to form a thick batter that coats the onions.","Heat oil to 170C and drop in small clusters of the mixture.","Fry until deep golden and crisp, drain on kitchen paper, and serve hot with chutney."],"pairing":"Mango chutney and a cold beer or lassi","tags":["fritter","crispy","sharing"],"vegetarian":true,"spicy":true,"calories":260,"protein":8,"carbs":30,"fat":12,"allergens":[],"type":"Starters"},{"id":"in-kachumber-salad","name":"Kachumber Salad","cuisineKey":"indian","category":"Tandoori & Grills","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"The crunchy North Indian table salad of diced cucumber, tomato, and onion sharpened with lemon and toasted cumin.","ingredients":["1 cucumber, finely diced","3 tomatoes, deseeded and finely diced","1 red onion, finely diced","2 green chillies, finely chopped","3 tbsp chopped fresh coriander","2 tbsp lemon juice","1 tsp roasted cumin powder","1/2 tsp Kashmiri chilli powder","Salt to taste"],"steps":["Combine the cucumber, tomato, red onion, green chillies, and coriander in a bowl.","Add the lemon juice, roasted cumin, and chilli powder.","Season with salt and toss gently to combine.","Chill for 10 minutes and toss again just before serving so it stays crisp."],"pairing":"Any rich curry or biryani","tags":["salad","fresh","side"],"vegetarian":true,"spicy":true,"calories":70,"protein":2,"carbs":12,"fat":1,"allergens":[],"type":"Salads"},{"id":"in-chana-chaat-salad","name":"Chickpea Chaat Salad","cuisineKey":"indian","category":"Tandoori & Grills","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"A protein-rich chaat-style salad of chickpeas, onion, tomato, and cucumber tossed in tamarind and lime with chaat masala.","ingredients":["2 x 400g tins chickpeas, drained and rinsed","1 red onion, finely diced","2 tomatoes, finely diced","1/2 cucumber, finely diced","2 tbsp tamarind chutney","2 tbsp lime juice","1 tsp chaat masala","1 tsp roasted cumin powder","2 green chillies, finely chopped","4 tbsp chopped fresh coriander","Salt to taste"],"steps":["Tip the chickpeas into a large bowl with the onion, tomato, and cucumber.","Add the tamarind chutney, lime juice, chaat masala, and roasted cumin.","Add the green chillies and coriander, season with salt, and toss well.","Rest for 5 minutes to let the flavours meld, then taste and adjust lime and salt before serving."],"pairing":"Grilled tandoori chicken or eaten on its own as a light lunch","tags":["salad","protein","chaat"],"vegetarian":true,"spicy":true,"calories":210,"protein":10,"carbs":34,"fat":4,"allergens":[],"type":"Salads"},{"id":"in-cucumber-raita-salad","name":"Cucumber and Pomegranate Raita Salad","cuisineKey":"indian","category":"Tandoori & Grills","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Cool yoghurt-dressed cucumber salad jewelled with pomegranate and toasted cumin, a refreshing foil to spice.","ingredients":["300g thick Greek yoghurt","1 cucumber, coarsely grated and squeezed dry","80g pomegranate seeds","1 tsp roasted cumin powder","1/2 tsp Kashmiri chilli powder","2 tbsp chopped fresh mint","2 tbsp chopped fresh coriander","1 tsp sugar","Salt to taste"],"steps":["Whisk the yoghurt with sugar and a pinch of salt until smooth.","Fold in the grated cucumber and most of the pomegranate seeds.","Stir through the roasted cumin, mint, and coriander.","Spoon into a bowl, scatter over the remaining pomegranate and a dusting of chilli powder, and serve chilled."],"pairing":"Biryani or any tandoori grill","tags":["salad","raita","cooling"],"vegetarian":true,"spicy":false,"calories":120,"protein":7,"carbs":13,"fat":4,"allergens":["Milk"],"type":"Salads"},{"id":"in-fish-tikka","name":"Amritsari Fish Tikka","cuisineKey":"indian","category":"Tandoori & Grills","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Firm white fish marinated in yoghurt, carom seeds, and gram flour, then chargrilled until smoky and golden.","ingredients":["700g firm white fish fillets (cod or pollock), cut into 4cm chunks","150g thick Greek yoghurt","2 tbsp ginger-garlic paste","2 tbsp gram flour (besan)","2 tsp Kashmiri chilli powder","1 tsp ground turmeric","1 tsp carom seeds (ajwain)","1 tsp garam masala","2 tbsp lemon juice","2 tbsp mustard oil","Salt to taste"],"steps":["Pat the fish dry and toss gently with lemon juice, turmeric, and salt.","Whisk the yoghurt with ginger-garlic paste, gram flour, chilli powder, carom seeds, garam masala, and mustard oil.","Coat the fish in the marinade and chill for 30 minutes.","Thread onto skewers or lay on a lined tray and grill or bake at 220C for 10 to 12 minutes, turning once, until charred at the edges and just cooked.","Rest briefly, then serve with kachumber and lemon wedges."],"pairing":"Kachumber salad and garlic naan","tags":["tandoori","fish","grilled","high protein"],"vegetarian":false,"spicy":true,"calories":300,"protein":38,"carbs":8,"fat":12,"allergens":["Fish","Milk","Mustard"],"type":"Grills & BBQ"},{"id":"th-red-curry-chicken","name":"Quick Thai Red Chicken Curry","category":"Curries & Stir-fry","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A weeknight curry built on a tub of shop-bought red curry paste, coconut milk and chicken. Frying the paste in a little of the thick coconut cream first is the one move that makes it taste cooked rather than canned.","ingredients":["600g chicken breast or thigh, sliced","400ml coconut milk","3 tbsp red curry paste","2 tbsp fish sauce","1 tbsp brown sugar","1 red pepper, sliced","150g green beans, halved","2 makrut lime leaves or zest of 1 lime","Handful basil leaves","1 tbsp neutral oil"],"steps":["Spoon the thick cream from the top of the coconut milk into a wide pan with the oil and heat until bubbling.","Add the red curry paste and fry 2 minutes until it smells fragrant.","Add the chicken and stir to coat, cooking 3 minutes until it turns opaque.","Pour in the rest of the coconut milk plus a splash of water, then add pepper, beans and lime leaves.","Simmer 10 minutes until the chicken is cooked and the vegetables are just tender.","Season with fish sauce and sugar, stir through the basil and serve with rice."],"pairing":"Jasmine rice and a cold lager","tags":["Quick","One-pan","Gluten-free option","Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":true,"calories":430,"protein":35,"carbs":12,"fat":27,"allergens":["Fish"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-cashew-chicken","name":"Thai Cashew Chicken Stir-fry","category":"Curries & Stir-fry","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"A gentle, mild stir-fry the whole family eats: chicken and toasted cashews in a glossy oyster-soy sauce with sweet pepper and onion. Friendly enough for kids but quick enough for a tired cook.","ingredients":["300g chicken breast, sliced","60g roasted cashews","1 onion, in wedges","1 red pepper, sliced","3 spring onions, in batons","3 garlic cloves, chopped","2 tbsp oyster sauce","1 tbsp light soy sauce","1 tsp sugar","2 tbsp neutral oil"],"steps":["Mix the oyster sauce, soy sauce and sugar with 2 tablespoons water in a small bowl.","Heat the oil in a wok or large pan until hot, add the garlic and onion and stir-fry 1 minute.","Add the chicken and stir-fry over high heat 4 minutes until cooked and lightly golden.","Add the pepper and toss 1 minute until just softened.","Pour in the sauce and the cashews and toss to glaze.","Finish with the spring onions and serve over rice."],"pairing":"Steamed rice and iced jasmine tea","tags":["Quick","One-pan","Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":false,"calories":510,"protein":42,"carbs":22,"fat":28,"allergens":["Fish","Shellfish","Soy","Gluten","Tree nuts"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-pad-krapow-gai","name":"Pad Krapow Gai (Holy Basil Chicken Stir-fry)","category":"Curries & Stir-fry","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Thailand's ultimate fast food: minced chicken seared hard with chilli, garlic and pungent basil, served over rice with a crisp-edged fried egg. Punchy, salty-savoury and on the table in minutes. Dial the chilli down for younger eaters.","ingredients":["300g minced chicken","4 garlic cloves, chopped","2 to 4 red chillies, chopped","Large handful Thai or holy basil leaves","1 tbsp oyster sauce","1 tbsp light soy sauce","1 tsp dark soy sauce","1 tsp sugar","2 tbsp neutral oil","2 eggs, to fry","Steamed jasmine rice, to serve"],"steps":["Fry the eggs in hot oil until the edges are lacy and crisp but the yolks stay soft, then set aside.","Heat a wok until hot, add oil, garlic and chilli and fry 20 seconds until fragrant.","Add the chicken and stir-fry over high heat, breaking it up, until cooked and slightly caramelised, about 4 minutes.","Add both soy sauces, oyster sauce and sugar with a splash of water and toss to glaze.","Kill the heat and fold through the basil until just wilted.","Serve over rice topped with a fried egg."],"pairing":"Ice-cold lager or lime soda","tags":["Spicy","Quick","One-pan","Comfort"],"vegetarian":false,"spicy":true,"calories":620,"protein":38,"carbs":52,"fat":29,"allergens":["Fish","Shellfish","Soy","Gluten","Egg"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-tofu-veg-stirfry","name":"Tofu and Vegetable Stir-fry with Sweet Chilli","category":"Curries & Stir-fry","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"A meat-free workhorse: golden pan-fried tofu and crunchy mixed vegetables in a sweet-chilli and soy glaze. Vegan, fast and endlessly flexible with whatever vegetables are in the drawer.","ingredients":["300g firm tofu, in cubes","200g tenderstem broccoli or green beans","1 carrot, sliced","1 red pepper, sliced","3 garlic cloves, chopped","3 tbsp sweet chilli sauce","2 tbsp light soy sauce","1 tsp rice vinegar","2 tbsp neutral oil","1 tbsp cornflour"],"steps":["Toss the tofu cubes in the cornflour to coat.","Heat the oil in a wok and fry the tofu until golden on all sides, then lift out.","Add the garlic, broccoli, carrot and pepper and stir-fry 3 to 4 minutes until crisp-tender.","Mix the sweet chilli sauce, soy and vinegar with a splash of water.","Return the tofu, pour over the sauce and toss to glaze for 1 minute.","Serve over rice or noodles."],"pairing":"Steamed rice and cold coconut water","tags":["Vegetarian","Vegan","Quick","One-pan","Gluten-free option","Comfort"],"vegetarian":true,"spicy":false,"calories":390,"protein":18,"carbs":33,"fat":21,"allergens":["Soy","Gluten"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-massaman-beef","name":"Massaman Beef Curry","category":"Curries & Stir-fry","course":"Main","meal":"dinner","tier":"signature","inspiration":"Nahm (David Thompson)","minutes":150,"serves":4,"level":"Project","idea":"A slow, Muslim-influenced southern curry layered with warm spice, tamarind and roasted peanuts, in the painstaking style David Thompson made famous at Nahm. The long braise melts the beef while cinnamon and cardamom perfume the coconut sauce into something deep and almost stew-like.","ingredients":["800g beef shin or chuck, in large chunks","400ml coconut milk","200ml coconut cream","4 tbsp massaman curry paste","3 tbsp fish sauce","2 tbsp palm sugar","2 tbsp tamarind paste","3 waxy potatoes, in chunks","1 onion, in wedges","80g roasted unsalted peanuts","1 cinnamon stick","3 cardamom pods, bruised","2 bay leaves"],"steps":["Fry the coconut cream in a heavy pot over medium heat until it splits and the oil surfaces, then add the massaman paste and fry 4 minutes until aromatic.","Add the beef and turn to coat, sealing the surfaces for a few minutes.","Pour in the coconut milk and 300ml water, then add cinnamon, cardamom and bay. Bring to a gentle simmer.","Cover and braise low for 1.5 hours until the beef is starting to turn tender.","Add potatoes, onion and peanuts and cook uncovered another 30 to 40 minutes until potatoes are soft and sauce has thickened.","Season with fish sauce, palm sugar and tamarind, balancing sweet, salty and sour. Rest 10 minutes before serving with rice."],"pairing":"Soft Grenache or a malty amber ale","tags":["Make-ahead","Gluten-free option","Comfort","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":720,"protein":48,"carbs":34,"fat":44,"allergens":["Fish","Peanut","Sulphites"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-green-curry-chicken","name":"Gaeng Keow Wan Gai (Thai Green Chicken Curry)","category":"Curries & Stir-fry","course":"Main","meal":"both","tier":"signature","inspiration":"Nahm (David Thompson)","minutes":40,"serves":4,"level":"Weekend","idea":"The benchmark Thai curry done the Nahm way: a fragrant green paste fried in cracked coconut cream until the fat surfaces, then balanced sweet, salty and hot. Splitting the cream and frying the paste hard is what separates a great version from a muddy, flat one.","ingredients":["600g boneless chicken thigh, sliced","400ml coconut milk","150ml coconut cream (skimmed from the top of a second tin)","4 tbsp green curry paste","2 tbsp fish sauce","1 tbsp palm sugar, grated","3 makrut lime leaves, torn","1 large Thai aubergine or 6 pea aubergines, quartered","100g bamboo shoots, drained","1 long red chilli, sliced","Large handful Thai basil leaves"],"steps":["Heat the coconut cream in a wide pan over medium heat until it bubbles and the oil starts to separate, about 4 minutes.","Add the green curry paste and fry hard in the split cream for 3 to 4 minutes until deeply fragrant and the fat surfaces around the paste.","Add the chicken and stir to coat, cooking 3 minutes until it turns opaque at the edges.","Pour in the coconut milk and 100ml water, then add lime leaves, aubergine and bamboo shoots. Simmer 12 to 15 minutes until chicken is cooked through and aubergine is tender.","Season with fish sauce and palm sugar, tasting for a salty-sweet-hot balance.","Off the heat, stir through Thai basil and scatter sliced chilli. Serve with jasmine rice."],"pairing":"Off-dry Riesling or jasmine rice and a cold Singha beer","tags":["Spicy","One-pan","Gluten-free option","Crowd-pleaser","Comfort"],"vegetarian":false,"spicy":true,"calories":450,"protein":32,"carbs":13,"fat":30,"allergens":["Fish"],"role":"main","cuisineKey":"thai","type":"Curry"},{"id":"th-pad-thai-goong","name":"Pad Thai Goong (Prawn Pad Thai)","category":"Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"The dish everyone knows, done properly: rice noodles tossed in a tamarind-palm sugar sauce until glossy and chewy, with sweet prawns, egg and a crunch of crushed peanuts. A jar of ready-made pad thai sauce makes this even faster on a busy night.","ingredients":["180g flat rice noodles (5mm)","200g raw prawns, peeled","2 eggs","100g firm tofu, diced","3 tbsp tamarind paste","2.5 tbsp palm sugar","2 tbsp fish sauce","100g beansprouts","3 spring onions, in batons","40g roasted peanuts, crushed","2 tbsp neutral oil","1 lime, in wedges"],"steps":["Soak the rice noodles in warm water for 20 minutes until pliable but not soft, then drain.","Whisk tamarind, palm sugar and fish sauce into a smooth sauce; taste for a sour-sweet-salty balance.","Heat oil in a wok, fry tofu until golden, then add prawns and cook until just pink. Push aside.","Crack in the eggs, scramble lightly, then add the drained noodles and the sauce.","Toss constantly over high heat 2 to 3 minutes until noodles absorb the sauce and turn glossy; add a splash of water if they tighten.","Throw in beansprouts and spring onions, toss briefly, then plate with peanuts and lime."],"pairing":"Crisp Sauvignon Blanc or Thai iced tea","tags":["Quick","Gluten-free option","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":620,"protein":33,"carbs":78,"fat":20,"allergens":["Fish","Shellfish","Egg","Soy","Peanut"],"role":"main","cuisineKey":"thai","type":"Noodles & Ramen"},{"id":"th-pad-see-ew","name":"Pad See Ew (Soy-fried Wide Noodles)","category":"Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"Smoky, savoury and comforting: wide rice noodles charred in a hot wok with chicken, egg and Chinese broccoli in a dark-and-light soy glaze. All about wok hei, the elusive breath of the wok.","ingredients":["400g fresh wide rice noodles (or 180g dried, soaked)","250g chicken thigh, sliced","2 eggs","200g Chinese broccoli (gai lan), cut into batons","3 garlic cloves, chopped","2 tbsp dark soy sauce","1.5 tbsp light soy sauce","1 tbsp oyster sauce","1 tsp sugar","2.5 tbsp neutral oil","White pepper, to finish"],"steps":["If using fresh noodles, gently separate the strands. Mix both soys, oyster sauce and sugar in a bowl.","Heat a wok until smoking, add oil and garlic, then the chicken, stir-frying until cooked through.","Push to one side, crack in the eggs and scramble lightly.","Add the gai lan stems first, then the leaves, tossing 1 minute until bright green.","Add the noodles and sauce, then leave them to sit against the hot wok for 20 seconds at a time before tossing, to build char and smokiness.","Stir-fry 2 to 3 minutes until noodles are glossy and the edges slightly crisp. Finish with white pepper."],"pairing":"Lager or chrysanthemum tea","tags":["Quick","One-pan","Comfort"],"vegetarian":false,"spicy":false,"calories":640,"protein":33,"carbs":74,"fat":24,"allergens":["Gluten","Fish","Shellfish","Soy","Egg"],"role":"main","cuisineKey":"thai","type":"Noodles & Ramen"},{"id":"th-singapore-noodles","name":"Singapore-style Curry Noodles","category":"Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Thin rice vermicelli tossed with curry powder, prawns, egg and crunchy vegetables until everything is fragrant and golden. A fast, one-wok dinner that uses pantry curry powder for big flavour with little effort.","ingredients":["150g rice vermicelli","150g raw prawns, peeled","2 eggs, beaten","1 red pepper, sliced","2 spring onions, sliced","1 carrot, julienned","100g beansprouts","2 tbsp curry powder","2 tbsp light soy sauce","1 tsp sugar","2 tbsp neutral oil"],"steps":["Soak the vermicelli in hot water for 4 minutes until soft, then drain well.","Heat the oil in a wok, pour in the beaten egg and scramble, then push to one side.","Add the prawns, pepper and carrot and stir-fry 2 minutes until the prawns turn pink.","Sprinkle in the curry powder and toss 30 seconds until fragrant.","Add the noodles, soy sauce and sugar and toss over high heat until evenly coated and golden.","Stir through the beansprouts and spring onions and serve at once."],"pairing":"Cold lager or iced lemongrass tea","tags":["Quick","One-pan","Gluten-free option","Lunchbox"],"vegetarian":false,"spicy":true,"calories":480,"protein":24,"carbs":58,"fat":17,"allergens":["Shellfish","Egg","Gluten","Soy"],"role":"main","cuisineKey":"thai","type":"Noodles & Ramen"},{"id":"th-pad-woon-sen-veg","name":"Pad Woon Sen (Glass Noodle Stir-fry)","category":"Noodles","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"Springy glass noodles stir-fried with egg, mixed vegetables and a light soy seasoning. Naturally meat-free and quick, it is a soothing bowl that even fussy eaters tend to like.","ingredients":["120g dried glass (mung bean) noodles","2 eggs, beaten","3 garlic cloves, chopped","1 carrot, julienned","100g cabbage, shredded","3 spring onions, sliced","1 tomato, in wedges","2 tbsp light soy sauce","1 tbsp oyster sauce or vegetarian stir-fry sauce","1 tsp sugar","2 tbsp neutral oil"],"steps":["Soak the glass noodles in warm water for 8 minutes until soft, then drain and snip into shorter lengths.","Heat the oil in a wok, add the garlic, then pour in the egg and scramble lightly.","Add the carrot, cabbage and tomato and stir-fry 2 minutes until softened.","Add the noodles, soy sauce, oyster sauce and sugar with a splash of water.","Toss over high heat until the noodles soak up the sauce and turn glossy.","Stir through the spring onions and serve."],"pairing":"Jasmine tea or a light lager","tags":["Vegetarian","Quick","One-pan","Gluten-free option","Comfort"],"vegetarian":true,"spicy":false,"calories":420,"protein":12,"carbs":60,"fat":15,"allergens":["Egg","Shellfish","Gluten","Soy"],"role":"main","cuisineKey":"thai","type":"Noodles & Ramen"},{"id":"th-khao-soi-gai","name":"Khao Soi Gai (Northern Curry Noodle Soup)","category":"Noodles","course":"Main","meal":"both","tier":"signature","inspiration":"Le Du (Thitid Tassanakajohn)","minutes":60,"serves":4,"level":"Weekend","idea":"Chiang Mai's signature bowl, the dish Andy Ricker built Pok Pok's reputation on: a rich, turmeric-gold coconut curry broth over soft egg noodles, crowned with a tangle of crisp fried noodles, with pickled mustard greens, shallot and lime alongside. Deep, creamy and layered.","ingredients":["8 bone-in chicken thighs or drumsticks","500g fresh egg noodles (reserve 100g for frying)","400ml coconut milk","200ml coconut cream","4 tbsp khao soi or red curry paste","1 tbsp ground turmeric","1 tbsp curry powder","3 tbsp fish sauce","1 tbsp palm sugar","600ml chicken stock","Pickled mustard greens, sliced shallot and lime wedges, to serve","Neutral oil for frying"],"steps":["Fry 100g of the egg noodles in hot oil until golden and crisp, then drain on paper for the topping.","In a pot, fry the coconut cream until split, add the curry paste, turmeric and curry powder, frying 4 minutes until fragrant.","Add the chicken and turn to coat, then pour in the coconut milk and stock.","Simmer gently 30 to 35 minutes until the chicken is tender and the broth is rich and golden.","Season with fish sauce and palm sugar, adjusting to a rounded salty-sweet curry flavour.","Boil the remaining egg noodles until just tender, divide into bowls, ladle over broth and chicken, then top with crispy noodles. Serve with mustard greens, shallot and lime."],"pairing":"Off-dry Gewürztraminer or a wheat beer","tags":["Make-ahead","Comfort","Crowd-pleaser","Spicy"],"vegetarian":false,"spicy":true,"calories":720,"protein":42,"carbs":48,"fat":40,"allergens":["Gluten","Egg","Fish","Mustard"],"role":"main","cuisineKey":"thai","type":"Noodles & Ramen"},{"id":"th-som-tam","name":"Som Tam Thai (Green Papaya Salad)","category":"Salads & Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":2,"level":"Weeknight","idea":"The pounded Isaan classic: crunchy green papaya bruised in a mortar with chilli, garlic, lime, fish sauce and palm sugar, lifted by sweet tomatoes and salty dried shrimp. Fiery, fresh and dangerously addictive. Swap papaya for shredded carrot if it is hard to find.","ingredients":["300g green papaya, peeled and shredded","2 garlic cloves","3 Thai bird's eye chillies","8 cherry tomatoes, halved","30g long beans, in 3cm pieces","2 tbsp fish sauce","2 tbsp lime juice","1.5 tbsp palm sugar","1 tbsp dried shrimp","2 tbsp roasted peanuts","1 tsp tamarind paste"],"steps":["Pound the garlic and chillies in a large mortar to a coarse paste.","Add palm sugar, fish sauce, lime juice and tamarind, pounding lightly to dissolve the sugar.","Add the long beans and dried shrimp and bruise them gently to release their flavour.","Add the tomatoes and crush just until they weep their juice.","Add the shredded papaya and peanuts, then pound and turn with a spoon so the papaya softens slightly and soaks up the dressing.","Taste for the signature hot-sour-salty-sweet balance and serve immediately, while crunchy."],"pairing":"Sticky rice and grilled chicken, or a cold light lager","tags":["Spicy","Quick","Light","Gluten-free option"],"vegetarian":false,"spicy":true,"calories":160,"protein":6,"carbs":22,"fat":6,"allergens":["Fish","Shellfish","Peanut"],"role":"salad","cuisineKey":"thai","type":"Salads"},{"id":"th-larb-gai","name":"Larb Gai (Isaan Chicken Larb)","category":"Salads & Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"A warm minced-chicken salad from the northeast, lifted with lime and fish sauce and given a nutty crunch by toasted rice powder, tangled with shallot, mint and coriander. Bright, savoury and intensely herby.","ingredients":["300g minced chicken","2 tbsp uncooked sticky rice (for toasted rice powder)","2.5 tbsp lime juice","2 tbsp fish sauce","1 tsp palm sugar","1 tsp roasted chilli flakes (prik bon)","2 shallots, thinly sliced","3 spring onions, sliced","Large handful mint leaves","Large handful coriander, chopped","60ml chicken stock or water"],"steps":["Toast the sticky rice in a dry pan over medium heat until golden brown and fragrant, then grind to a coarse powder in a mortar.","Simmer the chicken in the stock over medium heat, breaking it up, until just cooked through, about 5 minutes; do not let it dry out.","Take off the heat and dress while warm with lime juice, fish sauce, palm sugar and chilli flakes.","Stir through the shallots, spring onions and most of the toasted rice powder.","Fold in the mint and coriander just before serving so they stay fresh.","Taste for a sharp, salty, mildly hot balance and finish with the remaining rice powder. Serve with sticky rice and raw vegetables."],"pairing":"Sticky rice and a crisp Riesling or cold beer","tags":["Spicy","Quick","Light","Gluten-free option"],"vegetarian":false,"spicy":true,"calories":260,"protein":30,"carbs":10,"fat":11,"allergens":["Fish"],"role":"salad","cuisineKey":"thai","type":"Salads"},{"id":"th-thai-cucumber-salad","name":"Thai Cucumber Salad","category":"Salads & Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":2,"level":"Weeknight","idea":"A cooling five-minute side: crisp cucumber and red onion in a sweet-sour lime and chilli dressing, scattered with peanuts and coriander. Mild, refreshing and the perfect foil for anything spicy on the table.","ingredients":["1 large cucumber, sliced","1/2 red onion, thinly sliced","2 tbsp lime juice","1 tbsp fish sauce","1 tbsp sugar","1 small red chilli, sliced (optional)","2 tbsp roasted peanuts, crushed","Handful coriander, chopped"],"steps":["Whisk the lime juice, fish sauce and sugar until the sugar dissolves.","Add the chilli to the dressing if using.","Toss the cucumber and red onion in the dressing.","Let it sit 5 minutes so the flavours mingle.","Scatter with peanuts and coriander just before serving."],"pairing":"Anything grilled, or a cold lager","tags":["Quick","Light","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":110,"protein":4,"carbs":13,"fat":5,"allergens":["Fish","Peanut"],"role":"salad","cuisineKey":"thai","type":"Salads"},{"id":"th-spring-rolls","name":"Fresh Vegetable Summer Rolls with Peanut Dip","category":"Salads & Small plates","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"No-cook rice-paper rolls packed with crunchy vegetables, herbs and noodles, served with a creamy peanut dipping sauce. A fun, hands-on plate kids love to help build, and naturally light.","ingredients":["8 rice paper wrappers","60g rice vermicelli","1 carrot, julienned","1/2 cucumber, julienned","1 small lettuce, shredded","Handful mint and coriander leaves","3 tbsp smooth peanut butter","1 tbsp soy sauce","1 tbsp lime juice","1 tsp honey","Warm water to loosen"],"steps":["Soak the vermicelli in hot water for 4 minutes, drain and cool under cold water.","Whisk the peanut butter, soy, lime juice and honey with warm water until it is a smooth dip.","Dip a rice paper wrapper in warm water for a few seconds until pliable, then lay on a board.","Pile a little of each vegetable, the herbs and noodles in the centre.","Fold in the sides and roll up tightly like a small parcel.","Repeat with the rest and serve with the peanut dip."],"pairing":"Iced green tea or coconut water","tags":["Vegetarian","Light","Quick","Lunchbox","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":340,"protein":11,"carbs":42,"fat":15,"allergens":["Peanut","Soy"],"role":"appetizer","cuisineKey":"thai","type":"Starters"},{"id":"th-tom-yum-goong","name":"Tom Yum Goong (Hot and Sour Prawn Soup)","category":"Salads & Small plates","course":"Starter","meal":"both","tier":"signature","inspiration":"Nahm (David Thompson)","minutes":35,"serves":4,"level":"Weekend","idea":"Thailand's most famous soup, treated with the aromatic precision David Thompson brought to Nahm: a clear, electric broth singing with lemongrass, galangal, makrut lime and chilli, sharpened with lime and rounded out by plump prawns. Aromatic, sour and invigorating.","ingredients":["400g raw prawns, peeled, shells reserved","1.2 litres water or light stock","2 lemongrass stalks, bruised and sliced","4 slices galangal","5 makrut lime leaves, torn","200g oyster or straw mushrooms, halved","4 Thai bird's eye chillies, bruised","3 tbsp fish sauce","4 tbsp lime juice","1 tbsp nam prik pao (roasted chilli paste)","1 tomato, in wedges","Handful coriander leaves"],"steps":["Simmer the prawn shells in the water for 10 minutes to build a quick stock, then strain and return to the pan.","Add lemongrass, galangal, lime leaves and chillies, and simmer 5 minutes to infuse.","Add the mushrooms and tomato and cook 2 minutes until softened.","Add the prawns and cook just until they turn pink, about 2 minutes; do not overcook.","Take off the heat and season with fish sauce, nam prik pao and lime juice, balancing hot, sour and salty.","Scatter with coriander and serve immediately, while fragrant and steaming."],"pairing":"Dry Riesling or chilled jasmine tea","tags":["Spicy","Light","Gluten-free option","Crowd-pleaser"],"vegetarian":false,"spicy":true,"calories":140,"protein":20,"carbs":8,"fat":3,"allergens":["Fish","Shellfish"],"role":"appetizer","cuisineKey":"thai","type":"Starters"},{"id":"th-tod-man-pla","name":"Tod Man Pla (Thai Fish Cakes with Cucumber Relish)","cuisineKey":"thai","category":"Salads & Small plates","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Bouncy red-curry fish cakes flecked with long beans and lime leaf, fried until springy and served with a sweet-sour cucumber relish.","ingredients":["400g skinless white fish fillet (cod or pollock), roughly chopped","2 tbsp red curry paste","1 tbsp fish sauce","1 egg","60g long beans, very thinly sliced","4 makrut lime leaves, finely shredded","1 tsp sugar","Neutral oil for shallow frying","1 cucumber, quartered and sliced","3 tbsp rice vinegar","2 tbsp sugar (for relish)","1 small red chilli, sliced","2 tbsp roasted peanuts, crushed"],"steps":["Blitz the fish, red curry paste, fish sauce, egg and 1 tsp sugar to a sticky paste.","Mix in the long beans and shredded lime leaves by hand.","Wet your hands and shape into 12 small flat patties.","Shallow fry in hot oil for 2 to 3 minutes each side until golden and springy. Drain.","For the relish, warm the rice vinegar with 2 tbsp sugar until dissolved, cool, then add cucumber and chilli.","Serve the fish cakes hot with the relish and a scatter of crushed peanuts."],"pairing":"Steamed jasmine rice or a cold Singha","tags":["seafood","fried","crowd-pleaser","make-ahead"],"vegetarian":false,"spicy":true,"calories":280,"protein":24,"carbs":14,"fat":14,"allergens":["Fish","Egg","Peanut"],"type":"Starters"},{"id":"th-satay-gai","name":"Gai Satay (Grilled Chicken Skewers with Peanut Sauce)","cuisineKey":"thai","category":"Salads & Small plates","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":4,"level":"Weeknight","idea":"Turmeric-marinated chicken skewers grilled over high heat, served with a glossy peanut sauce and quick cucumber pickle.","ingredients":["500g chicken thigh, cut into strips","1 tsp ground turmeric","1 tsp ground coriander","1 tsp ground cumin","100ml coconut milk","1 tbsp fish sauce","1 tbsp brown sugar","3 tbsp smooth peanut butter","2 tbsp red curry paste","150ml coconut milk (for sauce)","1 tbsp tamarind paste","1 tbsp palm sugar","8 to 10 bamboo skewers, soaked"],"steps":["Mix turmeric, coriander, cumin, 100ml coconut milk, fish sauce and brown sugar. Marinate the chicken for at least 30 minutes.","Thread the chicken onto soaked skewers.","For the sauce, gently simmer red curry paste in a little of the 150ml coconut milk, then stir in peanut butter, the rest of the coconut milk, tamarind and palm sugar until glossy.","Grill or griddle the skewers over high heat for 3 to 4 minutes a side until charred and cooked through.","Serve hot with the warm peanut sauce for dipping."],"pairing":"Cucumber relish and steamed rice","tags":["grilled","skewers","kid-friendly","make-ahead"],"vegetarian":false,"spicy":false,"calories":360,"protein":30,"carbs":12,"fat":21,"allergens":["Peanut","Fish"],"type":"Starters"},{"id":"th-miang-kham","name":"Miang Kham (Betel Leaf One-bite Wraps)","cuisineKey":"thai","category":"Salads & Small plates","role":"appetizer","course":"Starter","meal":"both","tier":"signature","inspiration":"Sorn (Supaksorn Jongsiri)","minutes":30,"serves":4,"level":"Weekend","idea":"A do-it-yourself royal Thai snack: each leaf is topped with toasted coconut, ginger, lime, peanuts and a dark palm-sugar tamarind sauce for a single explosive bite.","ingredients":["20 wild betel or baby spinach leaves","60g desiccated coconut, toasted","2 shallots, finely diced","2cm ginger, finely diced","1 lime, cut into tiny cubes with skin on","40g roasted peanuts","2 tbsp dried shrimp","2 red chillies, finely diced","120g palm sugar","2 tbsp tamarind paste","2 tbsp fish sauce","1 tbsp toasted coconut (for sauce)"],"steps":["Make the sauce: melt palm sugar with 4 tbsp water, then add tamarind, fish sauce and 1 tbsp toasted coconut. Simmer to a thick pourable syrup and cool.","Arrange the toasted coconut, shallots, ginger, lime cubes, peanuts, dried shrimp and chilli in small piles.","To eat, fold a leaf into a cone, add a pinch of each topping, then a drizzle of the sauce.","Serve as a help-yourself platter so each person builds their own bite."],"pairing":"Chilled jasmine tea","tags":["royal-thai","sharing","no-cook-assembly","gluten-free"],"vegetarian":false,"spicy":true,"calories":190,"protein":5,"carbs":28,"fat":8,"allergens":["Shellfish","Fish","Peanut"],"type":"Starters"},{"id":"th-yam-talay","name":"Yam Talay (Hot and Sour Seafood Salad)","cuisineKey":"thai","category":"Salads & Small plates","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"Poached prawns and squid tossed with celery, tomato and red onion in a punchy lime, fish sauce and chilli dressing.","ingredients":["200g raw prawns, peeled","150g squid, cleaned and sliced into rings","1 stick Chinese celery, sliced","1 tomato, cut into wedges","1/2 red onion, thinly sliced","3 spring onions, sliced","3 tbsp lime juice","2 tbsp fish sauce","1 tsp sugar","2 Thai bird's eye chillies, sliced","2 garlic cloves, minced","Handful coriander leaves"],"steps":["Bring a pan of water to a simmer and poach the prawns and squid for 1 to 2 minutes until just opaque. Drain and cool.","Whisk lime juice, fish sauce, sugar, chilli and garlic into a sharp dressing.","Combine the seafood with celery, tomato, red onion and spring onion.","Pour over the dressing and toss gently.","Finish with coriander and serve at room temperature."],"pairing":"Steamed jasmine rice","tags":["seafood","light","gluten-free","high-protein"],"vegetarian":false,"spicy":true,"calories":170,"protein":24,"carbs":9,"fat":3,"allergens":["Shellfish","Fish"],"type":"Salads"},{"id":"th-yam-woon-sen","name":"Yam Woon Sen (Glass Noodle Salad)","cuisineKey":"thai","category":"Salads & Small plates","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Slippery glass noodles tossed with minced pork, prawns, tomato and herbs in a bright lime dressing, a Thai lunch-counter classic.","ingredients":["80g dried glass (mung bean) noodles","150g minced pork","100g raw prawns, peeled","1 tomato, in wedges","1/2 red onion, thinly sliced","3 spring onions, sliced","2 tbsp roasted peanuts","3 tbsp lime juice","2 tbsp fish sauce","1 tsp sugar","2 bird's eye chillies, sliced","Handful coriander, chopped"],"steps":["Soak the glass noodles in hot water for 5 minutes until soft, drain and cut into shorter lengths.","Poach the minced pork and prawns in simmering water until just cooked, then drain.","Whisk lime juice, fish sauce, sugar and chilli into a dressing.","Toss the noodles, pork, prawns, tomato, red onion and spring onion with the dressing.","Top with peanuts and coriander and serve."],"pairing":"Grilled chicken skewers","tags":["noodle-salad","light","high-protein","make-ahead"],"vegetarian":false,"spicy":true,"calories":250,"protein":20,"carbs":28,"fat":7,"allergens":["Shellfish","Fish","Peanut"],"type":"Salads"},{"id":"th-pomelo-salad","name":"Yam Som-O (Pomelo and Prawn Salad)","cuisineKey":"thai","category":"Salads & Small plates","role":"salad","course":"Starter","meal":"both","tier":"signature","inspiration":"Le Du (Thitid Tassanakajohn)","minutes":35,"serves":4,"level":"Weekend","idea":"Jewel-like pomelo segments with prawns, toasted coconut and crispy shallots in a tamarind-palm sugar dressing, balanced sweet, sour and savoury.","ingredients":["1 large pomelo, segmented and broken into pieces","200g raw prawns, peeled","40g desiccated coconut, toasted","30g roasted peanuts, crushed","2 tbsp crispy fried shallots","2 tbsp tamarind paste","1.5 tbsp palm sugar","1.5 tbsp fish sauce","1 tbsp lime juice","1 red chilli, finely sliced","Handful mint leaves"],"steps":["Warm the tamarind, palm sugar and fish sauce gently until the sugar dissolves, then cool and add lime juice and chilli.","Poach the prawns in simmering water for 1 to 2 minutes until just opaque, drain and cool.","Gently fold the pomelo, prawns and most of the toasted coconut with the dressing, keeping the segments intact.","Pile onto a plate and top with peanuts, crispy shallots, remaining coconut and mint."],"pairing":"Chilled coconut water","tags":["fruit-salad","seafood","gluten-free","special-occasion"],"vegetarian":false,"spicy":true,"calories":230,"protein":16,"carbs":24,"fat":8,"allergens":["Shellfish","Fish","Peanut"],"type":"Salads"},{"id":"fr-poulet-moutarde","name":"Creamy Mustard Chicken","category":"Bistro mains","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Golden seared chicken thighs simmered in a quick Dijon and creme fraiche sauce, all in one pan. Bistro comfort that lands on the table in the time it takes to boil the kids' pasta.","ingredients":["8 boneless chicken thighs, skin on","2 tbsp Dijon mustard","1 tbsp wholegrain mustard","200 ml creme fraiche or double cream","200 ml chicken stock","1 onion, finely chopped","2 cloves garlic, crushed","1 tbsp olive oil","2 sprigs thyme","Salt and black pepper"],"steps":["Season the chicken and sear skin-side down in the oil over medium-high heat until deep golden, about 6 minutes, then turn and brown the other side. Lift out.","Soften the onion and garlic in the same pan with the thyme until translucent.","Stir in both mustards and the stock, scraping up the browned bits, then return the chicken skin-side up.","Simmer gently for 12 to 15 minutes until the chicken is cooked through.","Stir the creme fraiche into the sauce, season, and warm through without boiling hard.","Serve with rice, mash or crusty bread to catch the sauce."],"pairing":"A glass of unoaked Chardonnay","tags":["Quick","One-pan","Comfort","Crowd-pleaser","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":520,"protein":34,"carbs":6,"fat":40,"allergens":["Milk","Mustard"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-poulet-basquaise","name":"Poulet Basquaise","category":"Bistro mains","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":4,"level":"Weeknight","idea":"Chicken braised with sweet peppers, tomatoes and a whisper of paprika in the sunny Basque style. One pot, common ingredients, and a sauce the whole family scoops up with bread.","ingredients":["8 boneless chicken thighs","2 red peppers, sliced","1 green pepper, sliced","1 onion, sliced","3 cloves garlic, crushed","400 g tin chopped tomatoes","1 tbsp tomato paste","1 tsp sweet paprika","2 tbsp olive oil","1 bay leaf","Salt and black pepper"],"steps":["Season and brown the chicken in the oil over medium-high heat until golden on both sides, then lift out.","Soften the onion, peppers and garlic in the same pan until they begin to colour.","Stir in the tomato paste and paprika for a minute, then add the chopped tomatoes and bay leaf.","Return the chicken, season, and simmer gently for 20 to 25 minutes until cooked through and the sauce has thickened.","Check the seasoning and serve with rice or crusty bread."],"pairing":"A glass of red Irouleguy or a light Rioja","tags":["One-pan","Comfort","Crowd-pleaser","Gluten-free option","Make-ahead"],"vegetarian":false,"spicy":false,"calories":390,"protein":33,"carbs":14,"fat":22,"allergens":[],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-saumon-en-papillote","name":"Salmon en Papillote with Leeks","category":"Bistro mains","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":4,"level":"Weeknight","idea":"Salmon steamed in paper parcels with leeks, lemon and a splash of white wine. Almost no washing up and nearly impossible to overcook, so it suits a busy night.","ingredients":["4 salmon fillets, about 150 g each","2 leeks, finely sliced","1 lemon, sliced","4 knobs of butter","4 tbsp dry white wine or stock","2 sprigs dill or tarragon","Salt and black pepper"],"steps":["Heat the oven to 200C. Cut four large squares of baking parchment.","Divide the sliced leeks among the squares and sit a salmon fillet on each.","Top each with lemon slices, a knob of butter, a herb sprig, a tablespoon of wine, salt and pepper.","Fold the parchment into sealed parcels, leaving room for steam.","Bake on a tray for 14 to 16 minutes until the salmon is just cooked.","Open the parcels at the table and serve with new potatoes or rice."],"pairing":"A cool glass of Sancerre","tags":["Quick","Light","Gluten-free option","Date night"],"vegetarian":false,"spicy":false,"calories":380,"protein":31,"carbs":6,"fat":25,"allergens":["Fish","Milk","Sulphites"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-steak-frites","name":"Steak Frites","category":"Bistro mains","course":"Main","meal":"dinner","tier":"easy","inspiration":"","minutes":35,"serves":2,"level":"Weeknight","idea":"The bistro plate made weeknight-simple: a quick-seared steak with oven-crisp fries and a fast pan sauce built on the steak's own browned juices. No deep-frying, no fuss.","ingredients":["2 sirloin steaks, about 200 g each","600 g potatoes, cut into chips","2 tbsp olive oil","20 g butter","1 shallot, finely chopped","100 ml beef stock","1 tsp Dijon mustard","1 tbsp chopped parsley","Salt and black pepper"],"steps":["Heat the oven to 220C. Toss the chips with 1 tbsp oil and salt, spread on a tray and bake for 25 to 30 minutes, turning once, until crisp and golden.","Pat the steaks dry and season well. Sear in the remaining oil over high heat for 2 to 3 minutes per side for medium-rare, then rest on a board.","In the same pan soften the shallot in the butter, add the stock and mustard, and simmer until lightly thickened. Stir in any resting juices and the parsley.","Slice the steaks, spoon over the sauce and serve with the fries and a green salad."],"pairing":"A bold Cotes du Rhone rouge","tags":["Comfort","Date night","Gluten-free option"],"vegetarian":false,"spicy":false,"calories":780,"protein":48,"carbs":52,"fat":42,"allergens":["Milk","Mustard"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-coq-au-vin","name":"Coq au Vin","category":"Bistro mains","course":"Main","meal":"dinner","tier":"signature","inspiration":"Bouchon (Thomas Keller)","minutes":120,"serves":4,"level":"Project","idea":"Chicken braised slowly in red wine with lardons, mushrooms and pearl onions until the sauce turns deep, glossy and silky. The Lyonnais standard codified by Paul Bocuse, rewarding patience and tasting even better the next day.","ingredients":["1 large chicken, about 1.8 kg, jointed into 8 pieces","750 ml red Burgundy or Pinot Noir","150 g smoked lardons or thick bacon, diced","250 g button mushrooms, halved","200 g pearl onions, peeled","2 tbsp plain flour","3 cloves garlic, crushed","2 bay leaves and 4 sprigs thyme","400 ml chicken stock","40 g unsalted butter","2 tbsp olive oil","Salt and black pepper"],"steps":["Marinate the chicken in the wine with the herbs and garlic for at least 4 hours, ideally overnight. Drain, reserving the wine, and pat the pieces dry.","Render the lardons in a casserole until crisp, then set aside. Brown the chicken in the rendered fat plus a little oil on all sides until deeply coloured, working in batches.","Dust the chicken with flour, return the lardons, then pour in the reserved wine and stock. Add the herbs, season, and braise gently, covered, for about 1 hour until the meat is tender and pulling from the bone.","Meanwhile, brown the pearl onions and mushrooms in the butter until golden, then add them to the pot for the final 20 minutes.","Lift out the chicken and vegetables, reduce the sauce until it coats the back of a spoon, and check the seasoning.","Return everything to the sauce to warm through and serve with mashed potato or buttered noodles."],"pairing":"The same red Burgundy used in the braise","tags":["Make-ahead","Comfort","Crowd-pleaser","Date night"],"vegetarian":false,"spicy":false,"calories":680,"protein":48,"carbs":16,"fat":42,"allergens":["Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-boeuf-bourguignon","name":"Boeuf Bourguignon","category":"Bistro mains","course":"Main","meal":"dinner","tier":"signature","inspiration":"Alain Ducasse","minutes":180,"serves":4,"level":"Project","idea":"Beef braised for hours in red wine with bacon, mushrooms and onions until the meat collapses at a fork and the sauce glosses like lacquer. The dish Julia Child called the finest beef stew known to man, all about deep browning and slow time.","ingredients":["1.2 kg beef chuck or shin, cut into 4 cm cubes","750 ml red Burgundy or other dry red","150 g smoked lardons, diced","250 g chestnut mushrooms, quartered","200 g pearl onions, peeled","2 carrots, cut into chunks","3 cloves garlic, crushed","2 tbsp tomato paste","2 tbsp plain flour","500 ml beef stock","Bouquet garni of thyme, parsley and bay","40 g butter and 2 tbsp oil","Salt and black pepper"],"steps":["Pat the beef very dry, season, and brown hard in batches in the oil until each piece is dark on all sides. Remove and reserve.","Render the lardons, soften the carrots, then stir in the tomato paste and flour and cook for a minute.","Deglaze with the wine, scraping the base clean, then return the beef with the stock, garlic and bouquet garni. Bring to a bare simmer.","Cover and braise in a 150C oven for about 2.5 hours until the beef is fork-tender.","Brown the pearl onions and mushrooms in the butter, then fold them in for the last 30 minutes.","Skim any fat, reduce the sauce on the hob if it is loose, adjust the seasoning, and serve with mash or boiled potatoes."],"pairing":"A structured Cote de Beaune or Cotes du Rhone","tags":["Make-ahead","Comfort","Crowd-pleaser","Date night"],"vegetarian":false,"spicy":false,"calories":720,"protein":62,"carbs":20,"fat":40,"allergens":["Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-omelette-fines-herbes","name":"Omelette aux Fines Herbes","category":"Brasserie classics","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":1,"level":"Weeknight","idea":"The pure French omelette: eggs beaten with fresh herbs, cooked fast in butter and rolled while still creamy inside. A five-minute lunch that feels like a treat.","ingredients":["3 eggs","1 tbsp chopped chives","1 tbsp chopped parsley","1 tsp chopped tarragon, optional","15 g unsalted butter","Salt and black pepper"],"steps":["Beat the eggs with the herbs, salt and pepper until just combined.","Melt the butter in a non-stick pan over medium-high heat until foaming.","Pour in the eggs and stir briskly with a fork for a few seconds, then let the base set.","Tilt the pan and fold the omelette over itself into a neat roll.","Slide onto a plate, seam-side down, and serve at once with a green salad or bread."],"pairing":"A light glass of Chablis","tags":["Quick","Vegetarian","Light","Gluten-free option"],"vegetarian":true,"spicy":false,"calories":340,"protein":19,"carbs":2,"fat":29,"allergens":["Egg","Milk"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-salade-nicoise","name":"Salade Nicoise","category":"Brasserie classics","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"A composed Provencal salad of tuna, green beans, eggs, olives and tomatoes over leaves in a sharp mustard vinaigrette. Bright, mostly no-cook, and it travels well to a lunchbox.","ingredients":["2 tins good tuna in oil, drained","4 eggs","200 g green beans, trimmed","400 g new potatoes","250 g cherry tomatoes, halved","100 g black olives","1 tin anchovies, optional","Mixed salad leaves","5 tbsp olive oil","2 tbsp red wine vinegar","1 tsp Dijon mustard","Salt and black pepper"],"steps":["Boil the potatoes until tender, adding the green beans for the last 4 minutes, then drain and cool.","Soft-boil the eggs for 7 minutes, cool under cold water, peel and halve.","Whisk the oil, vinegar, mustard, salt and pepper into a dressing.","Arrange the leaves, potatoes, beans, tomatoes and olives on a platter.","Flake over the tuna and add the eggs and anchovies if using.","Spoon over the dressing just before serving."],"pairing":"A chilled Provence rose","tags":["Light","Gluten-free option","Make-ahead","Lunchbox"],"vegetarian":false,"spicy":false,"calories":420,"protein":24,"carbs":22,"fat":27,"allergens":["Egg","Fish","Mustard","Sulphites"],"role":"salad","cuisineKey":"french","type":"Salads"},{"id":"fr-croque-monsieur","name":"Croque Monsieur","category":"Brasserie classics","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"The grown-up French toasted sandwich: ham and Gruyere bound by a nutmeg-scented bechamel, capped with more cheese and grilled until bubbling and blistered. Rich, savoury and built for a cafe lunch.","ingredients":["4 thick slices good white bread","150 g cooked ham, sliced","120 g Gruyere, grated","250 ml whole milk","25 g unsalted butter, plus extra for the bread","25 g plain flour","1 tsp Dijon mustard","1 pinch freshly grated nutmeg","Salt and white pepper"],"steps":["Make a bechamel: melt the butter, stir in the flour and cook for a minute, then whisk in the milk gradually until thick and smooth. Season with nutmeg, salt and white pepper, then beat in the Dijon and a third of the cheese.","Lightly butter the bread on the outside. Spread a little bechamel on the inside of two slices, layer with the ham, and close the sandwiches.","Toast in a dry pan over medium heat until golden on both sides.","Transfer to a tray, spoon the remaining bechamel over the tops, and scatter with the rest of the Gruyere.","Grill under a hot broiler for 3 to 4 minutes until the cheese is molten and blistered.","Serve hot with a sharp green salad."],"pairing":"A green salad in mustard vinaigrette","tags":["Quick","Comfort"],"vegetarian":false,"spicy":false,"calories":620,"protein":31,"carbs":38,"fat":38,"allergens":["Gluten","Milk","Mustard"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-moules-mariniere","name":"Moules Mariniere","category":"Brasserie classics","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":30,"serves":2,"level":"Weeknight","idea":"Mussels steamed open in white wine, shallots and parsley with a knob of butter to round the broth. A ten-minute brasserie staple that lives or dies on truly fresh mussels and good bread to mop up.","ingredients":["2 kg fresh mussels, scrubbed and debearded","250 ml dry white wine such as Muscadet","3 shallots, finely chopped","3 cloves garlic, finely chopped","50 g unsalted butter","1 large handful flat-leaf parsley, chopped","2 tbsp creme fraiche, optional","1 bay leaf","Black pepper","1 crusty baguette, to serve"],"steps":["Tap any open mussels and discard those that do not close, along with any with cracked shells.","In a large deep pot, melt the butter and sweat the shallots and garlic with the bay leaf until soft but not coloured.","Pour in the wine and bring to a rolling boil, then tip in the mussels and clamp on the lid.","Steam for 3 to 4 minutes, shaking the pot once or twice, until the shells have opened. Discard any that stay firmly shut.","Stir through the parsley and the creme fraiche if using, and grind over black pepper.","Serve immediately in deep bowls with the broth poured over and the baguette alongside."],"pairing":"A crisp Muscadet sur lie","tags":["Quick","Date night","Light"],"vegetarian":false,"spicy":false,"calories":620,"protein":42,"carbs":34,"fat":28,"allergens":["Gluten","Milk","Shellfish","Sulphites"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-quiche-poireaux","name":"Leek and Gruyere Quiche","category":"Brasserie classics","course":"All-day","meal":"both","tier":"easy","inspiration":"","minutes":75,"serves":6,"level":"Weekend","idea":"A buttery pastry shell filled with sweet softened leeks and a silky custard of eggs, cream and Gruyere. A meat-free brasserie staple, just as good warm from the oven or cold in a lunchbox the next day.","ingredients":["320 g shortcrust pastry","3 leeks, sliced","25 g butter","3 eggs plus 1 yolk","300 ml double cream","100 ml whole milk","100 g Gruyere, grated","1 pinch grated nutmeg","Salt and black pepper"],"steps":["Line a 23 cm tart tin with the pastry, prick the base, and blind bake at 190C for 15 minutes with baking beans, then 5 minutes more uncovered.","Soften the leeks gently in the butter with a pinch of salt until sweet and collapsed, about 10 minutes, then cool slightly and scatter over the base with the cheese.","Whisk the eggs, yolk, cream, milk, nutmeg, salt and pepper.","Pour the custard into the shell.","Bake at 170C for 30 to 35 minutes until just set with a slight wobble.","Cool for 10 minutes before slicing, or chill and serve cold."],"pairing":"A glass of Alsace Pinot Blanc","tags":["Make-ahead","Lunchbox","Comfort","Crowd-pleaser","Vegetarian"],"vegetarian":true,"spicy":false,"calories":520,"protein":13,"carbs":26,"fat":40,"allergens":["Gluten","Milk","Egg"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-soupe-oignon","name":"Soupe a l'Oignon Gratinee","category":"Brasserie classics","course":"Starter","meal":"both","tier":"signature","inspiration":"Le Cirque","minutes":75,"serves":4,"level":"Weekend","idea":"Onions caramelised low and slow into a sweet, mahogany base, deglazed with wine and crowned with a raft of toasted baguette under a blanket of melted Gruyere. The gratineed onion soup codified by Auguste Escoffier in Le Guide Culinaire, done properly.","ingredients":["1 kg onions, thinly sliced","50 g unsalted butter","1 tbsp olive oil","1 tsp sugar","150 ml dry white wine","1.2 litres beef stock","2 cloves garlic, crushed","2 sprigs thyme","1 tbsp plain flour","1 baguette, sliced","200 g Gruyere, grated","Salt and black pepper"],"steps":["Melt the butter with the oil in a heavy pot, add the onions, sugar and a pinch of salt, and cook over low heat, stirring often, for 35 to 45 minutes until deep brown and jammy.","Stir in the garlic, thyme and flour and cook for 2 minutes.","Deglaze with the wine and reduce briefly, then pour in the stock and simmer gently for 20 minutes. Season well.","Toast the baguette slices until dry and crisp.","Ladle the soup into ovenproof bowls, float the toasts on top, and pile on the Gruyere.","Grill under a hot broiler until the cheese is bubbling and golden, then serve at once with care, as the bowls are very hot."],"pairing":"A glass of dry white such as Aligote","tags":["Make-ahead","Comfort","Crowd-pleaser"],"vegetarian":false,"spicy":false,"calories":480,"protein":19,"carbs":42,"fat":25,"allergens":["Gluten","Milk","Sulphites"],"role":"main","cuisineKey":"french","type":"Mains"},{"id":"fr-creme-brulee","name":"Creme Brulee","category":"Desserts","course":"Dessert","meal":"both","tier":"signature","inspiration":"Le Cirque","minutes":60,"serves":4,"level":"Weekend","idea":"Silky vanilla custard set just to a tremble, finished with a thin sheet of bitter caramel you crack with a spoon. The textbook contrast of cool cream against hot, brittle sugar, perfected in the kitchens of Joel Robuchon.","ingredients":["500 ml double cream","1 vanilla pod, split and seeds scraped","5 egg yolks","75 g caster sugar, plus 4 tsp for the tops","1 pinch fine salt"],"steps":["Heat the cream gently with the vanilla pod and seeds until steaming, then take off the heat and infuse for 15 minutes.","Whisk the yolks with the 75 g sugar and salt until pale, then slowly pour in the warm cream, whisking constantly, and strain.","Divide among four ramekins set in a deep tray and pour boiling water halfway up their sides.","Bake at 150C for 30 to 35 minutes until just set with a faint wobble in the centre.","Cool, then chill for at least 3 hours.","Sprinkle each with a teaspoon of caster sugar and torch or grill until the top forms an even amber crust; rest a minute before serving."],"pairing":"A small glass of Sauternes","tags":["Make-ahead","Date night","Gluten-free option","Vegetarian"],"vegetarian":true,"spicy":false,"calories":520,"protein":5,"carbs":28,"fat":43,"allergens":["Milk","Egg"],"role":"dessert","cuisineKey":"french","type":"Desserts"},{"id":"fr-mousse-chocolat","name":"Chocolate Mousse","category":"Desserts","course":"Dessert","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Dark chocolate folded into airy whipped egg whites for a classic French mousse that needs no special kit, just a bowl and a whisk. Make it after lunch and it is set by pudding time.","ingredients":["200 g dark chocolate, chopped","4 eggs, separated","30 g caster sugar","1 pinch salt","1 tsp vanilla extract"],"steps":["Melt the chocolate gently in a bowl over barely simmering water, then let it cool slightly.","Beat the egg yolks with the vanilla and stir into the warm chocolate.","Whisk the egg whites with the salt to soft peaks, then add the sugar and whisk to glossy peaks.","Fold a spoonful of whites into the chocolate to loosen it, then fold in the rest gently.","Spoon into glasses and chill for at least 2 hours before serving."],"pairing":"A small espresso or a glass of Banyuls","tags":["Make-ahead","Vegetarian","Gluten-free option","Date night"],"vegetarian":true,"spicy":false,"calories":340,"protein":7,"carbs":28,"fat":22,"allergens":["Milk","Egg"],"role":"dessert","cuisineKey":"french","type":"Desserts"},{"id":"fr-clafoutis-cerises","name":"Cherry Clafoutis","category":"Desserts","course":"Dessert","meal":"both","tier":"easy","inspiration":"","minutes":45,"serves":6,"level":"Weeknight","idea":"Cherries baked in a simple vanilla batter somewhere between a flan and a pancake. A rustic Limousin pudding you whisk in one bowl and pour over the fruit.","ingredients":["500 g cherries, stoned, or a 400 g tin, drained","3 eggs","100 g caster sugar","80 g plain flour","300 ml whole milk","1 tsp vanilla extract","25 g butter, melted","1 pinch salt","Icing sugar, to dust"],"steps":["Heat the oven to 180C and butter a baking dish.","Scatter the cherries evenly across the dish.","Whisk the eggs, sugar, flour, milk, vanilla, melted butter and salt into a smooth batter.","Pour the batter over the cherries.","Bake for 30 to 35 minutes until puffed, set and golden.","Cool slightly, dust with icing sugar and serve warm."],"pairing":"A glass of chilled Cremant","tags":["Make-ahead","Vegetarian","Comfort","Crowd-pleaser"],"vegetarian":true,"spicy":false,"calories":250,"protein":6,"carbs":38,"fat":8,"allergens":["Gluten","Milk","Egg"],"role":"dessert","cuisineKey":"french","type":"Desserts"},{"id":"fr-tarte-tatin","name":"Tarte Tatin","category":"Desserts","course":"Dessert","meal":"both","tier":"easy","inspiration":"","minutes":75,"serves":6,"level":"Weekend","idea":"Apples caramelised in butter and sugar, baked under pastry and flipped to reveal a glossy, burnished top. The famous upside-down tart from the Tatin sisters, best served just warm with cream.","ingredients":["8 firm apples such as Braeburn, peeled, halved and cored","150 g caster sugar","80 g unsalted butter","320 g all-butter puff pastry","1 tsp lemon juice","1 pinch fine salt","Creme fraiche or vanilla ice cream, to serve"],"steps":["Toss the apples with the lemon juice. In an ovenproof frying pan, melt the sugar with a splash of water and cook to a medium amber caramel, then stir in the butter and salt.","Arrange the apple halves tightly, cut-side up, in the caramel and cook over medium heat for about 15 minutes until they soften and the caramel deepens.","Roll the pastry to a circle slightly larger than the pan, lay it over the apples and tuck the edges down inside.","Bake at 200C for 25 to 30 minutes until the pastry is puffed and deep golden.","Rest for 5 minutes, then confidently invert onto a plate larger than the pan, holding both firmly.","Serve warm with creme fraiche or vanilla ice cream."],"pairing":"A chilled glass of Coteaux du Layon","tags":["Crowd-pleaser","Comfort","Vegetarian"],"vegetarian":true,"spicy":false,"calories":420,"protein":3,"carbs":58,"fat":20,"allergens":["Gluten","Milk"],"role":"dessert","cuisineKey":"french","type":"Desserts"},{"id":"fr-poulet-roti","name":"Poulet Roti (Roast Chicken with Pan Jus)","cuisineKey":"french","category":"Bistro mains","course":"Main","meal":"dinner","tier":"signature","inspiration":"Joel Robuchon","minutes":80,"serves":4,"level":"Weekend","idea":"Keller calls his salt-and-truss roast chicken his favourite thing to eat. It is the ultimate achievable signature for a busy parent and a clean, honest attribution, far more weeknight-realistic than the brisket that currently represents the heavier end.","ingredients":["1 whole chicken, about 1.6kg","1 tbsp fine sea salt","1 tsp black pepper","2 sprigs thyme","1 tbsp Dijon mustard","150ml dry white wine","150ml chicken stock","1 tbsp butter"],"steps":["Heat oven to 220C. Pat the chicken bone-dry inside and out, then season generously all over with the salt and pepper.","Truss the legs with kitchen string and set breast-up in a roasting pan with the thyme.","Roast 50-60 minutes until the juices run clear and a thigh reads 74C internal.","Rest the chicken on a board 10 minutes; brush the skin lightly with Dijon.","Place the pan over a burner, pour in the wine and stock, scrape up the browned bits and reduce by half. Whisk in the butter.","Carve and serve with the pan jus."],"pairing":"Roast potatoes and a green salad; a glass of Chardonnay","tags":["crowd-pleaser","one-pan","leftovers"],"vegetarian":false,"spicy":false,"calories":480,"protein":42,"carbs":2,"fat":33,"allergens":["Milk","Mustard","Sulphites"],"role":"main","type":"Mains"},{"id":"fr-salade-lyonnaise","name":"Salade Lyonnaise","cuisineKey":"french","category":"Brasserie classics","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":4,"level":"Weeknight","idea":"The classic Lyon bistro salad of frisee with crisp lardons, a soft poached egg and a warm sharp mustard dressing.","ingredients":["2 heads frisee or curly endive, torn","200 g smoked lardons or thick bacon, diced","4 eggs","1 small shallot, finely chopped","2 tbsp red wine vinegar","1 tbsp Dijon mustard","4 tbsp olive oil","2 slices day-old bread, cubed for croutons","Salt and black pepper"],"steps":["Wash and dry the frisee and pile into a large bowl.","Fry the lardons in a dry pan until crisp, then lift out, leaving the fat behind.","Toss the bread cubes in the fat until golden, then drain.","In the same pan soften the shallot, then whisk in the mustard, vinegar and olive oil with a splash of water to make a warm dressing.","Poach the eggs in barely simmering water with a little vinegar for 3 minutes until the white is set and yolk runny.","Toss the frisee with the warm dressing, lardons and croutons, divide between plates and top each with a poached egg and a grind of pepper."],"pairing":"A glass of cold Beaujolais","tags":["bistro","egg","bacon","classic"],"vegetarian":false,"spicy":false,"calories":380,"protein":18,"carbs":12,"fat":29,"allergens":["Egg","Gluten","Mustard","Sulphites"],"type":"Salads"},{"id":"fr-salade-chevre-chaud","name":"Salade de Chevre Chaud","cuisineKey":"french","category":"Brasserie classics","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Warm goat cheese toasts over dressed leaves with walnuts and honey, a bistro lunch staple.","ingredients":["150 g mixed salad leaves","2 logs soft goat cheese (about 200 g), cut into 8 rounds","8 thin slices baguette","2 tbsp clear honey","50 g walnuts, roughly chopped","2 tbsp red wine vinegar","1 tsp Dijon mustard","5 tbsp olive oil","Salt and black pepper"],"steps":["Heat the grill to high.","Lay the baguette slices on a tray, top each with a round of goat cheese and drizzle with a little honey.","Grill for 3 to 4 minutes until the cheese is soft and golden.","Whisk the vinegar, mustard, olive oil, salt and pepper into a dressing.","Toast the walnuts briefly in a dry pan.","Toss the leaves with the dressing, divide between plates, scatter with walnuts and top each with two warm goat cheese toasts."],"pairing":"A chilled Sancerre or dry rose","tags":["goat cheese","walnut","honey"],"vegetarian":true,"spicy":false,"calories":420,"protein":14,"carbs":24,"fat":30,"allergens":["Milk","Gluten","Tree nuts","Mustard","Sulphites"],"type":"Salads"},{"id":"fr-celeri-remoulade","name":"Celeri Remoulade","cuisineKey":"french","category":"Brasserie classics","role":"salad","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":15,"serves":4,"level":"Weeknight","idea":"Crisp matchsticks of celeriac in a sharp mustard mayonnaise, the quintessential French deli salad.","ingredients":["1 celeriac, about 600 g, peeled","3 tbsp mayonnaise","1 tbsp creme fraiche","2 tbsp Dijon mustard","1 tbsp lemon juice","1 tbsp chopped parsley","1 tsp capers, chopped","Salt and black pepper"],"steps":["Cut the celeriac into fine matchsticks or coarsely grate it.","Toss immediately with the lemon juice to stop it browning.","Whisk the mayonnaise, creme fraiche, mustard, salt and pepper into a smooth dressing.","Fold the dressing through the celeriac with the capers until well coated.","Chill for 10 minutes, then stir through the parsley and check the seasoning before serving."],"pairing":"Cured ham and crusty bread","tags":["celeriac","mustard","deli","make-ahead"],"vegetarian":true,"spicy":false,"calories":190,"protein":3,"carbs":10,"fat":15,"allergens":["Egg","Milk","Mustard","Sulphites"],"type":"Salads"},{"id":"fr-rillettes-porc","name":"Pork Rillettes with Cornichons","cuisineKey":"french","category":"Brasserie classics","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":35,"serves":6,"level":"Weekend","idea":"Slow-cooked shredded pork potted under its own fat, spread thick on toast with sharp cornichons.","ingredients":["600 g pork shoulder, cubed","150 g pork fat or lardons","2 cloves garlic, crushed","2 sprigs thyme","1 bay leaf","150 ml white wine","100 ml water","Cornichons and toasted baguette, to serve","Salt and black pepper"],"steps":["Put the pork, fat, garlic, herbs, wine and water in a heavy pan and season well.","Cover and cook very gently for 3 hours until the meat falls apart, topping up with water if needed.","Lift out the meat and shred finely with two forks, discarding the herbs.","Beat in enough of the strained cooking fat to make a soft, spreadable paste and check the seasoning.","Press into ramekins, smooth the tops and seal with a thin layer of melted fat.","Chill until firm and serve with cornichons and toasted baguette."],"pairing":"A crisp dry Chenin Blanc","tags":["charcuterie","pork","make-ahead","potted"],"vegetarian":false,"spicy":false,"calories":340,"protein":18,"carbs":6,"fat":27,"allergens":["Gluten","Sulphites"],"type":"Starters"},{"id":"fr-gougeres","name":"Gougeres au Gruyere","cuisineKey":"french","category":"Brasserie classics","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":40,"serves":6,"level":"Weekend","idea":"Light Burgundian cheese puffs of choux pastry baked until golden, the perfect aperitif bite.","ingredients":["120 ml water","120 ml whole milk","100 g unsalted butter","140 g plain flour","4 eggs","120 g Gruyere, grated","1 pinch grated nutmeg","Salt and black pepper"],"steps":["Heat the oven to 200 C and line two trays with baking paper.","Bring the water, milk, butter and salt to the boil, then beat in the flour off the heat until it forms a smooth ball.","Cook the dough for a minute to dry it slightly, then cool for 5 minutes.","Beat in the eggs one at a time until glossy, then fold in most of the Gruyere and the nutmeg.","Pipe or spoon walnut-sized mounds onto the trays and top with the remaining cheese.","Bake for 22 to 25 minutes until puffed, golden and crisp, and serve warm."],"pairing":"A glass of Champagne or cremant","tags":["choux","cheese","aperitif","party"],"vegetarian":true,"spicy":false,"calories":260,"protein":10,"carbs":15,"fat":18,"allergens":["Gluten","Milk","Egg"],"type":"Starters"},{"id":"fr-tartare-saumon","name":"Salmon Tartare with Creme Fraiche","cuisineKey":"french","category":"Brasserie classics","role":"appetizer","course":"Starter","meal":"both","tier":"easy","inspiration":"","minutes":20,"serves":4,"level":"Weeknight","idea":"Hand-cut fresh salmon dressed with shallot, chives, lemon and creme fraiche, served on toasts.","ingredients":["400 g very fresh skinless salmon fillet","1 small shallot, finely chopped","2 tbsp chopped chives","2 tbsp creme fraiche","1 tbsp lemon juice","1 tsp Dijon mustard","1 tbsp olive oil","Toasted baguette or blinis, to serve","Salt and black pepper"],"steps":["Chill the salmon, then cut it into small even dice with a sharp knife.","Gently mix the salmon with the shallot, chives, lemon juice, mustard and olive oil.","Fold in the creme fraiche and season carefully with salt and pepper.","Taste and adjust the lemon and salt, keeping the mixture loose.","Spoon into ring moulds or simply mound onto plates and serve cold with toasts or blinis."],"pairing":"A cold glass of Chablis","tags":["salmon","raw","fresh","elegant"],"vegetarian":false,"spicy":false,"calories":240,"protein":21,"carbs":4,"fat":15,"allergens":["Fish","Milk","Mustard"],"type":"Starters"},{"id":"fr-blanquette-veau","name":"Blanquette de Veau","cuisineKey":"french","category":"Bistro mains","role":"main","course":"Main","meal":"dinner","tier":"signature","inspiration":"Joel Robuchon","minutes":120,"serves":4,"level":"Project","idea":"A gentle white veal stew in a velvety cream and egg-enriched sauce with mushrooms and pearl onions.","ingredients":["1 kg veal shoulder, cut into 4 cm cubes","2 carrots, cut into chunks","1 onion studded with 2 cloves","1 leek, sliced","250 g button mushrooms","200 g pearl onions, peeled","40 g butter","40 g plain flour","2 egg yolks","150 ml double cream","1 tbsp lemon juice","Bouquet garni of thyme, parsley and bay","Salt and white pepper"],"steps":["Put the veal in a pot, cover with cold water, bring to the boil and skim off the foam.","Add the carrots, clove-studded onion, leek and bouquet garni, then simmer gently for 90 minutes until tender.","Meanwhile sweat the pearl onions and mushrooms in a little butter until soft.","Strain the veal, reserving 600 ml of the broth, and discard the aromatics.","Make a roux with the butter and flour, whisk in the hot broth and simmer to a smooth veloute.","Beat the egg yolks with the cream and lemon, temper in some hot sauce, then return off the heat.","Fold the veal, mushrooms and pearl onions into the sauce, warm through without boiling and serve with rice."],"pairing":"Steamed white rice and a white Burgundy","tags":["veal","stew","creamy","classic"],"vegetarian":false,"spicy":false,"calories":620,"protein":48,"carbs":18,"fat":40,"allergens":["Milk","Egg","Gluten","Sulphites"],"type":"Mains"},{"id":"fr-croque-madame","name":"Croque Madame","cuisineKey":"french","category":"Brasserie classics","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":25,"serves":2,"level":"Weeknight","idea":"The croque monsieur crowned with a fried egg, a satisfying brasserie lunch in its own right.","ingredients":["4 thick slices good white bread","150 g cooked ham, sliced","120 g Gruyere, grated","2 eggs","250 ml whole milk","25 g butter, plus extra for frying","25 g plain flour","1 tsp Dijon mustard","1 pinch grated nutmeg","Salt and white pepper"],"steps":["Make a thick bechamel by melting the butter, stirring in the flour and whisking in the milk until smooth and glossy.","Season the sauce with mustard, nutmeg, salt and pepper and stir in half the Gruyere.","Butter the bread, layer with ham and a little sauce, then close into sandwiches.","Top each with sauce and the rest of the Gruyere and grill until bubbling and golden.","Fry the eggs in a little butter until the whites are set, then sit one on each sandwich and serve hot."],"pairing":"A green salad and a glass of cider","tags":["sandwich","ham","cheese","egg"],"vegetarian":false,"spicy":false,"calories":640,"protein":33,"carbs":40,"fat":38,"allergens":["Gluten","Milk","Egg","Mustard"],"type":"Mains"},{"id":"fr-ratatouille","name":"Ratatouille Nicoise","cuisineKey":"french","category":"Bistro mains","role":"main","course":"Main","meal":"both","tier":"easy","inspiration":"","minutes":60,"serves":4,"level":"Weeknight","idea":"A Provencal stew of aubergine, courgette and peppers slow-cooked in tomato and herbs, hearty enough as a vegetarian main.","ingredients":["1 large aubergine, cubed","2 courgettes, sliced","1 red pepper, chopped","1 yellow pepper, chopped","1 onion, chopped","3 cloves garlic, sliced","400 g tin chopped tomatoes","2 tbsp tomato paste","5 tbsp olive oil","1 sprig rosemary","2 sprigs thyme","1 handful basil, torn","Salt and black pepper"],"steps":["Fry the aubergine in olive oil until golden, then set aside.","Brown the courgettes and peppers in batches and add to the aubergine.","Soften the onion and garlic in the same pan, then stir in the tomato paste.","Add the chopped tomatoes, rosemary and thyme and simmer for 10 minutes.","Return all the vegetables, season and cook gently for 25 minutes until thick and tender.","Stir through the basil and serve warm with crusty bread or rice."],"pairing":"Crusty baguette and a Provence rose","tags":["provencal","vegetable","stew"],"vegetarian":true,"spicy":false,"calories":260,"protein":5,"carbs":24,"fat":17,"allergens":["Sulphites"],"type":"Mains"}]};
  var DISHES = GM.dishes, CUISINES = GM.cuisines, TYPES = GM.types;
  var DAYS = ["Monday","Tuesday","Wednesday","Thursday","Friday","Saturday","Sunday"];

  var CZ = {}; CUISINES.forEach(function(c){ CZ[c.key]=c; });
  function czName(key){ var c=CZ[key]; return c?c.short:key; }
  function czHue(key){ var c=CZ[key]; return (c&&c.hue)||"#cda85f"; }
  function esc(s){ return String(s==null?"":s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;"); }
  function pad(n){ return n<10?("0"+n):(""+n); }

  /* ---------------- allergens ---------------- */
  var ALLERGENS=["Gluten","Milk","Egg","Fish","Shellfish","Soy","Sesame","Peanut","Tree nuts","Mustard","Sulphites"];
  var PRESENT_ALLERGENS=(function(){ var s={}; DISHES.forEach(function(d){ (d.allergens||[]).forEach(function(a){ s[a]=1; }); }); return ALLERGENS.filter(function(a){ return s[a]; }); })();

  /* ---------------- preferences (localStorage) ---------------- */
  var PKEY="chloe_grownmeals_v1";
  function defaults(){ return { cuisine:"all", category:"all", veg:false, quick:false, avoid:[], favorites:[] }; }
  function loadPrefs(){ try{ var p=JSON.parse(localStorage.getItem(PKEY)); var d=defaults(); for(var k in p){ d[k]=p[k]; } return d; }catch(e){ return defaults(); } }
  function savePrefs(){ try{ localStorage.setItem(PKEY, JSON.stringify(prefs)); }catch(e){} }
  var prefs = loadPrefs();

  /* ---------------- icons ---------------- */
  var IC_ARROW='<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M4 11h13.2l-4.6-4.6L14 5l7 7-7 7-1.4-1.4 4.6-4.6H4z"/></svg>';
  var IC_BASKET='<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M7 4 5.2 8H2v2h1.1l1.6 9h14.6l1.6-9H22V8h-3.2L17 4h-2.2l1.6 4H7.6L9.2 4zM6 12h12l-1 5H7z"/></svg>';
  var IC_HEART='<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M12 21s-8-5.3-8-11a4.5 4.5 0 0 1 8-2.8A4.5 4.5 0 0 1 20 10c0 5.7-8 11-8 11z"/></svg>';
  var IC_GLASS='<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M6 3h12l-1.2 6.6A5 5 0 0 1 13 13.4V19h3v2H8v-2h3v-5.6A5 5 0 0 1 7.2 9.6L6 3z"/></svg>';

  /* ---------------- filtering ---------------- */
  function categoriesFor(){
    if(prefs.cuisine==="all") return TYPES;
    var c=CZ[prefs.cuisine]; return c?c.cats:[];
  }
  // base filters (cuisine, diet, allergies) that apply to EVERY course, including starters
  function passesBase(d){
    if(prefs.cuisine!=="all" && d.cuisineKey!==prefs.cuisine) return false;
    if(prefs.veg && !d.vegetarian) return false;
    if(prefs.quick && d.minutes>30) return false;
    if(prefs.avoid && prefs.avoid.length){    // allergens removed first, so an allergy never slips through
      var al=d.allergens||[];
      for(var i=0;i<prefs.avoid.length;i++){ if(al.indexOf(prefs.avoid[i])>-1) return false; }
    }
    return true;
  }
  // the cuisine/type chip filters the MAINS by dish type; it does not touch starters
  function passesCategory(d){
    if(prefs.category==="all") return true;
    if(prefs.cuisine==="all") return d.type===prefs.category;
    return d.category===prefs.category;
  }
  function dishMatches(d){ return passesBase(d) && passesCategory(d); }   // used by the full-menu grid
  function pool(){ return DISHES.filter(dishMatches); }
  function rot(arr,n,start){ var out=[]; for(var i=0;i<n && arr.length;i++){ out.push(arr[((start+i)%arr.length+arr.length)%arr.length]); } return out; }
  function uniq(arr){ var seen={}, out=[]; arr.forEach(function(m){ if(m&&!seen[m.id]){ seen[m.id]=1; out.push(m); } }); return out; }
  function tierOf(d){ return d.tier==="signature"?"signature":"easy"; }   // default missing tier to easy
  function mealOf(d){ return (d.meal==="lunch"||d.meal==="dinner")?d.meal:"both"; }
  function roleOf(d){ var r=d.role; return (r==="appetizer"||r==="salad"||r==="dessert")?r:"main"; }

  // MAINS for a slot: proper main courses only, two easy then one signature, rotated by day.
  // A per-slot seed shifts dinner off lunch so the two trios differ.
  function mainsTrio(slot, dayIdx){
    function mains(catFilter){ return DISHES.filter(function(d){ return roleOf(d)==="main" && passesBase(d) && (!catFilter||passesCategory(d)) && (mealOf(d)===slot||mealOf(d)==="both"); }); }
    var p=mains(true); if(p.length<3) p=mains(false);   // ease the type filter if it thins the slot
    var seed=(slot==="dinner")?1:0;
    var easy=p.filter(function(d){ return tierOf(d)==="easy"; });
    var sig =p.filter(function(d){ return tierOf(d)==="signature"; });
    var picks=uniq(rot(easy,2,dayIdx*2+seed*5).concat(rot(sig,1,dayIdx+seed*2)));
    if(picks.length<3) picks=uniq(picks.concat(rot(p,3,dayIdx*3+seed)));
    return picks.slice(0,3);
  }
  // STARTERS for a slot: one appetizer + one salad from the cuisine (the type chip never applies here)
  function startersFor(slot, dayIdx){
    var seed=(slot==="dinner")?3:0;
    var app=DISHES.filter(function(d){ return roleOf(d)==="appetizer" && passesBase(d); });
    var sal=DISHES.filter(function(d){ return roleOf(d)==="salad" && passesBase(d); });
    return uniq(rot(app,1,dayIdx+seed).concat(rot(sal,1,dayIdx+seed)));
  }

  /* ---------------- favourites ---------------- */
  function isFav(id){ return prefs.favorites.indexOf(id)>-1; }
  function toggleFav(id){ var i=prefs.favorites.indexOf(id); if(i>-1) prefs.favorites.splice(i,1); else prefs.favorites.push(id); savePrefs(); }

  /* ---------------- shared bits ---------------- */
  function tagsHtml(d){
    var out=[], shown={};
    if(d.tags.indexOf("Vegan")>-1){ out.push('<span class="gm-tag veg">Vegan</span>'); shown.Vegan=shown.Vegetarian=1; }
    else if(d.vegetarian){ out.push('<span class="gm-tag veg">Vegetarian</span>'); shown.Vegetarian=1; }
    if(d.spicy){ out.push('<span class="gm-tag spicy">Spicy</span>'); shown.Spicy=1; }
    d.tags.forEach(function(t){ if(out.length>=4) return; if(shown[t]||t==="Vegetarian"||t==="Vegan"||t==="Spicy") return; shown[t]=1; out.push('<span class="gm-tag">'+esc(t)+'</span>'); });
    return out.join("");
  }
  function metaRow(d){
    return '<div class="gm-meta">'+
      '<span class="cz"><span class="cdot"></span>'+esc(czName(d.cuisineKey))+'</span>'+
      '<span class="sep"></span><span>'+esc(d.category)+'</span>'+
      '<span class="sep"></span><span>'+d.minutes+' min</span>'+
      '<span class="sep"></span><span>Serves '+d.serves+'</span>'+
      (typeof d.calories==="number"?'<span class="sep"></span><span>'+d.calories+' kcal</span>':'')+
      '<span class="sep"></span><span>'+esc(d.level)+'</span>'+
    '</div>';
  }
  // calories + macros block and the allergen line, shown in the recipe (only when data is present)
  function nutriBlock(d){
    if(typeof d.calories!=="number") return "";
    function macro(v,l){ return '<div class="gm-macro"><span class="mv">'+v+'<i>g</i></span><span class="ml">'+l+'</span></div>'; }
    return '<div class="gm-nutri">'+
      '<div class="gm-kcal"><span class="kv">'+d.calories+'</span><span class="kl">kcal<br>per serving</span></div>'+
      '<div class="gm-macros">'+macro(d.protein,"Protein")+macro(d.carbs,"Carbs")+macro(d.fat,"Fat")+'</div>'+
    '</div>';
  }
  function allergenLine(d){
    if(!d.allergens) return "";
    if(!d.allergens.length) return '<div class="gm-allerg none"><span class="al-k">Allergens</span> none of the common 11</div>';
    return '<div class="gm-allerg"><span class="al-k">Contains</span>'+d.allergens.map(function(a){ return '<span class="gm-alg">'+esc(a)+'</span>'; }).join("")+'</div>';
  }

  /* ---------------- overlay (dark, focus-trapped) ---------------- */
  function overlay(kicker, heading, innerHtml){
    var opener=document.activeElement;
    var ov=el('<div class="gm-ov" role="dialog" aria-modal="true" aria-label="'+esc(heading)+'">'+
      '<div class="gm-panel"><button class="x" aria-label="Close">&times;</button>'+
      (kicker?'<span class="gm-kick">'+esc(kicker)+'</span>':'')+
      '<h3 class="gm-display">'+esc(heading)+'</h3>'+innerHtml+'</div></div>');
    function close(){ document.removeEventListener("keydown",onKey); window.removeEventListener("hashchange",close); ov.remove(); try{ opener&&opener.focus&&opener.focus(); }catch(e){} }
    function onKey(e){
      if(e.key==="Escape"||e.key==="Esc"){ close(); return; }
      if(e.key==="Tab"){
        var f=[].slice.call(ov.querySelectorAll("button")); if(!f.length) return;
        e.preventDefault(); var ci=f.indexOf(document.activeElement);
        var ni=e.shiftKey?(ci<=0?f.length-1:ci-1):((ci<0||ci>=f.length-1)?0:ci+1); try{ f[ni].focus(); }catch(_e){}
      }
    }
    ov.querySelector(".x").addEventListener("click",close);
    ov.addEventListener("click",function(e){ if(e.target===ov) close(); });
    document.addEventListener("keydown",onKey); window.addEventListener("hashchange",close);
    document.body.appendChild(ov); try{ ov.querySelector(".x").focus(); }catch(e){}
    return { ov:ov, close:close };
  }

  // the full recipe: idea, ingredients with quantities, method, pairing, then the shopping list
  function recipeDetail(d){
    var ing=d.ingredients.map(function(x){ return '<li>'+esc(x)+'</li>'; }).join("");
    var steps=d.steps.map(function(x){ return '<li>'+esc(x)+'</li>'; }).join("");
    var html=
      '<div class="gm-tierline">'+roleBadge(d)+tierBadge(d)+inspLine(d)+'</div>'+
      metaRow(d)+
      '<p class="gm-pidea">'+esc(d.idea)+'</p>'+
      nutriBlock(d)+
      allergenLine(d)+
      '<div class="gm-sec"><h4>Ingredients · serves '+d.serves+'</h4><ul class="gm-ing">'+ing+'</ul></div>'+
      '<div class="gm-sec"><h4>Method</h4><ol class="gm-steps">'+steps+'</ol></div>'+
      '<div class="gm-pair"><span class="pic">'+IC_GLASS+'</span><span><span class="pt">Pairing</span><span class="pv">'+esc(d.pairing)+'</span></span></div>'+
      '<div class="gm-tags">'+tagsHtml(d)+'</div>'+
      '<div class="gm-panel-acts">'+
        '<button class="gm-btn gm-shop-btn">'+IC_BASKET+' Shopping list</button>'+
        '<button class="gm-btn ghost gm-fav-btn'+(isFav(d.id)?" on":"")+'">'+IC_HEART+' '+(isFav(d.id)?"Saved":"Save it")+'</button>'+
      '</div>';
    var o=overlay(czName(d.cuisineKey)+" · "+d.category, d.name, html);
    o.ov.querySelector(".gm-panel").style.setProperty("--cz", czHue(d.cuisineKey));
    o.ov.querySelector(".gm-shop-btn").addEventListener("click",function(){ o.close(); shoppingFor(d.name, [d]); });
    var fb=o.ov.querySelector(".gm-fav-btn");
    fb.addEventListener("click",function(){ toggleFav(d.id); var on=isFav(d.id); fb.classList.toggle("on",on); fb.innerHTML=IC_HEART+" "+(on?"Saved":"Save it"); });
  }

  /* ---------------- shopping list (by aisle) ---------------- */
  var AISLES=[
    {k:"Pantry & dry goods", w:["flour","tipo 00","rice","arborio","carnaroli","pasta","spaghetti","tonnarelli","penne","linguine","noodle","udon","ramen","soba","vermicelli","tortilla","taco","bread","brioche","bun","panko","breadcrumb","oil","vinegar","soy","tamari","mirin","sake","dashi","miso","stock","broth","wine","passata","tinned","canned","coconut milk","chickpea","lentil","sugar","honey","maple","syrup","chocolate","vanilla","yeast","semolina","polenta","cornflour","cornstarch","baking","gelatin","fish sauce","oyster sauce","hoisin","tahini","tamarind","curry paste","nori","sesame oil","tomato puree","tomato paste","sun-dried","jaggery","palm sugar","ketchup","mustard","mayonnaise","worcestershire","stock cube","capers","olives"]},
    {k:"Meat, fish & deli", w:["chicken","beef","pork","lamb","veal","mince","guanciale","pancetta","bacon","sausage","chorizo","prosciutto","salami","steak","brisket","short rib","salmon","tuna","prawn","shrimp","squid","calamari","cod","haddock","sea bass","seabass","fish fillet","anchov","sardine","mackerel","scallop","mussel","clam","duck","turkey","ham"]},
    {k:"Dairy & eggs", w:["whole milk","milk","double cream","single cream","cream","butter","cheese","parmigiano","parmesan","pecorino","mozzarella","fior di latte","ricotta","mascarpone","burrata","yogurt","yoghurt","egg","ghee","paneer","feta","halloumi","creme fraiche","crème fraîche","buttermilk","gruyere","cheddar"]},
    {k:"Herbs, spices & aromatics", w:["garlic","ginger","chilli","chili","jalapeno","jalapeño","serrano","chipotle","cumin","coriander seed","ground coriander","turmeric","paprika","oregano","basil","thyme","rosemary","parsley","cilantro","fresh coriander","mint","bay leaf","cinnamon","cardamom","clove","saffron","peppercorn","black pepper","white pepper","nutmeg","lemongrass","kaffir","lime leaf","star anise","fennel seed","fenugreek","mustard seed","garam masala","curry powder","sesame seed","za'atar","sumac","dukkah","spring onion","scallion","shallot","galangal","dried","salt","sea salt","seasoning"]},
    {k:"Fresh produce", w:["tomato","onion","potato","carrot","celery","pepper","capsicum","bell pepper","mushroom","spinach","lettuce","cucumber","courgette","zucchini","aubergine","eggplant","lemon","lime","apple","pear","avocado","cabbage","broccoli","cauliflower","leek","corn","sweetcorn","bean sprout","beansprout","pea","edamame","radish","beetroot","squash","pumpkin","kale","rocket","arugula","watercress","coriander","fennel","asparagus","green bean","okra","plantain","banana","berries","strawberr","mango","herbs"]}
  ];
  function aisleOf(line){
    var s=line.toLowerCase();
    for(var a=0;a<AISLES.length;a++){ for(var i=0;i<AISLES[a].w.length;i++){ if(s.indexOf(AISLES[a].w[i])>-1) return AISLES[a].k; } }
    return "Other";
  }
  function shoppingFor(title, dishes){
    var by={}, seen={};
    dishes.forEach(function(d){ d.ingredients.forEach(function(ing){
      var key=ing.toLowerCase().trim(); if(seen[key]) return; seen[key]=1;
      var a=aisleOf(ing); (by[a]=by[a]||[]).push(ing);
    }); });
    var order=["Fresh produce","Meat, fish & deli","Dairy & eggs","Pantry & dry goods","Herbs, spices & aromatics","Other"];
    var body="";
    order.forEach(function(a){ if(!by[a]) return;
      body+='<div class="gm-aisle"><h5>'+a+'</h5><ul>'+by[a].sort().map(function(x){ return '<li>'+esc(x)+'</li>'; }).join("")+'</ul></div>';
    });
    overlay("Your basket", "Shopping list",
      '<p class="gm-shop-for">'+esc(title)+'</p><div class="gm-shop-cols">'+body+'</div>'+
      '<p class="gm-shop-note">Quantities follow each recipe’s serving size. Buy the best you can of the few hero ingredients; the rest is forgiving.</p>');
  }

  /* ---------------- surprise ---------------- */
  function surprise(){
    var p=pool(); if(!p.length) p=DISHES;
    var pick=p[Math.floor(Math.random()*p.length)];
    if(pick) recipeDetail(pick);
  }

  /* ---------------- cards ---------------- */
  function favBtn(d){
    return '<button class="gm-fav'+(isFav(d.id)?" on":"")+'" aria-label="Save '+esc(d.name)+' to favourites" aria-pressed="'+isFav(d.id)+'">'+IC_HEART+'</button>';
  }
  function wireFav(card, d){
    var b=card.querySelector(".gm-fav"); if(!b) return;
    b.addEventListener("click",function(ev){ ev.stopPropagation(); toggleFav(d.id); var on=isFav(d.id); b.classList.toggle("on",on); b.setAttribute("aria-pressed",on); });
  }
  function openable(card, d){
    function open(){ recipeDetail(d); }
    card.addEventListener("click",open);
    card.addEventListener("keydown",function(e){ if(e.key==="Enter"||e.key===" "){ e.preventDefault(); open(); } });
  }

  function tierBadge(d){
    return tierOf(d)==="signature"
      ? '<span class="gm-tier sig">✦ Signature</span>'
      : '<span class="gm-tier easy">Easy &middot; everyday</span>';
  }
  function inspLine(d){
    return (tierOf(d)==="signature" && d.inspiration) ? '<p class="gm-insp">In the spirit of '+esc(d.inspiration)+'</p>' : "";
  }
  function roleBadge(d){
    var r=roleOf(d);
    if(r==="appetizer") return '<span class="gm-role app">Appetizer</span>';
    if(r==="salad") return '<span class="gm-role sal">Salad</span>';
    if(r==="dessert") return '<span class="gm-role des">Dessert</span>';
    return "";
  }

  // the big editorial slot feature (lunch / dinner picks)
  function featureCard(d, i){
    var c=el(
      '<article class="gm-feature '+(tierOf(d)==="signature"?"tier-sig":"tier-easy")+'" tabindex="0" role="button" data-gm="rise-s" style="--cz:'+czHue(d.cuisineKey)+'; --gm-delay:'+(i*100)+'ms" aria-label="'+esc(d.name)+', open the recipe">'+
        '<div class="idx gm-display">'+pad(i+1)+'</div>'+
        '<div class="fbody">'+
          tierBadge(d)+
          '<h3 class="gm-fname">'+esc(d.name)+'</h3>'+
          '<p class="gm-fidea">'+esc(d.idea)+'</p>'+
          inspLine(d)+
          metaRow(d)+
          '<div class="gm-tags">'+tagsHtml(d)+'</div>'+
        '</div>'+
        '<div class="gm-fside">'+favBtn(d)+'<span class="gm-open">View recipe '+IC_ARROW+'</span></div>'+
      '</article>');
    wireFav(c,d); openable(c,d);
    return c;
  }

  // the compact menu card
  function gridCard(d, i){
    var c=el(
      '<article class="gm-card '+(tierOf(d)==="signature"?"tier-sig":"tier-easy")+'" tabindex="0" role="button" data-gm="rise" style="--cz:'+czHue(d.cuisineKey)+'; --gm-delay:'+(Math.min(i,7)*60)+'ms" aria-label="'+esc(d.name)+', open the recipe">'+
        '<div class="gm-ctop"><span class="gm-czlabel"><span class="cdot"></span>'+esc(czName(d.cuisineKey))+'</span><span class="gm-ctop-r">'+tierBadge(d)+favBtn(d)+'</span></div>'+
        '<h3 class="gm-cname">'+esc(d.name)+'</h3>'+
        '<p class="gm-cidea">'+esc(d.idea)+'</p>'+
        '<div class="gm-tags">'+tagsHtml(d)+'</div>'+
        '<div class="gm-cfoot"><span class="m" style="color:var(--gm-muted);font-weight:700;font-size:.8rem">'+esc(d.category)+' &middot; '+d.minutes+' min'+(typeof d.calories==="number"?' &middot; '+d.calories+' kcal':'')+'</span><span class="gm-open">Recipe '+IC_ARROW+'</span></div>'+
      '</article>');
    wireFav(c,d); openable(c,d);
    return c;
  }

  // compact "to start" card (appetizer / salad) shown above the mains in each meal
  function starterCard(d, i){
    var c=el(
      '<article class="gm-card gm-starter" tabindex="0" role="button" data-gm="rise" style="--cz:'+czHue(d.cuisineKey)+'; --gm-delay:'+(i*70)+'ms" aria-label="'+esc(d.name)+', open the recipe">'+
        '<div class="gm-ctop"><span class="gm-czlabel"><span class="cdot"></span>'+esc(czName(d.cuisineKey))+'</span><span class="gm-ctop-r">'+roleBadge(d)+favBtn(d)+'</span></div>'+
        '<h3 class="gm-cname">'+esc(d.name)+'</h3>'+
        '<p class="gm-cidea">'+esc(d.idea)+'</p>'+
        '<div class="gm-cfoot"><span class="m" style="color:var(--gm-muted);font-weight:700;font-size:.8rem">'+(typeof d.calories==="number"?d.calories+' kcal &middot; ':'')+d.minutes+' min</span><span class="gm-open">Recipe '+IC_ARROW+'</span></div>'+
      '</article>');
    wireFav(c,d); openable(c,d);
    return c;
  }

  /* ---------------- filter studio ---------------- */
  function mk(html, fn){ var b=el(html); b.addEventListener("click",fn); return b; }
  function chip(label, on, cls, hue){
    return '<button class="gm-chip'+(cls?(" "+cls):"")+(on?" on":"")+'" aria-pressed="'+(on?"true":"false")+'"'+(hue?(' style="--cz:'+hue+'"'):"")+'>'+(hue?'<span class="cdot"></span>':"")+esc(label)+'</button>';
  }
  function filterStudio(){
    var box=el('<section class="gm-filter" data-gm="rise"></section>');

    var r1=el('<div class="gm-frow"><span class="gm-flabel">Choose your kitchen</span></div>');
    var cr=el('<div class="gm-chiprow scroll"></div>');
    cr.appendChild(mk(chip("All cuisines", prefs.cuisine==="all", "cz-cuisine", "#cda85f"), function(){ prefs.cuisine="all"; prefs.category="all"; savePrefs(); remount(); }));
    CUISINES.forEach(function(c){ cr.appendChild(mk(chip(c.short, prefs.cuisine===c.key, "cz-cuisine", c.hue), function(){ prefs.cuisine=c.key; prefs.category="all"; savePrefs(); remount(); })); });
    r1.appendChild(cr); box.appendChild(r1);

    var r2=el('<div class="gm-frow"><span class="gm-flabel">'+(prefs.cuisine==="all"?"What are you in the mood for":("Pick a "+esc(czName(prefs.cuisine))+" style"))+'</span></div>');
    var cgr=el('<div class="gm-chiprow scroll"></div>');
    cgr.appendChild(mk(chip("Everything", prefs.category==="all", "mini"), function(){ prefs.category="all"; savePrefs(); remount(); }));
    categoriesFor().forEach(function(cat){ cgr.appendChild(mk(chip(cat, prefs.category===cat, "mini"), function(){ prefs.category=cat; savePrefs(); remount(); })); });
    r2.appendChild(cgr); box.appendChild(r2);

    var r3=el('<div class="gm-frow"><span class="gm-flabel">Tonight’s mood</span></div>');
    var mr=el('<div class="gm-chiprow"></div>');
    mr.appendChild(mk(chip("Vegetarian", prefs.veg, "mini"), function(){ prefs.veg=!prefs.veg; savePrefs(); remount(); }));
    mr.appendChild(mk(chip("Quick · 30 min or less", prefs.quick, "mini"), function(){ prefs.quick=!prefs.quick; savePrefs(); remount(); }));
    r3.appendChild(mr); box.appendChild(r3);

    if(PRESENT_ALLERGENS.length){
      var r5=el('<div class="gm-frow"><span class="gm-flabel">Allergies to avoid</span><span class="gm-fhelp">Any dish containing a selected allergen is removed first, so it never shows in your picks or menu.</span></div>');
      var ar=el('<div class="gm-chiprow"></div>');
      PRESENT_ALLERGENS.forEach(function(a){
        ar.appendChild(mk(chip(a, prefs.avoid.indexOf(a)>-1, "mini avoid"), function(){
          var i=prefs.avoid.indexOf(a); if(i>-1) prefs.avoid.splice(i,1); else prefs.avoid.push(a);
          savePrefs(); remount();
        }));
      });
      r5.appendChild(ar); box.appendChild(r5);
    }

    var r4=el('<div class="gm-frow"><span class="gm-flabel">Which evening</span></div>');
    r4.appendChild(dayRail()); box.appendChild(r4);

    return box;
  }
  function dayRail(){
    var wrap=el('<div class="gm-day-rail" aria-label="Day of the week"></div>');
    var today=(new Date().getDay()+6)%7;
    DAYS.forEach(function(d,i){
      var b=el('<button class="gm-day'+(i===state.day?" on":"")+(i===today?" today":"")+'"'+(i===state.day?' aria-current="true"':"")+'><b>'+d.slice(0,3)+'</b>'+(i===today?'<small>tonight</small>':"")+'</button>');
      b.addEventListener("click",function(){ state.day=i; remount(); });
      wrap.appendChild(b);
    });
    return wrap;
  }

  /* ---------------- section title with a drawing rule ---------------- */
  function stitle(eyebrow, titleHtml, sub){
    return el('<div class="gm-stitle">'+
      '<span class="gm-kick eyebrow" data-gm="rise">'+esc(eyebrow)+'</span>'+
      '<h2 class="gm-display" data-gm="rise">'+titleHtml+'</h2>'+
      (sub?'<p class="sub" data-gm="rise">'+esc(sub)+'</p>':"")+
      '<div class="gm-rule" data-gm="rule"></div>'+
    '</div>');
  }

  /* ---------------- scroll reveal (transform/opacity, gated on motion) ---------------- */
  var _io=null;
  function gmReveal(scope, animate){
    var nodes=scope.querySelectorAll("[data-gm]");
    if(animate===false || !P.motionOK() || !("IntersectionObserver" in window)){
      [].forEach.call(nodes,function(n){ n.classList.add("gm-in"); }); return;
    }
    if(!_io){ _io=new IntersectionObserver(function(ents,obs){
      ents.forEach(function(e){ if(e.isIntersecting){ e.target.classList.add("gm-in"); obs.unobserve(e.target); } });
    },{ threshold:0.12, rootMargin:"0px 0px -6% 0px" }); }
    [].forEach.call(nodes,function(n){ _io.observe(n); });
  }

  /* ---------------- the view ---------------- */
  var rootEl, state={ day:(new Date().getDay()+6)%7 };
  function remount(){ var y=window.scrollY; render(rootEl, false); window.scrollTo(0,y); }

  function render(root, animate){
    rootEl=root; root.innerHTML="";
    var v=el('<div class="view gm-view"></div>');
    v.appendChild(P.topbar());
    v.appendChild(P.sectionNav("grownmeals"));

    var hero=el(
      '<header class="gm-hero">'+
        '<span class="gm-kick" data-gm="rise">For busy parents · lunch &amp; dinner, sorted</span>'+
        '<h1 class="gm-display" data-gm="rise-s">The Grown-Ups’ <span class="it">Table</span></h1>'+
        '<p class="gm-lede" data-gm="rise">Cooking around a little one is a juggle. Each day you get three lunch and three dinner ideas: two that are genuinely easy, built on common ingredients for a hectic day, and one world-class signature for when you want to treat yourself. Every dish comes with the method, the ingredients and a ready shopping list.</p>'+
        '<div class="gm-rule" data-gm="rule"></div>'+
        '<div class="gm-hero-meta" data-gm="rise">'+
          '<div class="gm-stats"><span><b>'+CUISINES.length+'</b> cuisines</span><span><b>'+DISHES.length+'</b> dishes</span><span><b>2&#8201;+&#8201;1</b> easy plus a signature</span></div>'+
          '<span class="gm-spacer"></span>'+
          '<button class="gm-surprise"><span class="ic">✦</span> Surprise me</button>'+
        '</div>'+
      '</header>');
    hero.querySelector(".gm-surprise").addEventListener("click",surprise);
    v.appendChild(hero);

    v.appendChild(filterStudio());

    var ctx=(prefs.cuisine==="all"?"Across every kitchen":czName(prefs.cuisine))+
      (prefs.category!=="all"?(" · "+prefs.category):"")+
      (prefs.veg?" · vegetarian":"")+(prefs.quick?" · under 30 min":"")+
      (prefs.avoid&&prefs.avoid.length?(" · no "+prefs.avoid.join(", ").toLowerCase()):"");

    function slotSection(slotKey, eyebrow, titleHtml){
      v.appendChild(stitle(eyebrow+" · "+DAYS[state.day], titleHtml, ctx+" · a starter and a salad, then two easy mains and a signature"));
      var starters=startersFor(slotKey, state.day);
      var trio=mainsTrio(slotKey, state.day);
      var bag=[];
      if(starters.length){
        v.appendChild(el('<div class="gm-substar" data-gm="rise">To start</div>'));
        var sg=el('<div class="gm-starters"></div>');
        starters.forEach(function(d,i){ sg.appendChild(starterCard(d,i)); bag.push(d); });
        v.appendChild(sg);
      }
      if(trio.length){
        v.appendChild(el('<div class="gm-substar mains" data-gm="rise">The mains</div>'));
        var tg=el('<div class="gm-three"></div>');
        trio.forEach(function(d,i){ tg.appendChild(featureCard(d,i)); bag.push(d); });
        v.appendChild(tg);
      }
      if(bag.length){
        var foot=el('<div class="gm-three-foot" data-gm="rise"></div>');
        var label=slotKey==="lunch"?"lunch":"dinner";
        var sb=el('<button class="gm-btn">'+IC_BASKET+' Shopping list for '+label+'</button>');
        sb.addEventListener("click",function(){ shoppingFor((slotKey==="lunch"?"Lunch":"Dinner")+" · "+DAYS[state.day], uniq(bag)); });
        foot.appendChild(sb); v.appendChild(foot);
      } else {
        v.appendChild(el('<div class="gm-empty" data-gm="rise">Nothing matches those choices. Ease the mood filters, or pick another kitchen.</div>'));
      }
    }
    slotSection("lunch", "Lunch", 'What’s for <span class="it">lunch</span>?');
    slotSection("dinner", "Dinner", 'What’s for <span class="it">dinner</span>?');

    var p=pool();
    if(p.length){
      var menuTitle=prefs.cuisine==="all" ? 'The full <span class="it">menu</span>' : ("The "+esc(czName(prefs.cuisine))+' <span class="it">menu</span>');
      v.appendChild(stitle("Browse everything", menuTitle, p.length+" dish"+(p.length>1?"es":"")+" to explore"));
      var mg=el('<div class="gm-grid"></div>');
      p.forEach(function(d,i){ mg.appendChild(gridCard(d,i)); });
      v.appendChild(mg);
    }

    var favs=DISHES.filter(function(d){ return isFav(d.id); });
    if(favs.length){
      v.appendChild(stitle("Saved", 'Your <span class="it">favourites</span>', favs.length+" saved for later"));
      var fg=el('<div class="gm-grid"></div>');
      favs.forEach(function(d,i){ fg.appendChild(gridCard(d,i)); });
      v.appendChild(fg);
    }

    v.appendChild(el(
      '<section class="gm-srcnote" data-gm="rise">'+
        '<h3 class="gm-display">From our kitchen to yours</h3>'+
        '<p>Every recipe here was developed and then cross-checked by a culinary panel for authenticity, sound quantities and correct method. Quantities serve two or four as noted; season to your own taste, and treat the times as a confident guide rather than a law. <b>Pour a glass of something nice, and enjoy the quiet.</b></p>'+
      '</section>'));

    root.appendChild(v);
    gmReveal(v, animate);
  }

  function renderHome(root){ render(root, true); }
  P.registerModule({ id:"grownmeals", title:"The Grown-Ups' Table", renderHome:renderHome });
})();
